-- Poems batch 476
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('yuding-54','晉門：王茂弘','周曇','唐','御定全唐诗','yuding','','[]','韓魏荊揚日豈堪，胡風看欲過江南。',32,'御定全唐詩/json/729.json','["韓魏荊揚日豈堪，胡風看欲過江南。", "中原一片生靈血，誰秉王綱色不慚。"]'),
('yuding-55','晉門：吳隱之','周曇','唐','御定全唐诗','yuding','','[]','聞說貪泉近郁林，隱之今日得深斟。',32,'御定全唐詩/json/729.json','["聞說貪泉近郁林，隱之今日得深斟。", "徒言滴水能穿石，其那堅貞匪石心。"]'),
('yuding-56','晉門：再吟','周曇','唐','御定全唐诗','yuding','','[]','貪泉何處是泉源，只在靈台一點間。',32,'御定全唐詩/json/729.json','["貪泉何處是泉源，只在靈台一點間。", "必也心源元自有，此泉何必在江山。"]'),
('yuding-57','六朝門：前趙劉聰','周曇','唐','御定全唐诗','yuding','','[]','戎羯誰令識善言，刑將不舍遽能原。',32,'御定全唐詩/json/729.json','["戎羯誰令識善言，刑將不舍遽能原。", "垂成卻罷鳳儀殿，仍改逍遙納諫園。"]'),
('yuding-58','六朝門：前涼張軌','周曇','唐','御定全唐诗','yuding','','[]','官從主簿至專征，誰遣涼王破趙名。',32,'御定全唐詩/json/729.json','["官從主簿至專征，誰遣涼王破趙名。", "益信用賢由拔擢，穰苴不是將家生。"]'),
('yuding-59','六朝門：後魏武帝','周曇','唐','御定全唐诗','yuding','','[]','太武南征似卷蓬，徐陽兗蔡殺皆空。',32,'御定全唐詩/json/729.json','["太武南征似卷蓬，徐陽兗蔡殺皆空。", "從來吊伐寧如此，千里無煙血草紅。"]'),
('yuding-60','六朝門：三廢帝','周曇','唐','御定全唐诗','yuding','','[]','明莊節閔並罹殃，命在朱高二悖王。',32,'御定全唐詩/json/729.json','["明莊節閔並罹殃，命在朱高二悖王。", "已歎一年三易換，更嗟毆辱下東廊。"]'),
('yuding-61','六朝門：苻堅','周曇','唐','御定全唐诗','yuding','','[]','百萬南征幾馬歸，叛亡如蝟亦何悲。',32,'御定全唐詩/json/729.json','["百萬南征幾馬歸，叛亡如蝟亦何悲。", "賓擒敵國諸戎主，更遣權兵過在誰。"]'),
('yuding-62','六朝門：再呤','周曇','唐','御定全唐诗','yuding','','[]','空知勇銳不知兵，困獸孤軍未可輕。',32,'御定全唐詩/json/729.json','["空知勇銳不知兵，困獸孤軍未可輕。", "安有長驅百餘萬，身馳幾旅欲先征。"]'),
('yuding-63','六朝門：又吟','周曇','唐','御定全唐诗','yuding','','[]','水影星光怪異多，不思修德事干戈。',32,'御定全唐詩/json/729.json','["水影星光怪異多，不思修德事干戈。", "無謀拒諫仍輕敵，國破身擒將奈何。"]'),
('yuding-64','六朝門：宋武帝','周曇','唐','御定全唐诗','yuding','','[]','棲棲老楚未遭時，債主憑陵似迫危。',32,'御定全唐詩/json/729.json','["棲棲老楚未遭時，債主憑陵似迫危。", "人傑既為王謐識，刁逵誅斬獨何悲。"]'),
('yuding-65','六朝門：二廢帝','周曇','唐','御定全唐诗','yuding','','[]','肆意荒狂殺不辜，方嗟廢帝又蒼梧。',32,'御定全唐詩/json/729.json','["肆意荒狂殺不辜，方嗟廢帝又蒼梧。", "自言威震為英武，肯慮湘東與玉夫。"]'),
('yuding-66','六朝門：齊廢帝東昏侯','周曇','唐','御定全唐诗','yuding','','[]','定策誰扶捕鼠兒，不憂蕭衍畏潘妃。',32,'御定全唐詩/json/729.json','["定策誰扶捕鼠兒，不憂蕭衍畏潘妃。", "長圍既合刀臨項，猶惜金錢對落暉。"]'),
('yuding-67','六朝門：梁武帝','周曇','唐','御定全唐诗','yuding','','[]','梁武年高厭六龍，繁華聲色盡歸空。',32,'御定全唐詩/json/729.json','["梁武年高厭六龍，繁華聲色盡歸空。", "不求賢德追堯舜，翻作憂囚一病翁。"]'),
('yuding-68','六朝門：再吟','周曇','唐','御定全唐诗','yuding','','[]','興亡何故遽環回，湯紂身為事可哀。',32,'御定全唐詩/json/729.json','["興亡何故遽環回，湯紂身為事可哀。", "莫是自長嫌勝己，蔽賢猶執匹夫才。"]'),
('yuding-69','六朝門：簡文帝','周曇','唐','御定全唐诗','yuding','','[]','救兵方至強抽軍，與賊開城是簡文。',32,'御定全唐詩/json/729.json','["救兵方至強抽軍，與賊開城是簡文。", "曲項琵琶催酒處，不圖為樂向誰雲。"]'),
('yuding-70','六朝門：元帝','周曇','唐','御定全唐诗','yuding','','[]','木柵江城困魏軍，王褒橫議遏謀臣。',32,'御定全唐詩/json/729.json','["木柵江城困魏軍，王褒橫議遏謀臣。", "賓降未免俱為戮，一死安能謝益仁。"]'),
('yuding-71','六朝門：謝舉','周曇','唐','御定全唐诗','yuding','','[]','叛奴逃數豈堪留，忠節曾無肯到頭。',32,'御定全唐詩/json/729.json','["叛奴逃數豈堪留，忠節曾無肯到頭。", "朱異早能同遠見，青衫寧假帝登樓。"]'),
('yuding-72','六朝門：朱異','周曇','唐','御定全唐诗','yuding','','[]','徒覽儒書不學兵，彥和虛得不廉名。',32,'御定全唐詩/json/729.json','["徒覽儒書不學兵，彥和虛得不廉名。", "四郊多壘猶相罪，國破將何謝太清。"]'),
('yuding-73','六朝門：傅昭','周曇','唐','御定全唐诗','yuding','','[]','為政殘苛獸亦饑，除饑機在養疲羸。',32,'御定全唐詩/json/729.json','["為政殘苛獸亦饑，除饑機在養疲羸。", "人能善政獸何暴，焉用勞人以檻為。"]'),
('yuding-74','六朝門：宣帝','周曇','唐','御定全唐诗','yuding','','[]','宣帝驕奢恣所為，後宮升降略無時。',32,'御定全唐詩/json/729.json','["宣帝驕奢恣所為，後宮升降略無時。", "乘危自有妻公在，安許鸞凰是尉遲。"]'),
('yuding-75','六朝門：李集','周曇','唐','御定全唐诗','yuding','','[]','忠諫能堅信正臣，三沈三屈竟何雲。',32,'御定全唐詩/json/729.json','["忠諫能堅信正臣，三沈三屈竟何雲。", "每沈良久方能語，及語還呼桀紂君。"]'),
('yuding-76','隋門：隋文帝','周曇','唐','御定全唐诗','yuding','','[]','孤兒寡婦忍同欺，輔政剛教篡奪為。',32,'御定全唐詩/json/729.json','["孤兒寡婦忍同欺，輔政剛教篡奪為。", "矯詔必能疏昉譯，直臣誠合重顏儀。"]'),
('yuding-77','隋門：獨孤後','周曇','唐','御定全唐诗','yuding','','[]','腹生奚強有親疏，憐者為賢棄者愚。',32,'御定全唐詩/json/729.json','["腹生奚強有親疏，憐者為賢棄者愚。", "儲貳不遭讒構死，隋亡甯便在江都。"]'),
('yuding-78','隋門：煬帝','周曇','唐','御定全唐诗','yuding','','[]','拒諫勞兵作禍基，窮奢極武向戎夷。',32,'御定全唐詩/json/729.json','["拒諫勞兵作禍基，窮奢極武向戎夷。", "兆人疲弊不堪命，天下嗷嗷新主資。"]'),
('yuding-79','隋門：賀若弼','周曇','唐','御定全唐诗','yuding','','[]','破敵將軍意氣豪，請除傾國斬妖嬈。',32,'御定全唐詩/json/729.json','["破敵將軍意氣豪，請除傾國斬妖嬈。", "紅綃忍染嬌春雪，瞪目看行切玉刀。"]'),
('yuding-0','上清辭五首','李九齡','唐','御定全唐诗','yuding','','[]','入海浮生汗漫秋，紫皇高宴五雲樓。',160,'御定全唐詩/json/730.json','["入海浮生汗漫秋，紫皇高宴五雲樓。", "霓裳曲罷天風起，吹散仙香滿十洲。", "樓鎖彤霞地絕塵，碧桃花發九天春。", "東皇近日慵遊宴，閑煞瑤池五色麟。", "上清仙路有丹梯，影響行人到即迷。", "不會無端個漁父，阿誰教入武陵溪。", "本來方朔是真仙，偶別丹台未得還。", "何事玉皇消息晚，忍教憔悴向人間。", "新拜天官上玉都，紫皇親授五靈符。", "群仙個個來相問，人世風光似此無。"]'),
('yuding-1','讀三國志','李九齡','唐','御定全唐诗','yuding','','[]','有國由來在得賢，莫言興廢是迴圈。',32,'御定全唐詩/json/730.json','["有國由來在得賢，莫言興廢是迴圈。", "武侯星落周瑜死，平蜀降吳似等閒。"]'),
('yuding-2','山舍南溪小桃花','李九齡','唐','御定全唐诗','yuding','','[]','一樹繁英奪眼紅，開時先合占東風。',32,'御定全唐詩/json/730.json','["一樹繁英奪眼紅，開時先合占東風。", "可憐地僻無人賞，拋擲深山亂木中。"]'),
('yuding-3','春行遇雨','李九齡','唐','御定全唐诗','yuding','','[]','夾路輕風撼柳條，雨侵春態動無憀。采香陌上誰家女，濕損釵頭翡翠翹。',32,'御定全唐詩/json/730.json','["夾路輕風撼柳條，雨侵春態動無憀。采香陌上誰家女，濕損釵頭翡翠翹。"]'),
('yuding-4','登樓寄遠','李九齡','唐','御定全唐诗','yuding','','[]','滿城春色花如雪，極目煙光月似鉤。',32,'御定全唐詩/json/730.json','["滿城春色花如雪，極目煙光月似鉤。", "總是動人鄉思處，更堪容易上高樓。"]'),
('yuding-5','望思台','李九齡','唐','御定全唐诗','yuding','','[]','漢武年高慢帝圖，任人曾不問賢愚。',32,'御定全唐詩/json/730.json','["漢武年高慢帝圖，任人曾不問賢愚。", "直饒四老依前出，消得江充寵佞無。"]'),
('yuding-6','山舍偶題','李九齡','唐','御定全唐诗','yuding','','[]','門掩松蘿一徑深，偶攜藜杖出前林。',32,'御定全唐詩/json/730.json','["門掩松蘿一徑深，偶攜藜杖出前林。", "誰知盡日看山坐，萬古興亡總在心。"]'),
('yuding-7','荊溪夜泊','李九齡','唐','御定全唐诗','yuding','','[]','點點漁燈照浪清，水煙疏碧月朧明。',32,'御定全唐詩/json/730.json','["點點漁燈照浪清，水煙疏碧月朧明。", "小灘驚起鴛鴦處，一雙採蓮船過聲。"]'),
('yuding-8','旅舍臥病','李九齡','唐','御定全唐诗','yuding','','[]','家隔西秦無遠信，身隨東洛度流年。',32,'御定全唐詩/json/730.json','["家隔西秦無遠信，身隨東洛度流年。", "病來旅館誰相問，牢落閒庭一樹蟬。"]'),
('yuding-9','登昭福寺樓','李九齡','唐','御定全唐诗','yuding','','[]','旅懷秋興正無涯，獨倚危樓四望賒。',32,'御定全唐詩/json/730.json','["旅懷秋興正無涯，獨倚危樓四望賒。", "穀變陵遷何處問，滿川空有舊煙霞。"]'),
('yuding-10','代邊將','李九齡','唐','御定全唐诗','yuding','','[]','雪凍陰河半夜風，戰回狂虜血漂紅。',32,'御定全唐詩/json/730.json','["雪凍陰河半夜風，戰回狂虜血漂紅。", "據鞍遙指長安路，須刻麟台第一功。"]'),
('yuding-11','夜與張舒話別','李九齡','唐','御定全唐诗','yuding','','[]','愁聽南樓角又吹，曉雞啼後更分離。',32,'御定全唐詩/json/730.json','["愁聽南樓角又吹，曉雞啼後更分離。", "如何銷得淒涼思，更勸燈前酒一卮。"]'),
('yuding-12','寒梅詞','李九齡','唐','御定全唐诗','yuding','','[]','霜梅先拆嶺頭枝，萬卉千花凍不知。',32,'御定全唐詩/json/730.json','["霜梅先拆嶺頭枝，萬卉千花凍不知。", "留得和羹滋味在，任他風雪苦相欺。"]'),
('yuding-13','題靈泉寺','李九齡','唐','御定全唐诗','yuding','','[]','入谷先生一陣香，異花奇木簇禪堂。',32,'御定全唐詩/json/730.json','["入谷先生一陣香，異花奇木簇禪堂。", "可憐門外高低路，萬轂千蹄日日忙。"]'),
('yuding-14','宿張正字別業','李九齡','唐','御定全唐诗','yuding','','[]','茅屋蕭寥煙暗後，松窗寂曆月明初。',32,'御定全唐詩/json/730.json','["茅屋蕭寥煙暗後，松窗寂曆月明初。", "此時誰念孤吟客，唯有黃公一帙書。"]'),
('yuding-15','鶴','李九齡','唐','御定全唐诗','yuding','','[]','天上瑤池覆五雲，玉麟金鳳好為群。',32,'御定全唐詩/json/730.json','["天上瑤池覆五雲，玉麟金鳳好為群。", "不須更飲人間水，直是清流也汗君。"]'),
('yuding-16','過相思谷','李九齡','唐','御定全唐诗','yuding','','[]','悠悠信馬春山曲，芳草和煙鋪嫩綠。',32,'御定全唐詩/json/730.json','["悠悠信馬春山曲，芳草和煙鋪嫩綠。", "正被離愁著莫人，那堪更過相思穀。"]'),
('yuding-17','寫莊子','李九齡','唐','御定全唐诗','yuding','','[]','聖澤安排當散地，賢侯優貸借新居。',32,'御定全唐詩/json/730.json','["聖澤安排當散地，賢侯優貸借新居。", "閑中亦有閑生計，寫得南華一部書。"]'),
('yuding-18','山中寄友人','李九齡','唐','御定全唐诗','yuding','','[]','亂雲堆裏結茅廬，已共紅塵跡漸疏。',32,'御定全唐詩/json/730.json','["亂雲堆裏結茅廬，已共紅塵跡漸疏。", "莫問野人生計事，窗前流水枕前書。"]'),
('yuding-0','津亭','胡宿','唐','御定全唐诗','yuding','','[]','津亭欲闋戒棠舟，五兩風來不暫留。西北浮雲連魏闕，',40,'御定全唐詩/json/731.json','["津亭欲闋戒棠舟，五兩風來不暫留。西北浮雲連魏闕，", "平樂舊歡收不得，更憑飛夢到瀛洲。"]'),
('yuding-1','古別','胡宿','唐','御定全唐诗','yuding','','[]','長道何年祖軷休，風帆不斷岳陽樓。佳人挾瑟漳河曉，',40,'御定全唐詩/json/731.json','["長道何年祖軷休，風帆不斷岳陽樓。佳人挾瑟漳河曉，", "至今長樂坡前水，不啻秦人怨隴頭。"]'),
('yuding-2','塞上','胡宿','唐','御定全唐诗','yuding','','[]','漢家神箭定天山，煙火相望萬里間。契利請盟金匕酒，',40,'御定全唐詩/json/731.json','["漢家神箭定天山，煙火相望萬里間。契利請盟金匕酒，", "五餌已行王道勝，絕無刁鬥至闐顏。"]'),
('yuding-3','寄昭潭王中立','胡宿','唐','御定全唐诗','yuding','','[]','高弦一弄武陵深，六幕天空萬里心。吳苑歌驪成久別，',40,'御定全唐詩/json/731.json','["高弦一弄武陵深，六幕天空萬里心。吳苑歌驪成久別，", "莫上孤城頻送目，浮雲西北是家林。"]'),
('yuding-4','雪','胡宿','唐','御定全唐诗','yuding','','[]','屏翳驅雲結夜陰，素花飄墜惡氛沈。色欺曹國麻衣淺，',40,'御定全唐詩/json/731.json','["屏翳驅雲結夜陰，素花飄墜惡氛沈。色欺曹國麻衣淺，", "日高獨擁鸘裘臥，誰乞長安取酒金。"]'),
('yuding-5','沖虛觀','胡宿','唐','御定全唐诗','yuding','','[]','五粒青松護翠苔，石門岑寂斷纖埃。水浮花片知仙路，',40,'御定全唐詩/json/731.json','["五粒青松護翠苔，石門岑寂斷纖埃。水浮花片知仙路，", "馳煙未勒山亭字，可是英靈許再來。"]'),
('yuding-6','淮南發運趙邢州被詔歸闕','胡宿','唐','御定全唐诗','yuding','','[]','天臺封詔紫泥馨，馬首前瞻北斗城。人在函關先望氣，',40,'御定全唐詩/json/731.json','["天臺封詔紫泥馨，馬首前瞻北斗城。人在函關先望氣，", "正是兩宮裁化日，百金雙璧拜虞卿。"]'),
('yuding-7','天街曉望','胡宿','唐','御定全唐诗','yuding','','[]','長樂才聞一叩鐘，百官初謁未央宮。金波穆穆沙堤月，',40,'御定全唐詩/json/731.json','["長樂才聞一叩鐘，百官初謁未央宮。金波穆穆沙堤月，", "嗟余索米無人問，行避霜台禦史驄。"]'),
('yuding-8','淮南王','胡宿','唐','御定全唐诗','yuding','','[]','貪鑄金錢盜寫符，何曾七國戒前車。長生不待爐中藥，',40,'御定全唐詩/json/731.json','["貪鑄金錢盜寫符，何曾七國戒前車。長生不待爐中藥，", "雲中雞犬無消息，麥秀漸漸遍故墟。"]'),
('yuding-9','趙宗道歸輦下','胡宿','唐','御定全唐诗','yuding','','[]','沿牒相逢楚水湄，竹林文酒此攀嵇。半氈未暖還傷別，',40,'御定全唐詩/json/731.json','["沿牒相逢楚水湄，竹林文酒此攀嵇。半氈未暖還傷別，", "明年四月秦關到，洗眼揚州看馬蹄。"]'),
('yuding-10','憶薦福寺牡丹','胡宿','唐','御定全唐诗','yuding','','[]','十日春風隔翠岑，只應繁朵自成陰。樽前可要人頹玉，',40,'御定全唐詩/json/731.json','["十日春風隔翠岑，只應繁朵自成陰。樽前可要人頹玉，", "雕盤分篸何由得，空作西州擁鼻吟。"]'),
('yuding-11','次韻和朱況雨中之什','胡宿','唐','御定全唐诗','yuding','','[]','蒼野迷雲黯不歸，遠風吹雨入岩扉。石床潤極琴絲緩，',40,'御定全唐詩/json/731.json','["蒼野迷雲黯不歸，遠風吹雨入岩扉。石床潤極琴絲緩，", "憂花惜月長如此，爭得東陽病骨肥。"]'),
('yuding-12','感舊','胡宿','唐','御定全唐诗','yuding','','[]','千里青雲未致身，馬蹄空踏幾年塵。曾迷玉洞花光老，',40,'御定全唐詩/json/731.json','["千里青雲未致身，馬蹄空踏幾年塵。曾迷玉洞花光老，", "塢中橫笛偏多感，一涕闌幹白角巾。"]'),
('yuding-13','城南','胡宿','唐','御定全唐诗','yuding','','[]','昨夜輕陰結夕霏，城南十裏有香泥。初聞山鳥驚新哢，',40,'御定全唐詩/json/731.json','["昨夜輕陰結夕霏，城南十裏有香泥。初聞山鳥驚新哢，", "羅敷正苦桑蠶事，惆悵南來五馬蹄。"]'),
('yuding-14','早夏','胡宿','唐','御定全唐诗','yuding','','[]','井轄投多思不禁，密垂珠箔晝沉沉。睡驚燕語頻移枕，',40,'御定全唐詩/json/731.json','["井轄投多思不禁，密垂珠箔晝沉沉。睡驚燕語頻移枕，", "一春酒費知多少，探盡囊中換賦金。"]'),
('yuding-15','侯家','胡宿','唐','御定全唐诗','yuding','','[]','洞戶春遲漏箭長，短轅初返雒陽傍。彩雲按曲青岑醴，',40,'御定全唐詩/json/731.json','["洞戶春遲漏箭長，短轅初返雒陽傍。彩雲按曲青岑醴，", "宴殘紅燭長庚爛，還促朝珂謁未央。"]'),
('yuding-16','函谷關','胡宿','唐','御定全唐诗','yuding','','[]','天開函穀壯關中，萬古驚塵向此空。望氣竟能知老子，',40,'御定全唐詩/json/731.json','["天開函穀壯關中，萬古驚塵向此空。望氣竟能知老子，", "符命已歸如掌地，一丸曾誤隗王東。"]'),
('yuding-17','殘花','胡宿','唐','御定全唐诗','yuding','','[]','雨壓殘紅一夜凋，曉來簾外正飄搖。數枝翠葉空相對，',40,'御定全唐詩/json/731.json','["雨壓殘紅一夜凋，曉來簾外正飄搖。數枝翠葉空相對，", "愁將玉笛傳遺恨，苦被芳風透綺寮。"]'),
('yuding-18','次韻徐爽見寄','胡宿','唐','御定全唐诗','yuding','','[]','五兩青絲帝渥深，平時可敢歎英沈。侏儒自是長三尺，',40,'御定全唐詩/json/731.json','["五兩青絲帝渥深，平時可敢歎英沈。侏儒自是長三尺，", "年來想見瓊枝色，久夢蘧蘧到竹林。"]'),
('yuding-19','華清宮','杜常','唐','御定全唐诗','yuding','','[]','行盡江南數十程，曉星殘月入華清。',32,'御定全唐詩/json/731.json','["行盡江南數十程，曉星殘月入華清。", "朝元閣上西風急，都入長楊作雨聲。"]'),
('yuding-20','題文川村居','滕白','唐','御定全唐诗','yuding','','[]','種茶岩接紅霞塢，灌稻泉生白石根。',32,'御定全唐詩/json/731.json','["種茶岩接紅霞塢，灌稻泉生白石根。", "皤腹老翁眉似雪，海棠花下戲兒孫。"]'),
('yuding-21','燕','滕白','唐','御定全唐诗','yuding','','[]','短羽新來別海陽，真珠高卷語雕梁。',32,'御定全唐詩/json/731.json','["短羽新來別海陽，真珠高卷語雕梁。", "佳人未必全聽爾，正把金針繡鳳凰。"]'),
('yuding-22','題嚴君觀','王岩','唐','御定全唐诗','yuding','','[]','寒雲古木罩星台，凡骨仙蹤信可哀。',32,'御定全唐詩/json/731.json','["寒雲古木罩星台，凡骨仙蹤信可哀。", "二十年前曾此到，一千年內未歸來。"]'),
('yuding-23','山中有所思','王岩','唐','御定全唐诗','yuding','','[]','零零夜雨漬愁根，觸物傷離好斷魂。',32,'御定全唐詩/json/731.json','["零零夜雨漬愁根，觸物傷離好斷魂。", "莫怪杜鵑飛去盡，紫微花裏有啼猿。"]'),
('yuding-24','燕','王岩','唐','御定全唐诗','yuding','','[]','一巢功績破春光，絮落花殘兩翅狂。',32,'御定全唐詩/json/731.json','["一巢功績破春光，絮落花殘兩翅狂。", "月樹風枝不棲去，強來言語泥雕梁。"]'),
('yuding-25','貧女','王岩','唐','御定全唐诗','yuding','','[]','難把菱花照素顏，試臨春水插花看。',32,'御定全唐詩/json/731.json','["難把菱花照素顏，試臨春水插花看。", "木蘭船上游春子，笑把荊釵下遠灘。"]'),
('yuding-26','杪春寄友人','王岩','唐','御定全唐诗','yuding','','[]','何處相逢萬事忙，卓家樓上百淘香。',32,'御定全唐詩/json/731.json','["何處相逢萬事忙，卓家樓上百淘香。", "明朝漸近山僧寺，更為殘花醉一場。"]'),
('yuding-27','回舊山','王岩','唐','御定全唐诗','yuding','','[]','庾家樓上謝家池，處處風煙少舊知。',32,'御定全唐詩/json/731.json','["庾家樓上謝家池，處處風煙少舊知。", "明日落花誰共醉，野溪猿鳥恨歸遲。"]'),
('yuding-0','感巫州薺菜','高力士','唐','御定全唐诗','yuding','','[]','兩京作斤賣，五溪無人采。夷夏雖有殊，氣味都不改。',24,'御定全唐詩/json/732.json','["兩京作斤賣，五溪無人采。夷夏雖有殊，氣味都不改。"]'),
('yuding-1','句','高力士','唐','御定全唐诗','yuding','','[]','煙熏眼落膜，瘴染面朱虞。',12,'御定全唐詩/json/732.json','["煙熏眼落膜，瘴染面朱虞。"]'),
('yuding-2','使至灊山','王越賓','唐','御定全唐诗','yuding','','[]','碧塢煙霞晝未開，遊人到處盡裴回。',32,'御定全唐詩/json/732.json','["碧塢煙霞晝未開，遊人到處盡裴回。", "憑誰借問岩前叟，曾托吾皇一夢來。"]'),
('yuding-3','和武相公中秋夜西蜀錦樓望月得清字','王良會','唐','御定全唐诗','yuding','','[]','德星搖此夜，珥耳滿重城。杳靄煙氛色，飄颻砧杵聲。',48,'御定全唐詩/json/732.json','["德星搖此夜，珥耳滿重城。杳靄煙氛色，飄颻砧杵聲。", "令行秋氣爽，樂感素風輕。共賞千年聖，長歌四海清。"]'),
('yuding-4','星回節遊避風台與清平官賦','南詔驃信','唐','御定全唐诗','yuding','','[]','避風善闡台，極目見藤越。悲哉古與今，依然煙與月。',72,'御定全唐詩/json/732.json','["避風善闡台，極目見藤越。悲哉古與今，依然煙與月。", "自我居震旦，翊衛類夔契。伊昔頸皇運，艱難仰忠烈。", "不覺歲雲暮，感極星回節。元昶同一心，子孫堪貽厥。"]'),
('yuding-5','星回節避風台驃信命賦','趙叔達','唐','御定全唐诗','yuding','','[]','法駕避星回，波羅毗勇猜。河潤冰難合，地暖梅先開。',48,'御定全唐詩/json/732.json','["法駕避星回，波羅毗勇猜。河潤冰難合，地暖梅先開。", "下令俚柔洽，獻賝弄棟來。願將不才質，千載侍遊台。"]'),
('yuding-6','途中詩','楊奇鯤','唐','御定全唐诗','yuding','','[]','□□□□□□□，□□□□□□□。風裏浪花吹更白，',40,'御定全唐詩/json/732.json','["□□□□□□□，□□□□□□□。風裏浪花吹更白，", "此際自然無限趣，王程不敢暫留停。"]'),
('yuding-7','聽妓洞雲歌','布燮','唐','御定全唐诗','yuding','','[]','嵇叔夜，鼓琴飲酒無閒暇。若使當時聞此歌，',36,'御定全唐詩/json/732.json','["嵇叔夜，鼓琴飲酒無閒暇。若使當時聞此歌，", "一飲一碩猶自醉，無人為爾蔔深塵。"]'),
('yuding-8','思鄉作','布燮','唐','御定全唐诗','yuding','','[]','瀘北行人絕，雲南信未還。庭前花不掃，門外柳誰攀。',48,'御定全唐詩/json/732.json','["瀘北行人絕，雲南信未還。庭前花不掃，門外柳誰攀。", "坐久銷銀燭，愁多減玉顏。懸心秋夜月，萬里照關山。"]'),
('yuding-9','銜命還國作','朝衡','唐','御定全唐诗','yuding','','[]','銜命將辭國，非才忝侍臣。天中戀明主，海外憶慈親。',72,'御定全唐詩/json/732.json','["銜命將辭國，非才忝侍臣。天中戀明主，海外憶慈親。", "伏奏違金闕，騑驂去玉津。蓬萊鄉路遠，若木故園林。", "西望懷恩日，東歸感義辰。平生一寶劍，留贈結交人。"]'),
('yuding-10','繡袈裟衣緣','長屋','唐','御定全唐诗','yuding','','[]','山川異域，風月同天。寄諸佛子，共結來緣。',20,'御定全唐詩/json/732.json','["山川異域，風月同天。寄諸佛子，共結來緣。"]'),
('yuding-11','憤怨詩','王巨仁','唐','御定全唐诗','yuding','','[]','於公慟哭三年旱，鄒衍含愁五月霜。',32,'御定全唐詩/json/732.json','["於公慟哭三年旱，鄒衍含愁五月霜。", "今我幽愁還似古，皇天無語但蒼蒼。"]'),
('yuding-12','立木海上刻詩','李贊華','唐','御定全唐诗','yuding','','[]','小山壓大山，大山全無力。羞見故鄉人，從此投外國。',24,'御定全唐詩/json/732.json','["小山壓大山，大山全無力。羞見故鄉人，從此投外國。"]'),
('yuding-13','戲語','成輔端','唐','御定全唐诗','yuding','','[]','秦地城池二百年，何期如此賤田園。',32,'御定全唐詩/json/732.json','["秦地城池二百年，何期如此賤田園。", "一頃麥苗碩伍米，三間堂屋二千錢。"]'),
('yuding-14','萬壽寺歌詞','張隱','唐','御定全唐诗','yuding','','[]','位乖燮理致傷殘，四面牆匡不忍看。',32,'御定全唐詩/json/732.json','["位乖燮理致傷殘，四面牆匡不忍看。", "正是花時堪下淚，相公何必更追歡。"]'),
('yuding-15','迎孫刺史','朱元','唐','御定全唐诗','yuding','','[]','昔日郎君今刺史，朱元依舊守朱門。',32,'御定全唐詩/json/732.json','["昔日郎君今刺史，朱元依舊守朱門。", "今朝竹馬諸童子，儘是當時竹馬孫。"]'),
('yuding-16','臨刑詩','陳璠','唐','御定全唐诗','yuding','','[]','積玉堆金官又崇，禍來倏忽變成空。',32,'御定全唐詩/json/732.json','["積玉堆金官又崇，禍來倏忽變成空。", "五年榮貴今何在，不異南柯一夢中。"]'),
('yuding-17','詩','捧劍僕','唐','御定全唐诗','yuding','','[]','青鳥銜葡萄，飛上金井欄。美人恐驚去，不敢捲簾看。',24,'御定全唐詩/json/732.json','["青鳥銜葡萄，飛上金井欄。美人恐驚去，不敢捲簾看。"]'),
('yuding-18','題牡丹','捧劍僕','唐','御定全唐诗','yuding','','[]','一種芳菲出後庭，卻輸桃李得佳名。',32,'御定全唐詩/json/732.json','["一種芳菲出後庭，卻輸桃李得佳名。", "誰能為向天人說，從此移根近太清。"]'),
('yuding-19','將竄留詩','捧劍僕','唐','御定全唐诗','yuding','','[]','珍重郭四郎，臨行不得別。曉漏動離心，輕車冒殘雪。',48,'御定全唐詩/json/732.json','["珍重郭四郎，臨行不得別。曉漏動離心，輕車冒殘雪。", "欲出主人門，零涕暗嗚咽。萬里隔關山，一心思漢月。"]'),
('yuding-0','淮陽感懷','李密','唐','御定全唐诗','yuding','','[]','金風蕩初節，玉露凋晚林。此夕窮塗士，郁陶傷寸心。',108,'御定全唐詩/json/733.json','["金風蕩初節，玉露凋晚林。此夕窮塗士，郁陶傷寸心。", "野平葭葦合，村荒藜藿深。眺聽良多感，徙倚獨沾襟。", "沾襟何所為，悵然懷古意。秦俗猶未平，漢道將何冀。", "樊噲市井徒，蕭何刀筆吏。一朝時運會，千古傳名諡。", "寄言世上雄，虛生真可愧。"]'),
('yuding-1','南隱遊泉山','孔德紹','唐','御定全唐诗','yuding','','[]','名山狎招隱，俗外遠相求。還如倒景望，忽似閬風遊。',72,'御定全唐詩/json/733.json','["名山狎招隱，俗外遠相求。還如倒景望，忽似閬風遊。", "臨崖俯大壑，披霧仰飛流。歲積松方偃，年深椿欲秋。", "野花開石鏡，雲葉掩山樓。何須問方士，此處即瀛洲。"]'),
('yuding-2','行經太華','孔德紹','唐','御定全唐诗','yuding','','[]','紛吾世網暇，靈岳展幽尋。寥廓風塵遠，杳冥川穀深。',60,'御定全唐詩/json/733.json','["紛吾世網暇，靈岳展幽尋。寥廓風塵遠，杳冥川穀深。", "山昏五里霧，日落二華陰。疏峰起蓮葉，危塞隱桃林。", "何必東都外，此處可抽簪。"]'),
('yuding-3','夜宿荒村','孔德紹','唐','御定全唐诗','yuding','','[]','綿綿夕漏深，客恨轉傷心。撫弦無人聽，對酒時獨斟。',72,'御定全唐詩/json/733.json','["綿綿夕漏深，客恨轉傷心。撫弦無人聽，對酒時獨斟。", "故鄉萬里絕，窮愁百慮侵。秋草思邊馬，繞枝驚夜禽。", "風度穀餘響，月斜山半陰。勞歌欲敘意，終是白頭吟。"]'),
('yuding-4','王澤嶺遭洪水','孔德紹','唐','御定全唐诗','yuding','','[]','地籟風聲急，天津雲色愁。悠然萬頃滿，俄爾百川浮。',84,'御定全唐詩/json/733.json','["地籟風聲急，天津雲色愁。悠然萬頃滿，俄爾百川浮。", "還似金堤溢，翻如碧海流。驚濤遙起鷺，回岸不分牛。", "徒知懷趙景，終是倦陽侯。木梗誠無托，蘆灰豈暇求。", "思得乘槎便，蕭然河漢遊。"]'),
('yuding-5','登白馬山護明寺','孔德紹','唐','御定全唐诗','yuding','','[]','名岳標形勝，危峰遠鬱紆。成象建環極，大壯闡規模。',120,'御定全唐詩/json/733.json','["名岳標形勝，危峰遠鬱紆。成象建環極，大壯闡規模。", "層台聳靈鷲，高殿邇陽烏。暫同游閬苑，還類入仙都。", "三休開碧嶺，萬戶洞金鋪。攝心罄前禮，訪道挹中虛。", "遙瞻盡地軸，長望極天隅。白雲起梁棟，丹霞映栱櫨。", "露花疑濯錦，泉月似沉珠。今日桃源客，相雇失歸塗。"]'),
('yuding-6','送舍利宿定普岩','孔德紹','唐','御定全唐诗','yuding','','[]','仁祠表虛曠，祇園展肅恭。棲息翠微嶺，登頓白雲峰。',60,'御定全唐詩/json/733.json','["仁祠表虛曠，祇園展肅恭。棲息翠微嶺，登頓白雲峰。", "映流看夜月，臨峰聽曉鐘。澗芳十步草，崖陰百丈松。", "蕭然遙路絕，無複市朝蹤。"]'),
('yuding-7','觀太常奏新樂','孔德紹','唐','御定全唐诗','yuding','','[]','大君膺寶曆，出豫表功成。鈞天金石響，洞庭弦管清。',72,'御定全唐詩/json/733.json','["大君膺寶曆，出豫表功成。鈞天金石響，洞庭弦管清。", "八音動繁會，九變葉希聲。和雲留睿賞，熏風悅聖情。", "盛烈光韶濩，易俗邁咸英。竊吹良無取，率舞抃群生。"]'),
('yuding-8','賦得涉江采芙蓉','孔德紹','唐','御定全唐诗','yuding','','[]','蓮舟泛錦磧，極目眺江幹。沿流渡楫易，逆浪取花難。',48,'御定全唐詩/json/733.json','["蓮舟泛錦磧，極目眺江幹。沿流渡楫易，逆浪取花難。", "有霧疑川廣，無風見水寬。朝來採摘倦，詎得久盤桓。"]'),
('yuding-9','賦得華亭鶴','孔德紹','唐','御定全唐诗','yuding','','[]','華亭失侶鶴，乘軒寵遂終。三山淩苦霧，千里激悲風。',48,'御定全唐詩/json/733.json','["華亭失侶鶴，乘軒寵遂終。三山淩苦霧，千里激悲風。", "心危白露下，聲斷彩弦中。何言斯物變，翻覆似遼東。"]'),
('yuding-10','送蔡君知入蜀二首','孔德紹','唐','御定全唐诗','yuding','','[]','金陵已去國，銅梁忽背飛。失路遠相送，他鄉何日歸。',48,'御定全唐詩/json/733.json','["金陵已去國，銅梁忽背飛。失路遠相送，他鄉何日歸。", "靈關九折險，蜀道二星遙。乘槎若有便，希泛廣陵潮。"]'),
('yuding-11','落葉','孔德紹','唐','御定全唐诗','yuding','','[]','早秋驚葉落，飄零似客心。翻飛未肯下，猶言惜故林。',24,'御定全唐詩/json/733.json','["早秋驚葉落，飄零似客心。翻飛未肯下，猶言惜故林。"]'),
('yuding-12','句','孔德紹','唐','御定全唐诗','yuding','','[]','誰分菱花影，還看蓬鬢秋。',12,'御定全唐詩/json/733.json','["誰分菱花影，還看蓬鬢秋。"]'),
('yuding-13','臨刑詩','鄭頲','唐','御定全唐诗','yuding','','[]','幻生還幻滅，大幻莫過身。安心自有處，求人無有人。',24,'御定全唐詩/json/733.json','["幻生還幻滅，大幻莫過身。安心自有處，求人無有人。"]'),
('yuding-14','和謁孔子廟','劉斌','唐','御定全唐诗','yuding','','[]','性與雖天縱，主世乃無由。何言泰山毀，空驚逝水流。',60,'御定全唐詩/json/733.json','["性與雖天縱，主世乃無由。何言泰山毀，空驚逝水流。", "及門思往烈，入室想前修。寂寞荒階暮，摧殘古木秋。", "遺風曖如此，聊以慰蒸求。"]'),
('yuding-15','和許給事傷牛尚書','劉斌','唐','御定全唐诗','yuding','','[]','名臣不世出，百工之所求。況乃非常器，遭逢興運秋。',144,'御定全唐詩/json/733.json','["名臣不世出，百工之所求。況乃非常器，遭逢興運秋。", "符彩照千里，銓衡綜九流。經綸資百物，樽俎寄皇猷。", "韶濩傾複理，典禮紊還修。雖貞棟樑任，兼好藝文遊。", "佇聞和鼎實，行當奉介丘。高衢翻稅駕，閱水遽遷舟。", "傳呼更何日，曳履聞無由。歸魂藐修路，征棹艤邗溝。", "林薄長風慘，江上寒雲愁。夜台終不曙，遺芳徒自留。"]'),
('yuding-16','送劉散員同賦陳思王詩，得好鳥鳴高枝','劉斌','唐','御定全唐诗','yuding','','[]','春林已自好，時鳥複和鳴。枝交難奮翼，谷靜易流聲。',48,'御定全唐詩/json/733.json','["春林已自好，時鳥複和鳴。枝交難奮翼，谷靜易流聲。", "間關才得性，矰繳遽相驚。安知背飛遠，拂霧獨晨征。"]'),
('yuding-17','詠山','劉斌','唐','御定全唐诗','yuding','','[]','靈山峙千仞，蔽日且嵯峨。紫蓋雲陰遠，香爐煙氣多。',48,'御定全唐詩/json/733.json','["靈山峙千仞，蔽日且嵯峨。紫蓋雲陰遠，香爐煙氣多。", "石樑高鳥路，瀑水近天河。欲知聞道裏，別自有仙歌。"]'),
('yuding-18','登樓望月二首','劉辟','唐','御定全唐诗','yuding','','[]','圓月當新霽，高樓見最明。素波流粉壁，丹桂拂飛甍。',144,'御定全唐詩/json/733.json','["圓月當新霽，高樓見最明。素波流粉壁，丹桂拂飛甍。", "下瞰千門靜，旁觀萬象生。梧桐窗下影，烏鵲檻前聲。", "嘯逸劉琨興，吟資庾亮情。遊人莫登眺，迢遞故鄉程。", "皎潔三秋月，巍峨百丈樓。下分征客路，上有美人愁。", "帳卷芙蓉帶，簾褰玳瑁鉤。倚窗情渺渺，憑檻思悠悠。", "未得金波轉，俄成玉箸流。不堪三五夕，夫婿在邊州。"]'),
('yuding-19','題菊花','黃巢','唐','御定全唐诗','yuding','','[]','颯颯西風滿院栽，蕊寒香冷蝶難來。',32,'御定全唐詩/json/733.json','["颯颯西風滿院栽，蕊寒香冷蝶難來。", "他年我若為青帝，報與桃花一處開。"]'),
('yuding-20','不第後賦菊','黃巢','唐','御定全唐诗','yuding','','[]','待到秋來九月八，我花開後百花殺。',32,'御定全唐詩/json/733.json','["待到秋來九月八，我花開後百花殺。", "沖天香陣透長安，滿城盡帶黃金甲。"]'),
('yuding-21','自題像','黃巢','唐','御定全唐诗','yuding','','[]','記得當年草上飛，鐵衣著盡著僧衣。',32,'御定全唐詩/json/733.json','["記得當年草上飛，鐵衣著盡著僧衣。", "天津橋上無人識，獨倚欄幹看落暉。"]'),
('yuding-0','柳','羅紹威','唐','御定全唐诗','yuding','','[]','妝點青春更有誰，青春常許占先知。亞夫營畔風輕處，',40,'御定全唐詩/json/734.json','["妝點青春更有誰，青春常許占先知。亞夫營畔風輕處，", "交情別緒論多少，好向仁人贈一枝。"]'),
('yuding-1','白菊','羅紹威','唐','御定全唐诗','yuding','','[]','雖被風霜競欲催，皎然顏色不低摧。已疑素手能妝出，',40,'御定全唐詩/json/734.json','["雖被風霜競欲催，皎然顏色不低摧。已疑素手能妝出，", "尋思閉戶中宵見，應認寒窗雪一堆。"]'),
('yuding-2','句','羅紹威','唐','御定全唐诗','yuding','','[]','樓前澹澹雲頭日，簾外蕭蕭雨腳風。',16,'御定全唐詩/json/734.json','["樓前澹澹雲頭日，簾外蕭蕭雨腳風。"]'),
('yuding-3','清明登奉先城樓','羅袞','唐','御定全唐诗','yuding','','[]','年來年去只艱危，春半堯山草尚衰。四海清平耆舊見，',40,'御定全唐詩/json/734.json','["年來年去只艱危，春半堯山草尚衰。四海清平耆舊見，", "拭盡賈生無限淚，一行歸雁遠參差。"]'),
('yuding-4','清明赤水寺居','羅袞','唐','御定全唐诗','yuding','','[]','榆火輕煙處處新，旋從閑望到諸鄰。浮生浮世只多事，',40,'御定全唐詩/json/734.json','["榆火輕煙處處新，旋從閑望到諸鄰。浮生浮世只多事，", "蓑衣毳衲誠吾黨，自結村園一社貧。"]'),
('yuding-5','贈羅隱','羅袞','唐','御定全唐诗','yuding','','[]','平日時風好涕流，讒書雖盛一名休。寰區歎屈瞻天問，',40,'御定全唐詩/json/734.json','["平日時風好涕流，讒書雖盛一名休。寰區歎屈瞻天問，", "何當世祖從人望，早以公台命卓侯。"]'),
('yuding-6','哭趙州和尚二首','王鎔','唐','御定全唐诗','yuding','','[]','師離dt水動王侯，心印光潛麈尾收。碧落霧霾松嶺月，',81,'御定全唐詩/json/734.json','["師離dt水動王侯，心印光潛麈尾收。碧落霧霾松嶺月，", "縱是了然雲外客，每瞻瓶幾淚還流。", "佛日西傾祖印隳，珠沈丹沼月沈輝。影敷丈室爐煙慘，", "解空弟子絕悲喜，猶自潸然對雪幃。"]'),
('yuding-7','答同年李昉見贈次韻','鄧洵美','唐','御定全唐诗','yuding','','[]','詞場幾度讓長鞭，又向清朝賀九遷。品秩雖然殊此日，',40,'御定全唐詩/json/734.json','["詞場幾度讓長鞭，又向清朝賀九遷。品秩雖然殊此日，", "今日相逢翻自愧，閑吟對酒倍潸然。"]'),
('yuding-8','除夜長安作','李京','唐','御定全唐诗','yuding','','[]','長安朔風起，窮巷掩雙扉。新歲明朝是，故鄉何路歸。',48,'御定全唐詩/json/734.json','["長安朔風起，窮巷掩雙扉。新歲明朝是，故鄉何路歸。", "鬢絲饒鏡色，隙雪奪燈輝。卻羨秦州雁，逢春盡北飛。"]'),
('yuding-9','登嶺望','許鼎','唐','御定全唐诗','yuding','','[]','淼淼三江水，悠悠五嶺關。雁飛猶不度，人去若為還。',24,'御定全唐詩/json/734.json','["淼淼三江水，悠悠五嶺關。雁飛猶不度，人去若為還。"]'),
('yuding-10','崿嶺四望','許鼎','唐','御定全唐诗','yuding','','[]','漢家仙仗在咸陽，洛水東流出建章。',32,'御定全唐詩/json/734.json','["漢家仙仗在咸陽，洛水東流出建章。", "野老至今猶望幸，離宮秋樹獨蒼蒼。"]'),
('yuding-11','官左拾遺歸隱作','王易簡','唐','御定全唐诗','yuding','','[]','汩沒朝班愧不才，誰能低折向塵埃。',32,'御定全唐詩/json/734.json','["汩沒朝班愧不才，誰能低折向塵埃。", "青山得去且歸去，官職有來還自來。"]'),
('yuding-12','悼楊氏妓琴弦','朱褒','唐','御定全唐诗','yuding','','[]','魂歸寥廓魄歸泉，只住人間十五年。',32,'御定全唐詩/json/734.json','["魂歸寥廓魄歸泉，只住人間十五年。", "昨日施僧裙帶上，斷腸猶系琵琶弦。"]'),
('yuding-13','公子行','黃損','唐','御定全唐诗','yuding','','[]','春草綠綿綿，驕驂驟暖煙。微風飄樂韻，半日醉花邊。',48,'御定全唐詩/json/734.json','["春草綠綿綿，驕驂驟暖煙。微風飄樂韻，半日醉花邊。", "打鵲拋金盞，招人舉玉鞭。田翁與蠶婦，平地看神仙。"]'),
('yuding-14','讀史','黃損','唐','御定全唐诗','yuding','','[]','逐鹿走紅塵，炎炎火德新。家肥生孝子，國霸有餘臣。',48,'御定全唐詩/json/734.json','["逐鹿走紅塵，炎炎火德新。家肥生孝子，國霸有餘臣。", "帝道雲龍合，民心草木春。須知煙閣上，一半老儒真。"]'),
('yuding-15','出山吟','黃損','唐','御定全唐诗','yuding','','[]','來書初出白雲扃，乍躡秋風馬走輕。遠近留連分嶽色，',40,'御定全唐詩/json/734.json','["來書初出白雲扃，乍躡秋風馬走輕。遠近留連分嶽色，", "昨夜細看雲色裏，進賢星座甚分明。"]'),
('yuding-16','書壁','黃損','唐','御定全唐诗','yuding','','[]','一別人間歲月多，歸來人事已銷磨。',32,'御定全唐詩/json/734.json','["一別人間歲月多，歸來人事已銷磨。", "惟有門前鑒池水，春風不改舊時波。"]'),
('yuding-17','句','黃損','唐','御定全唐诗','yuding','','[]','機關才運動，勝敗便相隨。',142,'御定全唐詩/json/734.json','["機關才運動，勝敗便相隨。", "忽遇南遷客，若為西入心。", "往來三島近，活計一囊空。", "三通明主詔，一片白雲心。", "掃地待明月，踏花迎野僧。", "水諳彭澤闊，山憶武陵深。", "金鐙冷光風宛轉，錦袍紅潤雨霏微。", "高齊日月方為道，動合乾坤始是心。", "傍水野禽通體白，飣盤山果半邊紅。", "而今世上多離別，莫向相思樹下啼。（《鷓鴣》，"]'),
('yuding-18','梁郊祀樂章：慶肅','張袞','唐','御定全唐诗','yuding','','[]','籩豆簠簋，黍稷非馨。懿茲彝器，厥德惟明。',40,'御定全唐詩/json/734.json','["籩豆簠簋，黍稷非馨。懿茲彝器，厥德惟明。", "金石匏革，以和以平。由此無疆，期乎永寧。"]'),
('yuding-19','梁郊祀樂章：慶熙','張袞','唐','御定全唐诗','yuding','','[]','哲後躬享，旨酒斯陳。王恭無斁，嚴祀惟寅。',40,'御定全唐詩/json/734.json','["哲後躬享，旨酒斯陳。王恭無斁，嚴祀惟寅。", "皇祖以配，大孝以振。宜錫景福，永休下民。"]'),
('yuding-20','梁郊祀樂章：慶隆','張袞','唐','御定全唐诗','yuding','','[]','恭祀上帝，于國之陽。爵醴是荷，鴻基永昌。',20,'御定全唐詩/json/734.json','["恭祀上帝，于國之陽。爵醴是荷，鴻基永昌。"]'),
('yuding-21','梁郊祀樂章：慶融','張袞','唐','御定全唐诗','yuding','','[]','道和氣兮襲氤氳，宣皇規兮彰聖神。',32,'御定全唐詩/json/734.json','["道和氣兮襲氤氳，宣皇規兮彰聖神。", "服遐裔兮敷質文，格苗扈兮息煙塵。"]'),
('yuding-22','梁郊祀樂章：慶休','張袞','唐','御定全唐诗','yuding','','[]','大業來四夷，仁風和萬國。白日體無私，皇天輔有德。',48,'御定全唐詩/json/734.json','["大業來四夷，仁風和萬國。白日體無私，皇天輔有德。", "七旬罪已服，六月師方克。偉哉帝道隆，終始常作則。"]'),
('yuding-23','梁郊祀樂章：慶和','張袞','唐','御定全唐诗','yuding','','[]','煙燎升，禮容徹。誠感達，人神悅。',32,'御定全唐詩/json/734.json','["煙燎升，禮容徹。誠感達，人神悅。", "靈貺彰，聖情結。玉座寂，金爐歇。"]'),
('yuding-24','梁郊祀樂章：慶和','趙光逢','唐','御定全唐诗','yuding','','[]','就陽位，升圜丘。佩雙玉，禦大裘。',208,'御定全唐詩/json/734.json','["就陽位，升圜丘。佩雙玉，禦大裘。", "膺天命，擁神休。萬靈感，百祿遒。", "秉黃鉞，建朱旗。震八表，清二儀。", "帝業顯，王道夷。受景命，啟皇基。", "開九門，懷百神。通肸蚃，接氤氳。", "明粢薦，廣樂陳。奠嘉璧，燎芳薪。", "膺寶圖，執左契。德應天，聖饗帝。", "薦表衷，荷靈惠。壽萬年，祚百世。", "惟德動天，有感必通。秉茲一德，禋于六宗。", "欽夤寶命，恭肅禮容。來顧來享，永穆皇風。", "天惟佑德，辟乃奉天。交感斯在，昭事罔愆。", "歲功已就，王道無偏。於焉報本，是用告虔。"]'),
('yuding-25','梁郊祀樂章：慶順','趙光逢','唐','御定全唐诗','yuding','','[]','聖皇戾止，天步舒遲。幹幹睿相，穆穆皇儀。',40,'御定全唐詩/json/734.json','["聖皇戾止，天步舒遲。幹幹睿相，穆穆皇儀。", "進退必肅，陟降是祗。六變克協，萬靈協隨。"]'),
('yuding-26','梁郊祀樂章：慶平','趙光逢','唐','御定全唐诗','yuding','','[]','天命降鑒，帝德惟馨。享祀不忒，禮容孔明。',40,'御定全唐詩/json/734.json','["天命降鑒，帝德惟馨。享祀不忒，禮容孔明。", "奠璧布幣，薦純獻精。神佑以答，敷錫永寧。"]'),
('yuding-0','宮詞百首','和凝','唐','御定全唐诗','yuding','','[]','紫燎光銷大駕歸，禦樓初見赭黃衣。',384,'御定全唐詩/json/735.json','["紫燎光銷大駕歸，禦樓初見赭黃衣。", "千聲鼓定將宣赦，竿上金雞翅欲飛。", "北闕晴分五鳳樓，嵩山秀色護神州。", "洛河自契千年運，更擬波中出九疇。", "中興殿上曉光融，一炷天香舞瑞風。", "百辟虔心齊稽首，捲簾遙見禦衣紅。", "日和風暖禦樓時，萬姓齊瞻八彩眉。", "瑞氣祥煙籠細仗，合門宣赦四方知。", "鳳吹鸞歌曉日明，豐年觀稼出神京。", "封人爭獻南山壽，五色雲中禦輦平。", "聖主臨軒待曉時，穿花宮漏正遲遲。", "雞人一唱乾坤曉，百辟分班儼羽儀。", "朦朧西月照池亭，初夜椒房掩畫屏。", "宮女相呼有何事，上樓同看老人星。", "紅泥椒殿綴珠璫，帳蹙金龍窣地長。", "紅獸慢然天色暖，鳳爐時複爇沈香。", "九重樓殿簇丹青，高柳含煙覆井亭。", "宮內不知今日幾，自來階下數堯蓂。", "寢殿香濃玉漏嚴，雲隨涼月下西南。", "帳前宮女低聲道，主上還應夢傅岩。", "繞殿鉤闌壓玉階，內人輕語憑蔥苔。", "皆言明主垂衣理，不假朱雲傍檻來。", "顢頇冰面瑩池心，風刮瑤階臘雪深。", "怪得宮中無獸炭，步搖釵是辟寒金。"]'),
('yuding-1','漁父歌','和凝','唐','御定全唐诗','yuding','','[]','白芷汀寒立鷺鷥，蘋風輕剪浪花時。',32,'御定全唐詩/json/735.json','["白芷汀寒立鷺鷥，蘋風輕剪浪花時。", "煙冪冪，日遲遲，香引芙蓉惹釣絲。"]'),
('yuding-2','楊柳枝','和凝','唐','御定全唐诗','yuding','','[]','軟碧搖煙似送人，映花時把翠眉嚬。',96,'御定全唐詩/json/735.json','["軟碧搖煙似送人，映花時把翠眉嚬。", "青青自是風流主，慢颭金絲待洛神。", "瑟瑟羅裙金縷腰，黛眉隈破未重描。", "醉來咬損新花子，拽住仙郎盡放嬌。", "鵲橋初就咽銀河，今夜仙郎自姓和。", "不是昔年攀桂樹，豈能月裏索姮娥。"]'),
('yuding-3','解紅歌','和凝','唐','御定全唐诗','yuding','','[]','百戲罷，五音清，解紅一曲新教成。',32,'御定全唐詩/json/735.json','["百戲罷，五音清，解紅一曲新教成。", "兩個瑤池小仙子，此時奪卻柘枝名。"]'),
('yuding-4','題鷹獵兔畫','和凝','唐','御定全唐诗','yuding','','[]','雖是丹青物，沈吟亦可傷。君誇鷹眼疾，我憫兔心忙。',48,'御定全唐詩/json/735.json','["雖是丹青物，沈吟亦可傷。君誇鷹眼疾，我憫兔心忙。", "豈動騷人興，惟增獵客狂。鮫綃百餘尺，爭及制衣裳。"]'),
('yuding-5','醴泉院','和凝','唐','御定全唐诗','yuding','','[]','萬山嵐靄簇洋城，數處禪齋盡有名。古柏八株堆翠色，',40,'御定全唐詩/json/735.json','["萬山嵐靄簇洋城，數處禪齋盡有名。古柏八株堆翠色，", "珍重支公每相勉，我於儒行也修行。"]'),
('yuding-6','興勢觀','和凝','唐','御定全唐诗','yuding','','[]','山名興勢鎮梁洋，儼有真風福此方。瘦柏握盤籠殿紫，',40,'御定全唐詩/json/735.json','["山名興勢鎮梁洋，儼有真風福此方。瘦柏握盤籠殿紫，", "只向五千文字內，願成金骨住仙鄉。"]'),
('yuding-7','洋川','和凝','唐','御定全唐诗','yuding','','[]','華夷圖上見洋川，知在青山綠水邊。',32,'御定全唐詩/json/735.json','["華夷圖上見洋川，知在青山綠水邊。", "官閑最好遊僧舍，江近應須買釣船。"]'),
('yuding-8','句','和凝','唐','御定全唐诗','yuding','','[]','先生自舞琴。',29,'御定全唐詩/json/735.json','["先生自舞琴。", "波上人如潘玉兒，掌中花似趙飛燕。（《採蓮曲》，"]'),
('yuding-0','從蜀後主幸秦川上梓潼山','王仁裕','唐','御定全唐诗','yuding','','[]','彩仗拂寒煙，鳴騶在半天。黃雲生馬足，白日下松巔。',48,'御定全唐詩/json/736.json','["彩仗拂寒煙，鳴騶在半天。黃雲生馬足，白日下松巔。", "盛德安疲俗，仁風扇極邊。前程問成紀，此去尚三千。"]'),
('yuding-1','和蜀後主題劍門','王仁裕','唐','御定全唐诗','yuding','','[]','孟陽曾有語，刊在白雲棱。李杜常挨托，孫劉亦恃憑。',48,'御定全唐詩/json/736.json','["孟陽曾有語，刊在白雲棱。李杜常挨托，孫劉亦恃憑。", "庸才安可守，上德始堪矜。暗指長天路，濃巒蔽幾層。"]'),
('yuding-2','荊南席上詠胡琴妓二首','王仁裕','唐','御定全唐诗','yuding','','[]','紅妝齊抱紫檀槽，一抹朱弦四十條。湘水淩波慚鼓瑟，',80,'御定全唐詩/json/736.json','["紅妝齊抱紫檀槽，一抹朱弦四十條。湘水淩波慚鼓瑟，", "丹禁舊臣來側耳，骨清神爽似聞韶。", "玉纖挑落折冰聲，散入秋空韻轉清。二五指中句塞雁，", "無限細腰宮裏女，就中偏愜楚王情。"]'),
('yuding-3','題麥積山天堂','王仁裕','唐','御定全唐诗','yuding','','[]','躡盡懸空萬仞梯，等閒身共白雲齊。簷前下視群山小，',40,'御定全唐詩/json/736.json','["躡盡懸空萬仞梯，等閒身共白雲齊。簷前下視群山小，", "天邊為要留名姓，拂石殷勤身自題。"]'),
('yuding-4','題鬥山觀','王仁裕','唐','御定全唐诗','yuding','','[]','霞衣欲舉醉陶陶，不覺全家住絳霄。拔宅只知雞犬在，',40,'御定全唐詩/json/736.json','["霞衣欲舉醉陶陶，不覺全家住絳霄。拔宅只知雞犬在，", "為有故林蒼柏健，露華涼葉鎖金飆。"]'),
('yuding-5','題孤雲絕頂淮陰祠','王仁裕','唐','御定全唐诗','yuding','','[]','一握寒天古木深，路人猶說漢淮陰。孤雲不掩興亡策，',40,'御定全唐詩/json/736.json','["一握寒天古木深，路人猶說漢淮陰。孤雲不掩興亡策，", "當時若放還西楚，尺寸中華未可侵。"]'),
('yuding-6','和韓昭從駕過白衛嶺','王仁裕','唐','御定全唐诗','yuding','','[]','龍旆飄颻指極邊，到時猶更二三千。登高曉蹋巉岩石，',40,'御定全唐詩/json/736.json','["龍旆飄颻指極邊，到時猶更二三千。登高曉蹋巉岩石，", "秦民莫遣無恩及，大散關東別有天。"]'),
('yuding-7','賀王溥入相','王仁裕','唐','御定全唐诗','yuding','','[]','一戰文場拔趙旗，便調金鼎佐無為。白麻驟降恩何極，',40,'御定全唐詩/json/736.json','["一戰文場拔趙旗，便調金鼎佐無為。白麻驟降恩何極，", "立班始得遙相見，親洽爭如未貴時。"]'),
('yuding-8','與諸門生春日會飲繁台賦','王仁裕','唐','御定全唐诗','yuding','','[]','柳陰如霧絮成堆，又引門生飲古台。淑景即隨風雨去，',40,'御定全唐詩/json/736.json','["柳陰如霧絮成堆，又引門生飲古台。淑景即隨風雨去，", "爛醉也須詩一首，不能空放馬頭回。"]'),
('yuding-9','示諸門生','王仁裕','唐','御定全唐诗','yuding','','[]','二百一十四門生，春風初長羽毛成。擲金換得天邊桂，',40,'御定全唐詩/json/736.json','["二百一十四門生，春風初長羽毛成。擲金換得天邊桂，", "衰翁漸老兒孫小，異日知誰略有情。"]'),
('yuding-10','過平戎谷吊胡翽','王仁裕','唐','御定全唐诗','yuding','','[]','立馬荒郊滿目愁，伊人何罪死林丘。風號古木悲長在，',40,'御定全唐詩/json/736.json','["立馬荒郊滿目愁，伊人何罪死林丘。風號古木悲長在，", "不緣魂寄孤山下，此地堪名鸚鵡洲。"]'),
('yuding-11','奉詔賦劍州途中鷙獸','王仁裕','唐','御定全唐诗','yuding','','[]','劍牙釘舌血毛腥，窺算勞心豈暫停。不與大朝除患難，',40,'御定全唐詩/json/736.json','["劍牙釘舌血毛腥，窺算勞心豈暫停。不與大朝除患難，", "今日帝王親出狩，白雲岩下好藏形。"]'),
('yuding-12','放猿','王仁裕','唐','御定全唐诗','yuding','','[]','放爾丁甯複故林，舊來行處好追尋。月明巫峽堪憐靜，',40,'御定全唐詩/json/736.json','["放爾丁甯複故林，舊來行處好追尋。月明巫峽堪憐靜，", "三秋果熟松梢健，任抱高枝徹曉吟。"]'),
('yuding-13','遇放猿再作','王仁裕','唐','御定全唐诗','yuding','','[]','嶓塚祠前漢水濱，飲猿連臂下嶙峋。漸來子細窺行客，',40,'御定全唐詩/json/736.json','["嶓塚祠前漢水濱，飲猿連臂下嶙峋。漸來子細窺行客，", "數聲腸斷和雲叫，識是前時舊主人。"]'),
('yuding-14','句','王仁裕','唐','御定全唐诗','yuding','','[]','鐵鎖寨門扃白日，大張旗幟插青天。',16,'御定全唐詩/json/736.json','["鐵鎖寨門扃白日，大張旗幟插青天。"]'),
('yuding-0','天道','馮道','唐','御定全唐诗','yuding','','[]','窮達皆由命，何勞發歎聲。但知行好事，莫要問前程。',48,'御定全唐詩/json/737.json','["窮達皆由命，何勞發歎聲。但知行好事，莫要問前程。", "冬去冰須泮，春來草自生。請君觀此理，天道甚分明。"]'),
('yuding-1','偶作','馮道','唐','御定全唐诗','yuding','','[]','莫為危時便愴神，前程往往有期因。須知海嶽歸明主，',40,'御定全唐詩/json/737.json','["莫為危時便愴神，前程往往有期因。須知海嶽歸明主，", "但教方寸無諸惡，狼虎叢中也立身。"]'),
('yuding-2','北使還京作','馮道','唐','御定全唐诗','yuding','','[]','去年今日奉皇華，只為朝廷不為家。殿上一杯天子泣，',40,'御定全唐詩/json/737.json','["去年今日奉皇華，只為朝廷不為家。殿上一杯天子泣，", "上下一行如骨肉，幾人身死掩風沙。"]'),
('yuding-3','贈竇十','馮道','唐','御定全唐诗','yuding','','[]','燕山竇十郎，教子有義方。靈椿一株老，丹桂五枝芳。',24,'御定全唐詩/json/737.json','["燕山竇十郎，教子有義方。靈椿一株老，丹桂五枝芳。"]'),
('yuding-4','放魚書所鑰戶','馮道','唐','御定全唐诗','yuding','','[]','高卻垣牆鑰卻門，監丞從此罷垂綸。',32,'御定全唐詩/json/737.json','["高卻垣牆鑰卻門，監丞從此罷垂綸。", "池中魚鱉應相賀，從此方知有主人。"]'),
('yuding-5','句','馮道','唐','御定全唐诗','yuding','','[]','朝披四襖專藏手，夜覆三衾怕露頭。（虜中大寒，',134,'御定全唐詩/json/737.json','["朝披四襖專藏手，夜覆三衾怕露頭。（虜中大寒，", "牛頭偏得賜，象笏更容持。（虜以道有重名，欲留之，", "牛頭，皆殊禮也，道皆得之，以詩謝。以上見《叢苑》）", "已落地花方遣掃，未經霜草莫教鋤。（《吟治圃》，", "視草北來唐學士，擁旄西去漢將軍。（《同光中承旨盧", "質節制河中贈》，見《續翰林志》）"]'),
('yuding-6','後唐宗廟樂舞辭','盧文紀','唐','御定全唐诗','yuding','','[]','仁君禦宇，寰海謐清。運符武德，道協文明。',40,'御定全唐詩/json/737.json','["仁君禦宇，寰海謐清。運符武德，道協文明。", "九成式敘，百度惟成。金門積慶，玉葉傳榮。"]'),
('yuding-7','後唐宗廟樂舞辭','崔居儉','唐','御定全唐诗','yuding','','[]','艱難王業，返正皇唐。先天再造，卻日重光。',40,'御定全唐詩/json/737.json','["艱難王業，返正皇唐。先天再造，卻日重光。", "漢紹世祖，夏資少康。功成德茂，率祀無疆。"]'),
('yuding-8','春社從李昉乞酒','李濤1','唐','御定全唐诗','yuding','','[]','社公今日沒心情，為乞治聾酒一瓶。',32,'御定全唐詩/json/737.json','["社公今日沒心情，為乞治聾酒一瓶。", "惱亂玉堂將欲遍，依稀巡到第三廳。"]'),
('yuding-9','句','李濤1','唐','御定全唐诗','yuding','','[]','溪聲長在耳，山色不離門。',50,'御定全唐詩/json/737.json','["溪聲長在耳，山色不離門。", "掃地樹留影，拂床琴有聲。", "一言寤主寧複聽，三諫不從歸去來。（《諫晉主不從作》，"]'),
('yuding-10','靈溪老松歌','盧士衡','唐','御定全唐诗','yuding','','[]','靈溪古觀壇西角，千尺鱗皴棟樑樸。橫出一枝戛樓閣，',48,'御定全唐詩/json/737.json','["靈溪古觀壇西角，千尺鱗皴棟樑樸。橫出一枝戛樓閣，", "有時風雨晦暝，擺撼若黑龍之騰躍。合生於象外峰巒，"]'),
('yuding-11','遊靈溪觀','盧士衡','唐','御定全唐诗','yuding','','[]','雲藏寶殿風塵外，粉壁松軒入看初。話久仙童顏色老，',40,'御定全唐詩/json/737.json','["雲藏寶殿風塵外，粉壁松軒入看初。話久仙童顏色老，", "不為壯心降未得，便堪從此玩清虛。"]'),
('yuding-12','寄天臺道友','盧士衡','唐','御定全唐诗','yuding','','[]','相思遙指玉霄峰，悵望江山阻萬重。會隔曉窗聞法鼓，',40,'御定全唐詩/json/737.json','["相思遙指玉霄峰，悵望江山阻萬重。會隔曉窗聞法鼓，", "且住人間行聖教，莫思天路便登龍。"]'),
('yuding-13','花落','盧士衡','唐','御定全唐诗','yuding','','[]','迎風嘯未已，和雨落谷穀。千枝與萬枝，不如一竿竹。',24,'御定全唐詩/json/737.json','["迎風嘯未已，和雨落谷穀。千枝與萬枝，不如一竿竹。"]'),
('yuding-14','鐘陵鐵柱','盧士衡','唐','御定全唐诗','yuding','','[]','千年埋沒竟何為，變化宜將萬物齊。',32,'御定全唐詩/json/737.json','["千年埋沒竟何為，變化宜將萬物齊。", "安得風胡借方便，鑄成神劍斬鯨鯢。"]'),
('yuding-15','僧房聽雨','盧士衡','唐','御定全唐诗','yuding','','[]','古寺松軒雨聲別，寒窗聽久詩魔發。',32,'御定全唐詩/json/737.json','["古寺松軒雨聲別，寒窗聽久詩魔發。", "記得年前在赤城，石樓夢覺三更雪。"]'),
('yuding-16','題牡丹','盧士衡','唐','御定全唐诗','yuding','','[]','萬葉紅綃剪盡春，丹青任寫不如真。',32,'御定全唐詩/json/737.json','["萬葉紅綃剪盡春，丹青任寫不如真。", "風光九十無多日，難惜尊前折贈人。"]'),
('yuding-17','祖龍詞','熊皦','唐','御定全唐诗','yuding','','[]','平吞六國更何求，童女童男問十洲。',32,'御定全唐詩/json/737.json','["平吞六國更何求，童女童男問十洲。", "滄海不回應悵望，始知徐福解風流。"]'),
('yuding-18','謫居海上','熊皦','唐','御定全唐诗','yuding','','[]','家臨涇水隔秦川，來往關河路八千。',32,'御定全唐詩/json/737.json','["家臨涇水隔秦川，來往關河路八千。", "堪恨此身何處老，始皇橋畔又經年。"]'),
('yuding-19','冬日原居酬光上人見訪','熊皎','唐','御定全唐诗','yuding','','[]','吾道喪已久，吾師何此來。門無塵事閉，卷有國風開。',48,'御定全唐詩/json/737.json','["吾道喪已久，吾師何此來。門無塵事閉，卷有國風開。", "野迥霜先白，庭荒葉自堆。寒暄吟罷後，猶喜話天臺。"]'),
('yuding-20','早梅','熊皎','唐','御定全唐诗','yuding','','[]','江南近臘時，已亞雪中枝。一夜欲開盡，百花猶未知。',48,'御定全唐詩/json/737.json','["江南近臘時，已亞雪中枝。一夜欲開盡，百花猶未知。", "人情皆共惜，天意欲教遲。莫訝無濃豔，芳筵正好吹。"]'),
('yuding-21','懷三茅道友','熊皎','唐','御定全唐诗','yuding','','[]','塵事何年解客嘲，十年容易到三茅。長思碧洞雲窗下，',40,'御定全唐詩/json/737.json','["塵事何年解客嘲，十年容易到三茅。長思碧洞雲窗下，", "杏壇仙侶應相笑，只為浮名未肯拋。"]'),
('yuding-22','贈胥尊師','熊皎','唐','御定全唐诗','yuding','','[]','綠發童顏羽服輕，天臺王屋幾經行。雲程去速因風起，',40,'御定全唐詩/json/737.json','["綠發童顏羽服輕，天臺王屋幾經行。雲程去速因風起，", "他年華表重歸日，卻恐桑田已變更。"]'),
('yuding-23','句','熊皎','唐','御定全唐诗','yuding','','[]','山前猶見月，陌上未逢人。',72,'御定全唐詩/json/737.json','["山前猶見月，陌上未逢人。", "果熟秋先落，禽寒夜未棲。", "深逢野草皆為藥，靜見樵人恐是仙。", "厭聽啼鳥夢醒後，慵掃落花春盡時。", "廢土有人耕不畏，古廳無訟醉何妨。"]'),
('yuding-24','塞上','趙延壽','唐','御定全唐诗','yuding','','[]','黃沙風卷半空拋，雲動陰山雪滿郊。探水人回移帳就，',40,'御定全唐詩/json/737.json','["黃沙風卷半空拋，雲動陰山雪滿郊。探水人回移帳就，", "占得高原肥草地，夜深生火折林梢。"]'),
('yuding-25','棋','高輦','唐','御定全唐诗','yuding','','[]','野客圍棋坐，支頤向暮秋。不言如守默，設計似平讎。',48,'御定全唐詩/json/737.json','["野客圍棋坐，支頤向暮秋。不言如守默，設計似平讎。", "決勝雖關勇，防危亦合憂。看他終一局，白卻少年頭。"]'),
('yuding-26','句','高輦','唐','御定全唐诗','yuding','','[]','飄飄送下遙天雪，颯颯吹幹旅舍煙。（《冬風》，',22,'御定全唐詩/json/737.json','["飄飄送下遙天雪，颯颯吹幹旅舍煙。（《冬風》，"]'),
('yuding-27','與李專美','韓昭裔','唐','御定全唐诗','yuding','','[]','昭裔登庸汝未登，鳳池雞樹冷如冰。',32,'御定全唐詩/json/737.json','["昭裔登庸汝未登，鳳池雞樹冷如冰。", "何如且作宣徽使，免被人呼粥飯僧。"]'),
('yuding-28','題龍窩洞','張仁溥','唐','御定全唐诗','yuding','','[]','折花攜酒看龍窩，鏤玉長旌俊彥過。',32,'御定全唐詩/json/737.json','["折花攜酒看龍窩，鏤玉長旌俊彥過。", "他日各為雲外客，碧紗籠卻又如何。"]'),
('yuding-29','留題座主和凝舊閣','李瀚1','唐','御定全唐诗','yuding','','[]','座主登庸歸鳳闕，門生批詔立鼇頭。',32,'御定全唐詩/json/737.json','["座主登庸歸鳳闕，門生批詔立鼇頭。", "玉堂舊閣多珍玩，可作西齋潤筆不。"]'),
('yuding-30','題家園','楊昭儉','唐','御定全唐诗','yuding','','[]','池蓮憔悴無顏色，園竹低垂減翠陰。',32,'御定全唐詩/json/737.json','["池蓮憔悴無顏色，園竹低垂減翠陰。", "園竹池蓮莫惆悵，相看恰似主人心。"]'),
('yuding-31','書從事廳屏上','劉坦','唐','御定全唐诗','yuding','','[]','金殿試回新折桂，將軍留辟向江城。',32,'御定全唐詩/json/737.json','["金殿試回新折桂，將軍留辟向江城。", "思量一醉猶難得，辜負揚州管記名。"]'),
('yuding-32','題施璘畫竹圖','韋遵','唐','御定全唐诗','yuding','','[]','枯籜危根繳石頭，千竿交映近清流。',32,'御定全唐詩/json/737.json','["枯籜危根繳石頭，千竿交映近清流。", "堪珍仲寶窮幽筆，留得荊湘一片秋。"]'),
('yuding-0','陪遊鳳凰台獻詩','宋齊丘','唐','御定全唐诗','yuding','','[]','嵯峨壓洪泉，岝峉撐碧落。宜哉秦始皇，不驅亦不鑿。',373,'御定全唐詩/json/738.json','["嵯峨壓洪泉，岝峉撐碧落。宜哉秦始皇，不驅亦不鑿。", "上有布政台，八顧背城郭。山蹙龍虎健，水黑螭蜃作。", "白虹欲吞人，赤驥相煿zh。畫棟泥金碧，石路盤磽埆。", "倒掛哭月猿，危立思天鶴。鑿池養蛟龍，栽桐棲鸑鷟。", "梁間燕教雛，石罅蛇懸殼。養花如養賢，去草如去惡。", "日晚嚴城鼓，風來蕭寺鐸。掃地驅塵埃，剪蒿除鳥雀。", "金桃帶葉摘，綠李和衣嚼。貞竹無盛衰，媚柳先搖落。", "塵飛景陽井，草合臨春閣。芙蓉如佳人，回首似調謔。", "當軒有直道，無人肯駐腳。夜半鼠窸窣，天陰鬼敲啄。", "松孤不易立，石醜難安著。自憐啄木鳥，去蠹終不錯。", "晚風吹梧桐，樹頭鳴嚗嚗。峨峨江令石，青苔何淡薄。", "不話興亡事，舉首思眇邈。籲哉未到此，褊劣同尺蠖。", "籠鶴羨鳧毛，猛虎愛蝸角。一日賢太守，與我觀橐鑰。", "往往獨自語，天帝相唯諾。風雲偶不來，寰宇銷一略。", "我欲烹長鯨，四海為鼎鑊。我欲取大鵬，天地為矰繳。", "安得生羽翰，雄飛上寥廓。"]'),
('yuding-1','贈仰山慧度禪師','宋齊丘','唐','御定全唐诗','yuding','','[]','初聞如自解，及見勝初聞。兩鬢堆殘雪，一身披斷雲。',48,'御定全唐詩/json/738.json','["初聞如自解，及見勝初聞。兩鬢堆殘雪，一身披斷雲。", "道應齊古佛，高不揖吾君。稽首清涼月，蕭然萬象分。"]'),
('yuding-2','陪華林園試小妓羯鼓','宋齊丘','唐','御定全唐诗','yuding','','[]','切斷牙床鏤紫金，最宜平穩玉槽深。因逢淑景開佳宴，',40,'御定全唐詩/json/738.json','["切斷牙床鏤紫金，最宜平穩玉槽深。因逢淑景開佳宴，", "開元天子曾如此，今日將軍好用心。"]'),
('yuding-3','句','宋齊丘','唐','御定全唐诗','yuding','','[]','大似賢臣扶社稷，遇明則見暗還藏。（《影詩》，',22,'御定全唐詩/json/738.json','["大似賢臣扶社稷，遇明則見暗還藏。（《影詩》，"]'),
('yuding-4','早朝','馮延巳','唐','御定全唐诗','yuding','','[]','銅壺滴漏初晝，高閣雞鳴半空。催啟五門金鎖，',42,'御定全唐詩/json/738.json','["銅壺滴漏初晝，高閣雞鳴半空。催啟五門金鎖，", "鴛瓦數行曉日，鸞旗百尺春風。侍臣踏舞重拜，"]'),
('yuding-5','句','馮延巳','唐','御定全唐诗','yuding','','[]','青樓阿監應相笑，書記登壇又卻回。',16,'御定全唐詩/json/738.json','["青樓阿監應相笑，書記登壇又卻回。"]'),
('yuding-6','感懷詩二章','韓熙載','唐','御定全唐诗','yuding','','[]','僕本江北人，今作江南客。再去江北遊，舉目無相識。',112,'御定全唐詩/json/738.json','["僕本江北人，今作江南客。再去江北遊，舉目無相識。", "金風吹我寒，秋月為誰白。不如歸去來，江南有人憶。", "未到故鄉時，將為故鄉好。及至親得歸，爭如身不到。", "目前相識無一人，出入空傷我懷抱。風雨蕭蕭旅館秋，", "桃臉蛾眉笑出門，爭向前頭擁將去。"]'),
('yuding-7','溧水無相寺贈僧','韓熙載','唐','御定全唐诗','yuding','','[]','無相景幽遠，山屏四面開。憑師領鶴去，待我掛冠來。',48,'御定全唐詩/json/738.json','["無相景幽遠，山屏四面開。憑師領鶴去，待我掛冠來。", "藥為依時采，松宜繞舍栽。林泉自多興，不是效劉雷。"]'),
('yuding-8','書歌妓泥金帶','韓熙載','唐','御定全唐诗','yuding','','[]','風柳搖搖無定枝，陽臺雲雨夢中歸。',32,'御定全唐詩/json/738.json','["風柳搖搖無定枝，陽臺雲雨夢中歸。", "他年蓬島音塵斷，留取尊前舊舞衣。"]'),
('yuding-9','送徐鉉流舒州','韓熙載','唐','御定全唐诗','yuding','','[]','昔年淒斷此江湄，風滿征帆淚滿衣。',32,'御定全唐詩/json/738.json','["昔年淒斷此江湄，風滿征帆淚滿衣。", "今日重憐鶺鴒羽，不堪波上又分飛。"]'),
('yuding-10','句','韓熙載','唐','御定全唐诗','yuding','','[]','幾人平地上，看我半天中。',12,'御定全唐詩/json/738.json','["幾人平地上，看我半天中。"]'),
('yuding-11','登祝融峰','李征古','唐','御定全唐诗','yuding','','[]','欲上祝融峰，先登古石橋。鑿開巇嶮處，取路到丹霄。',24,'御定全唐詩/json/738.json','["欲上祝融峰，先登古石橋。鑿開巇嶮處，取路到丹霄。"]'),
('yuding-12','七歲吟','潘佑','唐','御定全唐诗','yuding','','[]','朝遊滄海東，暮歸何太速。只因騎折白龍腰，',20,'御定全唐詩/json/738.json','["朝遊滄海東，暮歸何太速。只因騎折白龍腰，"]'),
('yuding-13','送許處士堅往茅山','潘佑','唐','御定全唐诗','yuding','','[]','天壇雲似雪，玉洞水如琴。白雲與流水，千載清人心。',48,'御定全唐詩/json/738.json','["天壇雲似雪，玉洞水如琴。白雲與流水，千載清人心。", "君攜布囊去，路長風滿林。一入華陽洞，千秋那可尋。"]'),
('yuding-14','送人往宣城','潘佑','唐','御定全唐诗','yuding','','[]','江畔送行人，千山生暮氛。謝安團扇上，為畫敬亭雲。',24,'御定全唐詩/json/738.json','["江畔送行人，千山生暮氛。謝安團扇上，為畫敬亭雲。"]'),
('yuding-15','失題','潘佑','唐','御定全唐诗','yuding','','[]','誰家舊宅春無主，深院簾垂杏花雨。',32,'御定全唐詩/json/738.json','["誰家舊宅春無主，深院簾垂杏花雨。", "香飛綠瑣人未歸，巢燕承塵默無語。"]'),
('yuding-16','句','潘佑','唐','御定全唐诗','yuding','','[]','勸君此醉直須歡，明朝又是花狼藉。',16,'御定全唐詩/json/738.json','["勸君此醉直須歡，明朝又是花狼藉。"]'),
('yuding-17','寄孟賓于','李昉','唐','御定全唐诗','yuding','','[]','初攜書劍別湘潭，金榜標名第十三。昔日聲名喧洛下，',40,'御定全唐詩/json/738.json','["初攜書劍別湘潭，金榜標名第十三。昔日聲名喧洛下，", "莫學馮唐便休去，明君晚事未為慚。"]'),
('yuding-18','送孟賓于','馬致恭','唐','御定全唐诗','yuding','','[]','曾聞洛下綴神仙，火樹南棲幾十年。白首自忻丹桂在，',40,'御定全唐詩/json/738.json','["曾聞洛下綴神仙，火樹南棲幾十年。白首自忻丹桂在，", "今日還家莫惆悵，不同初上渡頭船。"]'),
('yuding-19','奉和聖制元日大雪登樓','張義方','唐','御定全唐诗','yuding','','[]','恰當歲日紛紛落，天寶瑤花助物華。自古最先標瑞牒，',40,'御定全唐詩/json/738.json','["恰當歲日紛紛落，天寶瑤花助物華。自古最先標瑞牒，", "豈但小臣添興詠，狂歌醉舞一家家。"]'),
('yuding-0','中酒寄劉行軍','李建勳','唐','御定全唐诗','yuding','','[]','甚矣頻頻醉，神昏體亦虛。肺傷徒問藥，發落不盈梳。',48,'御定全唐詩/json/739.json','["甚矣頻頻醉，神昏體亦虛。肺傷徒問藥，發落不盈梳。", "戀寢嫌明室，修生愧道書。西峰老僧語，相勸合何如。"]'),
('yuding-1','白雁','李建勳','唐','御定全唐诗','yuding','','[]','東溪一白雁，毛羽何皎潔。薄暮浴清波，斜陽共明滅。',72,'御定全唐詩/json/739.json','["東溪一白雁，毛羽何皎潔。薄暮浴清波，斜陽共明滅。", "差池失群久，幽獨依人切。旅食賴菰蒲，單棲怯霜雪。", "邊風昨夜起，顧影空哀咽。不及牆上烏，相將繞雙闕。"]'),
('yuding-2','早春寄懷','李建勳','唐','御定全唐诗','yuding','','[]','家山歸未得，又是看春過。老覺光陰速，閑悲世路多。',48,'御定全唐詩/json/739.json','["家山歸未得，又是看春過。老覺光陰速，閑悲世路多。", "風和吹岸柳，雪盡見庭莎。欲向東溪醉，狂眠一放歌。"]'),
('yuding-3','春日東山正堂作','李建勳','唐','御定全唐诗','yuding','','[]','身閑贏得出，天氣漸暄和。蜀馬登山穩，南朝古寺多。',48,'御定全唐詩/json/739.json','["身閑贏得出，天氣漸暄和。蜀馬登山穩，南朝古寺多。", "早花微弄色，新酒欲生波。從此唯行樂，閒愁奈我何。"]'),
('yuding-4','春日小園晨看兼招同舍','李建勳','唐','御定全唐诗','yuding','','[]','最有杏花繁，枝枝若手摶。須知一春促，莫厭百回看。',48,'御定全唐詩/json/739.json','["最有杏花繁，枝枝若手摶。須知一春促，莫厭百回看。", "鳥囀風潛息，蜂遲露未幹。可容排飲否，兼折贈頭冠。"]'),
('yuding-5','惜花寄孫員外','李建勳','唐','御定全唐诗','yuding','','[]','朝始一枝開，暮複一枝落。只恐雨淋漓，又見春蕭索。',48,'御定全唐詩/json/739.json','["朝始一枝開，暮複一枝落。只恐雨淋漓，又見春蕭索。", "侵晨結駟攜酒徒，尋芳踏盡長安衢。思量少壯不自樂，"]'),
('yuding-6','春日病中','李建勳','唐','御定全唐诗','yuding','','[]','才得歸閑去，還教病臥頻。無由全勝意，終是負青春。',48,'御定全唐詩/json/739.json','["才得歸閑去，還教病臥頻。無由全勝意，終是負青春。", "綠柳漸拂地，黃鶯如喚人。方為醫者勸，斷酒已經旬。"]'),
('yuding-7','毆妓','李建勳','唐','御定全唐诗','yuding','','[]','自為專房甚，匆匆有所傷。當時心已悔，徹夜手猶香。',48,'御定全唐詩/json/739.json','["自為專房甚，匆匆有所傷。當時心已悔，徹夜手猶香。", "恨枕堆雲髻，啼襟搵月黃。起來猶忍惡，剪破繡鴛鴦。"]'),
('yuding-8','踏青樽前','李建勳','唐','御定全唐诗','yuding','','[]','期君速行樂，不要旋還家。永日雖無雨，東風自落花。',48,'御定全唐詩/json/739.json','["期君速行樂，不要旋還家。永日雖無雨，東風自落花。", "詩毫粘酒淡，歌袖向人斜。薄暮忘歸路，垂楊噪亂鴉。"]'),
('yuding-9','正月晦日','李建勳','唐','御定全唐诗','yuding','','[]','莫倦尋春去，都無百日遊。更堪正月過，已是一分休。',48,'御定全唐詩/json/739.json','["莫倦尋春去，都無百日遊。更堪正月過，已是一分休。", "泉暖聲才出，雲寒勢未收。晚來重作雪，翻為杏花愁。"]'),
('yuding-10','惜花','李建勳','唐','御定全唐诗','yuding','','[]','白髮今如此，紅芳莫更催。預愁多日謝，翻怕十分開。',48,'御定全唐詩/json/739.json','["白髮今如此，紅芳莫更催。預愁多日謝，翻怕十分開。", "點滴無時雨，荒涼滿地苔。閑階一杯酒，惟待故人來。"]'),
('yuding-11','金穀園落花','李建勳','唐','御定全唐诗','yuding','','[]','愁見清明後，紛紛蓋地紅。惜看難過日，自落不因風。',48,'御定全唐詩/json/739.json','["愁見清明後，紛紛蓋地紅。惜看難過日，自落不因風。", "蝶散餘香在，鶯啼半樹空。堪悲一尊酒，從此似西東。"]'),
('yuding-12','柳花寄宋明府','李建勳','唐','御定全唐诗','yuding','','[]','每愛江城裏，青春向盡時。一回新雨歇，是處好風吹。',48,'御定全唐詩/json/739.json','["每愛江城裏，青春向盡時。一回新雨歇，是處好風吹。", "破石黏蟲網，高樓撲酒旗。遙知陶令宅，五樹正離披。"]'),
('yuding-13','送人','李建勳','唐','御定全唐诗','yuding','','[]','相見未逾月，堪悲遠別離。非君誰顧我，萬里又南之。',48,'御定全唐詩/json/739.json','["相見未逾月，堪悲遠別離。非君誰顧我，萬里又南之。", "雨逼清明日，花陰杜宇時。愁看掛帆處，鷗鳥共遲遲。"]'),
('yuding-14','閒遊','李建勳','唐','御定全唐诗','yuding','','[]','攜酒複攜觴，朝朝一似忙。馬諳頻到路，僧借舊眠床。',48,'御定全唐詩/json/739.json','["攜酒複攜觴，朝朝一似忙。馬諳頻到路，僧借舊眠床。", "道勝他圖薄，身閑白日長。扁舟動歸思，高處見滄浪。"]'),
('yuding-15','柏梁隔句韻詩','李建勳','唐','御定全唐诗','yuding','','[]','不喜長亭柳，枝枝擬送君。惟憐北窗□，樹樹解留人。',48,'御定全唐詩/json/739.json','["不喜長亭柳，枝枝擬送君。惟憐北窗□，樹樹解留人。", "圓缺都如月，東西只似雲。愁看離席散，歸蓋動行塵。"]'),
('yuding-16','贈趙學士','李建勳','唐','御定全唐诗','yuding','','[]','常欽趙夫子，遠作五侯賓。見面到今日，操心如古人。',48,'御定全唐詩/json/739.json','["常欽趙夫子，遠作五侯賓。見面到今日，操心如古人。", "醉同華席少，吟訪野僧頻。寂寂長河畔，荒齋與廟鄰。"]'),
('yuding-17','春陰','李建勳','唐','御定全唐诗','yuding','','[]','老雨不肯休，東風勢還作。未放草蒙茸，已遣花蕭索。',48,'御定全唐詩/json/739.json','["老雨不肯休，東風勢還作。未放草蒙茸，已遣花蕭索。", "浮生何苦勞，觸事妨行樂。寄語達生人，須知酒勝藥。"]'),
('yuding-18','春日金谷園','李建勳','唐','御定全唐诗','yuding','','[]','火急召親賓，歡游莫厭頻。日長徒似歲，花過即非春。',48,'御定全唐詩/json/739.json','["火急召親賓，歡游莫厭頻。日長徒似歲，花過即非春。", "晚雨來何定，東風自不勻。須知三個月，不是負芳晨。"]'),
('yuding-19','夏日酬祥松二公見訪','李建勳','唐','御定全唐诗','yuding','','[]','多謝空門客，時時出草堂。從容非有約，淡薄不相忘。',48,'御定全唐詩/json/739.json','["多謝空門客，時時出草堂。從容非有約，淡薄不相忘。", "池映春篁老，簷垂夏果香。西峰正清霽，自與拂吟床。"]'),
('yuding-20','懷贈操禪師','李建勳','唐','御定全唐诗','yuding','','[]','嘗憶曹溪子，龕居面碧嵩。杉松新夏後，雨雹夜禪中。',48,'御定全唐詩/json/739.json','["嘗憶曹溪子，龕居面碧嵩。杉松新夏後，雨雹夜禪中。", "道匪因經悟，心能向物空。秋來得音信，又在剡山東。"]'),
('yuding-21','閒居秋思呈祥松二公','李建勳','唐','御定全唐诗','yuding','','[]','秋光雖即好，客思轉悠哉。去國身將老，流年雁又來。',48,'御定全唐詩/json/739.json','["秋光雖即好，客思轉悠哉。去國身將老，流年雁又來。", "葉紅堆晚徑，菊冷藉空罍。不得師相訪，難將道自開。"]'),
('yuding-22','賦得冬日青溪草堂四十字','李建勳','唐','御定全唐诗','yuding','','[]','莫道無幽致，常來到日西。地雖當北闕，天與設東溪。',48,'御定全唐詩/json/739.json','["莫道無幽致，常來到日西。地雖當北闕，天與設東溪。", "疏葦寒多折，驚鳧去不齊。坐中皆作者，長愛覓分題。"]'),
('yuding-23','溪齋','李建勳','唐','御定全唐诗','yuding','','[]','水木繞吾廬，搴簾晚檻虛。衰條寒露鵲，幽果落驚魚。',48,'御定全唐詩/json/739.json','["水木繞吾廬，搴簾晚檻虛。衰條寒露鵲，幽果落驚魚。", "愛酒貧還甚，趨時老更疏。乖慵自有素，不是忽簪裾。"]'),
('yuding-24','留題愛敬寺','李建勳','唐','御定全唐诗','yuding','','[]','野性竟未改，何以居朝廷。空為百官首，但愛千峰青。',48,'御定全唐詩/json/739.json','["野性竟未改，何以居朝廷。空為百官首，但愛千峰青。", "南風新雨後，與客攜觴行。斜陽惜歸去，萬壑啼鳥聲。"]'),
('yuding-25','小園','李建勳','唐','御定全唐诗','yuding','','[]','小園吾所好，栽植忘勞形。晚果經秋赤，寒蔬近社青。',48,'御定全唐詩/json/739.json','["小園吾所好，栽植忘勞形。晚果經秋赤，寒蔬近社青。", "竹蘿荒引蔓，土井淺生萍。更欲從人勸，憑高置草亭。"]'),
('yuding-26','宿山房','李建勳','唐','御定全唐诗','yuding','','[]','石窗燈欲盡，松檻月還明。就枕渾無睡，披衣卻出行。',48,'御定全唐詩/json/739.json','["石窗燈欲盡，松檻月還明。就枕渾無睡，披衣卻出行。", "岩高泉亂滴，林動鳥時驚。倏忽山鐘曙，喧喧僕馬聲。"]'),
('yuding-27','金陵所居青溪草堂閑興','李建勳','唐','御定全唐诗','yuding','','[]','窗外皆連水，杉松欲作林。自憐趨競地，獨有愛閒心。',48,'御定全唐詩/json/739.json','["窗外皆連水，杉松欲作林。自憐趨競地，獨有愛閒心。", "素壁題看遍，危冠醉不簪。江僧暮相訪，簾卷見秋岑。"]'),
('yuding-28','闕下偶書寄孫員外','李建勳','唐','御定全唐诗','yuding','','[]','長安驅馳地，貴賤共悠悠。白日誰相促，勞生自不休。',48,'御定全唐詩/json/739.json','["長安驅馳地，貴賤共悠悠。白日誰相促，勞生自不休。", "鳳翔雙闕曉，蟬噪六街秋。獨有南宮客，時來話釣舟。"]'),
('yuding-29','寄魏郎中','李建勳','唐','御定全唐诗','yuding','','[]','碌碌但隨群，蒿蘭任不分。未嘗矜有道，求遇向吾君。',48,'御定全唐詩/json/739.json','["碌碌但隨群，蒿蘭任不分。未嘗矜有道，求遇向吾君。", "逸駕秋尋寺，長歌醉望雲。高齋紙屏古，塵暗北山文。"]'),
('yuding-30','病中書懷寄王二十六','李建勳','唐','御定全唐诗','yuding','','[]','落葉滿山州，閑眠病未瘳。窗陰連竹枕，藥氣染茶甌。',48,'御定全唐詩/json/739.json','["落葉滿山州，閑眠病未瘳。窗陰連竹枕，藥氣染茶甌。", "路匪人遮去，官須自覓休。焉宜更羸老，扶杖作公侯。"]'),
('yuding-31','采菊','李建勳','唐','御定全唐诗','yuding','','[]','簇簇竟相鮮，一枝開幾番。味甘資麹糵，香好勝蘭蓀。',48,'御定全唐詩/json/739.json','["簇簇竟相鮮，一枝開幾番。味甘資麹糵，香好勝蘭蓀。", "古道風搖遠，荒籬露壓繁。盈筐時采得，服餌近知門。"]'),
('yuding-32','送王郎中之官吉水','李建勳','唐','御定全唐诗','yuding','','[]','南望廬陵郡，山連五嶺長。吾君憐遠俗，從事輟名郎。',48,'御定全唐詩/json/739.json','["南望廬陵郡，山連五嶺長。吾君憐遠俗，從事輟名郎。", "移戶多無土，春蠶不滿筐。惟應勞贊畫，溪峒況強梁。"]'),
('yuding-33','孤雁','李建勳','唐','御定全唐诗','yuding','','[]','欲食不敢食，合棲猶未棲。聞風亦驚過，避繳恨飛低。',48,'御定全唐詩/json/739.json','["欲食不敢食，合棲猶未棲。聞風亦驚過，避繳恨飛低。", "水闊緣湘困，雲寒過磧迷。悲鳴感人意，不見夜烏啼。"]'),
('yuding-34','贈送致仕郎中','李建勳','唐','御定全唐诗','yuding','','[]','鶴立瘦棱棱，髭長白似銀。衣冠皆古制，氣貌異常人。',48,'御定全唐詩/json/739.json','["鶴立瘦棱棱，髭長白似銀。衣冠皆古制，氣貌異常人。", "聽雪添詩思，看山滯酒巡。西峰重歸路，唯許野僧親。"]'),
('yuding-35','宿友人山居寄司徒相公','李建勳','唐','御定全唐诗','yuding','','[]','雨雪正霏霏，令人不憶歸。地爐僧坐暖，山枿火聲肥。',96,'御定全唐詩/json/739.json','["雨雪正霏霏，令人不憶歸。地爐僧坐暖，山枿火聲肥。", "隔紙烘茶蕊，移鐺剝芋衣。知君在霄漢，此興得還稀。", "郢客相尋夜，荒庭雪灑篙。虛堂看向曙，吟坐共忘勞。", "溪凍聲全減，燈寒焰不高。他人莫相笑，未易會吾曹。"]'),
('yuding-36','感故府二首','李建勳','唐','御定全唐诗','yuding','','[]','戚戚複戚戚，期懷安可釋。百年金石心，中路生死隔。',96,'御定全唐詩/json/739.json','["戚戚複戚戚，期懷安可釋。百年金石心，中路生死隔。", "新墳應草合，舊地空苔色。白日燈熒熒，凝塵滿幾席。", "悒悒複悒悒，思君安可及。永日在階前，披衣隨風立。", "高樓暮角斷，遠樹寒鴉集。惆悵幾行書，遺蹤墨猶濕。"]'),
('yuding-37','田家三首','李建勳','唐','御定全唐诗','yuding','','[]','畢歲知無事，兵銷復舊丁。竹門桑徑狹，春日稻畦青。',144,'御定全唐詩/json/739.json','["畢歲知無事，兵銷復舊丁。竹門桑徑狹，春日稻畦青。", "犬吠隈籬落，雞飛上碓桯。歸田起囗思，蛙叫草冥冥。", "不識城中路，熙熙樂有年。木盤擎社酒，瓦鼓送神錢。", "霜落牛歸屋，禾收雀滿田。遙陂過秋水，閑閣釣魚船。", "長愛田家事，時時欲一過。垣籬皆樹槿，廳院亦堆禾。", "病果因風落，寒蔬向日多。遙聞數聲笛，牛晚下前坡。"]'),
('yuding-38','新竹','李建勳','唐','御定全唐诗','yuding','','[]','嫋嫋熏風軟，娟娟湛露光。參差仙子仗，迤邐羽林槍。',96,'御定全唐詩/json/739.json','["嫋嫋熏風軟，娟娟湛露光。參差仙子仗，迤邐羽林槍。", "迥去侵花地，斜來破蘚牆。籜幹猶抱翠，粉膩若塗裝。", "徑曲莖難數，陰疏葉未長。懶嫌吟客倚，甘畏夏蟲傷。", "映水如爭立，當軒自著行。北亭尊酒興，還為此君狂。"]'),
('yuding-39','歸燕詞','李建勳','唐','御定全唐诗','yuding','','[]','羽翼勢雖微，雲霄亦可期。飛翻自有路，鴻鵠莫相嗤。',96,'御定全唐詩/json/739.json','["羽翼勢雖微，雲霄亦可期。飛翻自有路，鴻鵠莫相嗤。", "待侶臨書幌，尋泥傍藻池。沖人穿柳徑，捕蝶繞花枝。", "廣廈來應遍，深宮去不疑。雕梁聲上下，煙浦影參差。", "舊地人潛換，新巢雀謾窺。雙雙暮歸處，疏雨滿江湄。"]'),
('yuding-40','題魏壇二首','李建勳','唐','御定全唐诗','yuding','','[]','不遇至真傳道要，曾看真誥亦何為。舊碑經亂沈荒澗，',80,'御定全唐詩/json/739.json','["不遇至真傳道要，曾看真誥亦何為。舊碑經亂沈荒澗，", "蕭條夕景空壇畔，朽檜枝斜綠蔓垂。", "一尋遺跡到仙鄉，雲鶴沉沉思渺茫。丹井歲深生草木，", "薄暮欲歸仍佇立，菖蒲風起水泱泱。"]'),
('yuding-41','東樓看雪','李建勳','唐','御定全唐诗','yuding','','[]','一上高樓醉複醒，日西江雪更冥冥。化風吹火全無氣，',40,'御定全唐詩/json/739.json','["一上高樓醉複醒，日西江雪更冥冥。化風吹火全無氣，", "因思舊隱匡廬日，閑看杉檉掩石扃。"]'),
('yuding-42','落花','李建勳','唐','御定全唐诗','yuding','','[]','惜花無計又花殘，獨繞芳叢不忍看。暖豔動隨鶯翅落，',40,'御定全唐詩/json/739.json','["惜花無計又花殘，獨繞芳叢不忍看。暖豔動隨鶯翅落，", "忍把一尊重命樂，送春招客亦何歡。"]'),
('yuding-43','春雪','李建勳','唐','御定全唐诗','yuding','','[]','南國春寒朔氣回，霏霏還阻百花開。全移暖律何方去，',40,'御定全唐詩/json/739.json','["南國春寒朔氣回，霏霏還阻百花開。全移暖律何方去，", "不知金勒誰家子，只待晴明賞帝台。"]'),
('yuding-44','重戲和春雪寄沈員外','李建勳','唐','御定全唐诗','yuding','','[]','誰道江南要雪難，半春猶得倚樓看。卻遮遲日偷鶯暖，',40,'御定全唐詩/json/739.json','["誰道江南要雪難，半春猶得倚樓看。卻遮遲日偷鶯暖，", "和來瓊什雖無敵，且是儂家比興殘。"]'),
('yuding-45','春日尊前示從事','李建勳','唐','御定全唐诗','yuding','','[]','州中案牘魚鱗密，界上軍書竹節稠。眼底好花渾似雪，',40,'御定全唐詩/json/739.json','["州中案牘魚鱗密，界上軍書竹節稠。眼底好花渾似雪，", "最覺此春無氣味，不如庭草解忘憂。"]'),
('yuding-46','尊前','李建勳','唐','御定全唐诗','yuding','','[]','官為將相複何求，世路多端早合休。漸老更知春可惜，',40,'御定全唐詩/json/739.json','["官為將相複何求，世路多端早合休。漸老更知春可惜，", "莫厭百壺相勸倒，免教無事結閒愁。"]'),
('yuding-47','薔薇二首','李建勳','唐','御定全唐诗','yuding','','[]','萬蕊爭開照檻光，詩家何物可相方。錦江風撼雲霞碎，',80,'御定全唐詩/json/739.json','["萬蕊爭開照檻光，詩家何物可相方。錦江風撼雲霞碎，", "彩箋蠻榼旬休日，欲召親賓看一場。", "拂簷拖地對前墀，蝶影蜂聲爛熳時。萬倍馨香勝玉蕊，", "將並舞腰誰得及，惹衣傷手盡從伊。"]'),
('yuding-48','殘牡丹','李建勳','唐','御定全唐诗','yuding','','[]','腸斷題詩如執別，芳茵愁更繞闌鋪。風飄金蕊看全落，',40,'御定全唐詩/json/739.json','["腸斷題詩如執別，芳茵愁更繞闌鋪。風飄金蕊看全落，", "回看池館春休也，又是迢迢看畫圖。"]'),
('yuding-49','春雨二首','李建勳','唐','御定全唐诗','yuding','','[]','春霖未免妨遊賞，唯到詩家自有情。花徑不通新草合，',80,'御定全唐詩/json/739.json','["春霖未免妨遊賞，唯到詩家自有情。花徑不通新草合，", "閑憶昔年為客處，悶留山館阻行行。", "蕭蕭春雨密還疏，景象三時固不如，寒入遠林鶯翅重，", "唯稱乖慵多睡者，掩門中酒覽閒書。"]'),
('yuding-50','醉中惜花更書與諸從事','李建勳','唐','御定全唐诗','yuding','','[]','公退尋芳已是遲，莫因他事更來稀。未經旬日唯憂落，',40,'御定全唐詩/json/739.json','["公退尋芳已是遲，莫因他事更來稀。未經旬日唯憂落，", "高樓鼓絕重門閉，長為拋回恨解衣。"]'),
('yuding-51','和判官喜雨','李建勳','唐','御定全唐诗','yuding','','[]','去禱山川尚未還，雲雷尋作遠聲寒。人情便似秋登悅，',40,'御定全唐詩/json/739.json','["去禱山川尚未還，雲雷尋作遠聲寒。人情便似秋登悅，", "須知太守重牆內，心極農夫望處歡。"]'),
('yuding-52','離闕下日感恩','李建勳','唐','御定全唐诗','yuding','','[]','二年塵冒處中台，喜得南歸退不才。即路敢期皇子送，',40,'御定全唐詩/json/739.json','["二年塵冒處中台，喜得南歸退不才。即路敢期皇子送，", "斜日葦汀凝立處，遠波微颺翠如苔。"]'),
('yuding-53','細雨遙懷故人','李建勳','唐','御定全唐诗','yuding','','[]','江雲未散東風暖，溟蒙正在高樓見。細柳緣堤少過人，',40,'御定全唐詩/json/739.json','["江雲未散東風暖，溟蒙正在高樓見。細柳緣堤少過人，", "昨夜南窗不得眠，閑階點滴回燈坐。"]'),
('yuding-54','春水','李建勳','唐','御定全唐诗','yuding','','[]','萬派爭流雨過時，晚來春靜更逶迤。輕鷗散繞夫差國，',40,'御定全唐詩/json/739.json','["萬派爭流雨過時，晚來春靜更逶迤。輕鷗散繞夫差國，", "風鬟倚楫誰家子，愁看鴛鴦望所之。"]'),
('yuding-55','蝶','李建勳','唐','御定全唐诗','yuding','','[]','粉蝶翩翩若有期，南園長是到春歸。閑依柳帶參差起，',40,'御定全唐詩/json/739.json','["粉蝶翩翩若有期，南園長是到春歸。閑依柳帶參差起，", "晚來欲雨東風急，回看池塘影漸稀。"]'),
('yuding-56','中春寫懷寄沈彬員外','李建勳','唐','御定全唐诗','yuding','','[]','省從騎竹學謳吟，便殢光陰役此心。寓目不能閑一日，',40,'御定全唐詩/json/739.json','["省從騎竹學謳吟，便殢光陰役此心。寓目不能閑一日，", "唯有故人同此興，近來何事懶相尋。"]'),
('yuding-57','鐘山寺避暑勉二三子','李建勳','唐','御定全唐诗','yuding','','[]','樓臺雖少景何深，滿地青苔勝布金。松影晚留僧共坐，',40,'御定全唐詩/json/739.json','["樓臺雖少景何深，滿地青苔勝布金。松影晚留僧共坐，", "長愛寄吟經案上，石窗秋霽向千岑。"]'),
('yuding-58','道林寺','李建勳','唐','御定全唐诗','yuding','','[]','雖向鐘峰數寺連，就中奇勝出其間。不教幽樹妨閑地，',40,'御定全唐詩/json/739.json','["雖向鐘峰數寺連，就中奇勝出其間。不教幽樹妨閑地，", "無因得結香燈社，空向王門玷玉班。"]'),
('yuding-59','和致仕沈郎中','李建勳','唐','御定全唐诗','yuding','','[]','欲謀休退尚因循，且向東溪種白蘋。謬應星辰居四輔，',40,'御定全唐詩/json/739.json','["欲謀休退尚因循，且向東溪種白蘋。謬應星辰居四輔，", "殘照晚庭沈醉醒，靜吟斜倚老松身。"]'),
('yuding-60','醉中詠梅花','李建勳','唐','御定全唐诗','yuding','','[]','十月清霜尚未寒，雪英重疊已如摶。還悲獨詠東園裏，',40,'御定全唐詩/json/739.json','["十月清霜尚未寒，雪英重疊已如摶。還悲獨詠東園裏，", "交親罕至長安遠，一醉如泥豈自歡。"]'),
('yuding-61','閑出書懷','李建勳','唐','御定全唐诗','yuding','','[]','閒遊何用問東西，寓興皆非有所期。斷酒只攜僧共去，',40,'御定全唐詩/json/739.json','["閒遊何用問東西，寓興皆非有所期。斷酒只攜僧共去，", "應有交親長笑我，獨輕人事鬢將衰。"]'),
('yuding-62','寺居陸處士相訪，感懷卻寄二三友人','李建勳','唐','御定全唐诗','yuding','','[]','湘寺閒居亦半年，就中昨夜好潸然。人歸遠岫疏鐘後，',40,'御定全唐詩/json/739.json','["湘寺閒居亦半年，就中昨夜好潸然。人歸遠岫疏鐘後，", "爐煙向冷孤燈下，唯有寒吟到曙天。"]'),
('yuding-63','春雪','李建勳','唐','御定全唐诗','yuding','','[]','隨風竟日勢漫漫，特地繁於故歲看。幽榭凍黏花屋重，',40,'御定全唐詩/json/739.json','["隨風竟日勢漫漫，特地繁於故歲看。幽榭凍黏花屋重，", "莫道便為桑麥藥，亦勝焦涸到春殘。"]'),
('yuding-64','惜花','李建勳','唐','御定全唐诗','yuding','','[]','淡淡西園日又垂，一尊何忍負芳枝。莫言風雨長相促，',40,'御定全唐詩/json/739.json','["淡淡西園日又垂，一尊何忍負芳枝。莫言風雨長相促，", "年年使我成狂叟，腸斷紅箋幾首詩。"]'),
('yuding-65','梅花寄所親','李建勳','唐','御定全唐诗','yuding','','[]','一氣才新物未知，每慚青律與先吹。雪霜迷素猶嫌早，',40,'御定全唐詩/json/739.json','["一氣才新物未知，每慚青律與先吹。雪霜迷素猶嫌早，", "老夫多病無風味，只向尊前詠舊詩。"]'),
('yuding-66','登升元閣','李建勳','唐','御定全唐诗','yuding','','[]','登高始覺太虛寬，白雪須知唱和難。雲渡瑣窗金榜濕，',40,'御定全唐詩/json/739.json','["登高始覺太虛寬，白雪須知唱和難。雲渡瑣窗金榜濕，", "唯有上層人未到，金烏飛過拂闌幹。"]'),
('yuding-67','雪有作','李建勳','唐','御定全唐诗','yuding','','[]','霏霏奕奕滿寒空，況是難逢值臘中。未白已堪張宴會，',40,'御定全唐詩/json/739.json','["霏霏奕奕滿寒空，況是難逢值臘中。未白已堪張宴會，", "長愛清華入詩句，預愁遲日放消融。"]'),
('yuding-68','宮詞','李建勳','唐','御定全唐诗','yuding','','[]','自遠凝旒守上陽，舞衣頓減舊朝香。簾垂粉閣春將盡，',40,'御定全唐詩/json/739.json','["自遠凝旒守上陽，舞衣頓減舊朝香。簾垂粉閣春將盡，", "君王一去不回駕，皓齒青蛾空斷腸。"]'),
('yuding-69','晚春送牡丹','李建勳','唐','御定全唐诗','yuding','','[]','攜觴邀客繞朱闌，腸斷殘春送牡丹。風雨數來留不得，',40,'御定全唐詩/json/739.json','["攜觴邀客繞朱闌，腸斷殘春送牡丹。風雨數來留不得，", "借問少年能幾許，不許推酒厭杯盤。"]'),
('yuding-70','歲暮晚泊，望廬山不見，因懷嶽僧呈察判','李建勳','唐','御定全唐诗','yuding','','[]','貪程只為看廬阜，及到停舟恨頗濃。雲暗半空藏萬仞，',40,'御定全唐詩/json/739.json','["貪程只為看廬阜，及到停舟恨頗濃。雲暗半空藏萬仞，", "長愧昔年招我入，共尋香社見芙蓉。"]'),
('yuding-71','重台蓮','李建勳','唐','御定全唐诗','yuding','','[]','斜倚秋風絕比倫，千英和露染難勻。自為祥瑞生南國，',40,'御定全唐詩/json/739.json','["斜倚秋風絕比倫，千英和露染難勻。自為祥瑞生南國，", "憐伊不算多時立，贏得馨香暗上身。"]'),
('yuding-72','迎神','李建勳','唐','御定全唐诗','yuding','','[]','攂蠻鼉，吟塞笛，女巫結束分行立。空中再拜神且來，',40,'御定全唐詩/json/739.json','["攂蠻鼉，吟塞笛，女巫結束分行立。空中再拜神且來，", "與君降福為豐年，莫教賽祀虧常筵。"]'),
('yuding-73','春詞','李建勳','唐','御定全唐诗','yuding','','[]','日高閒步下堂階，細草春莎沒繡鞋。',32,'御定全唐詩/json/739.json','["日高閒步下堂階，細草春莎沒繡鞋。", "折得玫瑰花一朵，憑君簪向鳳凰釵。"]'),
('yuding-74','獨夜作','李建勳','唐','御定全唐诗','yuding','','[]','佳人一去無消息，夢覺香殘愁複入。',32,'御定全唐詩/json/739.json','["佳人一去無消息，夢覺香殘愁複入。", "空庭悄悄月如霜，獨倚闌幹伴花立。"]'),
('yuding-75','竹','李建勳','唐','御定全唐诗','yuding','','[]','瓊節高吹宿鳳枝，風流交我立忘歸。',32,'御定全唐詩/json/739.json','["瓊節高吹宿鳳枝，風流交我立忘歸。", "最憐瑟瑟斜陽下，花影相和滿客衣。"]'),
('yuding-76','清明日','李建勳','唐','御定全唐诗','yuding','','[]','他皆攜酒尋芳去，我獨關門好靜眠。',32,'御定全唐詩/json/739.json','["他皆攜酒尋芳去，我獨關門好靜眠。", "唯有楊花似相覓，因風時複到床前。"]'),
('yuding-77','宮詞','李建勳','唐','御定全唐诗','yuding','','[]','宮門長閉舞衣閑，略識君王鬢便斑。',32,'御定全唐詩/json/739.json','["宮門長閉舞衣閑，略識君王鬢便斑。", "卻羨落花春不管，禦溝流得到人間。"]'),
('yuding-78','送喻煉師歸茅山','李建勳','唐','御定全唐诗','yuding','','[]','休糧知幾載，臉色似桃紅。半醉離城去，單衣行雪中。',48,'御定全唐詩/json/739.json','["休糧知幾載，臉色似桃紅。半醉離城去，單衣行雪中。", "水聲茅洞曉，雲影石房空。莫學秦時客，音書便不通。"]'),
('yuding-79','和元宗元日大雪登樓','李建勳','唐','御定全唐诗','yuding','','[]','紛紛忽降當元會，著物輕明似月華。狂灑玉墀初散絮，',40,'御定全唐詩/json/739.json','["紛紛忽降當元會，著物輕明似月華。狂灑玉墀初散絮，", "甯意傳來中使出，禦題先賜老僧家。"]'),
('yuding-80','遊棲霞寺','李建勳','唐','御定全唐诗','yuding','','[]','養花天氣近平分，瘦馬來敲白下門。曉色未開山意遠，',40,'御定全唐詩/json/739.json','["養花天氣近平分，瘦馬來敲白下門。曉色未開山意遠，", "此地幾經人聚散，只今王謝獨名存。"]'),
('yuding-81','答湯悅','李建勳','唐','御定全唐诗','yuding','','[]','司空猶不作，那敢作司徒。幸有山翁號，如何不見呼。',24,'御定全唐詩/json/739.json','["司空猶不作，那敢作司徒。幸有山翁號，如何不見呼。"]'),
('yuding-82','金山','李建勳','唐','御定全唐诗','yuding','','[]','不嗟白髮曾遊此，不歎征帆無了期。',32,'御定全唐詩/json/739.json','["不嗟白髮曾遊此，不歎征帆無了期。", "盡日憑闌誰會我，只悲不見韓垂詩。"]'),
('yuding-83','送李冠','李建勳','唐','御定全唐诗','yuding','','[]','勻如春澗長流水，怨似秋枝欲斷蟬。',32,'御定全唐詩/json/739.json','["勻如春澗長流水，怨似秋枝欲斷蟬。", "可惜人間容易聽，清聲不到禦樓前。"]'),
('yuding-84','游宋興寺東岩','李建勳','唐','御定全唐诗','yuding','','[]','幾年不到東岩下，舊住僧亡屋亦無。',32,'御定全唐詩/json/739.json','["幾年不到東岩下，舊住僧亡屋亦無。", "寒日蕭條何物在，朽松經燒石池枯。"]'),
('yuding-85','批周宗書後','李建勳','唐','御定全唐诗','yuding','','[]','偶罷阿衡來典郡，固無閑物可應官。',32,'御定全唐詩/json/739.json','["偶罷阿衡來典郡，固無閑物可應官。", "憑君為報群胥道，莫作循州刺史看。"]'),
('yuding-86','題信果觀壁','李建勳','唐','御定全唐诗','yuding','','[]','春來漲水流而活，曉色西山勢似行。',32,'御定全唐詩/json/739.json','["春來漲水流而活，曉色西山勢似行。", "玉洞主人經劫在，攜竿步步就長生。"]'),
('yuding-87','送八分書與友人，繼以詩','李建勳','唐','御定全唐诗','yuding','','[]','跁跒為詩跁跒書，不封將去寄仙都。',32,'御定全唐詩/json/739.json','["跁跒為詩跁跒書，不封將去寄仙都。", "仙翁拍手應相笑，得似秦朝次仲無。"]'),
('yuding-88','句','李建勳','唐','御定全唐诗','yuding','','[]','桃花流水須長信，不學劉郎去又來。',56,'御定全唐詩/json/739.json','["桃花流水須長信，不學劉郎去又來。", "粟多未必全為計，師老須防有伏兵。", "遍尋雲壑重題石，欲下山門更倚松。（《留別鐘山》，"]'),
('yuding-0','蟠溪懷古','孟賓於','唐','御定全唐诗','yuding','','[]','良哉呂尚父，深隱始歸周。釣石千年在，春風一水流。',48,'御定全唐詩/json/740.json','["良哉呂尚父，深隱始歸周。釣石千年在，春風一水流。", "松根盤蘚石，花影臥沙鷗。誰更懷韜術，追思古渡頭。"]'),
('yuding-1','懷連上舊居','孟賓於','唐','御定全唐诗','yuding','','[]','閑思連上景難齊，樹繞仙鄉路繞溪。明月夜舟漁父唱，',40,'御定全唐詩/json/740.json','["閑思連上景難齊，樹繞仙鄉路繞溪。明月夜舟漁父唱，", "更憶海陽垂釣侶，昔年相遇草萋萋。"]'),
('yuding-2','公子行','孟賓於','唐','御定全唐诗','yuding','','[]','錦衣紅奪彩霞明，侵曉春遊向野庭。',32,'御定全唐詩/json/740.json','["錦衣紅奪彩霞明，侵曉春遊向野庭。", "不識農夫辛苦力，驕驄蹋爛麥青春。"]'),
('yuding-3','湘江亭','孟賓於','唐','御定全唐诗','yuding','','[]','獨宿大中年裏寺，樊籠得出事無心。',32,'御定全唐詩/json/740.json','["獨宿大中年裏寺，樊籠得出事無心。", "寒山夢覺一聲磬，霜葉滿林秋正深。"]'),
('yuding-4','題梅仙館','孟賓於','唐','御定全唐诗','yuding','','[]','仙界路遙雲縹緲，古壇風冷葉蕭騷。',32,'御定全唐詩/json/740.json','["仙界路遙雲縹緲，古壇風冷葉蕭騷。", "後來豈合言淹滯，一尉升騰道最高。"]'),
('yuding-5','題顏氏亭宇','孟賓于','唐','御定全唐诗','yuding','','[]','園林蕭灑聞來久，欲訪因循二十秋。',32,'御定全唐詩/json/740.json','["園林蕭灑聞來久，欲訪因循二十秋。", "今日開襟吟不盡，碧山重疊水長流。"]'),
('yuding-6','晚眺','孟賓於','唐','御定全唐诗','yuding','','[]','倚杖殘秋裏，吟中四顧頻。西風天際雁，落日渡頭人。',48,'御定全唐詩/json/740.json','["倚杖殘秋裏，吟中四顧頻。西風天際雁，落日渡頭人。", "草色衰平野，山陰斂暮塵。卻尋苔徑去，明月照村鄰。"]'),
('yuding-7','獻主司','孟賓於','唐','御定全唐诗','yuding','','[]','那堪雨後更聞蟬，溪隔重湖路七千。',32,'御定全唐詩/json/740.json','["那堪雨後更聞蟬，溪隔重湖路七千。", "憶昔故園楊柳岸，全家送上渡頭船。"]'),
('yuding-8','句','孟賓於','唐','御定全唐诗','yuding','','[]','遠樹連沙靜，閑舟入浦遲。',225,'御定全唐詩/json/740.json','["遠樹連沙靜，閑舟入浦遲。", "簾垂群吏散，苔長訟庭閑。", "去年曾折處，今日又垂條。", "早知落處隨疏雨，悔得開時順暖風。", "千家簾幕春空在，幾處樓臺月自明。", "臘雪化為流水去，春風吹出好山來。", "昔日聲塵喧洛下，近年詩句滿江南。", "匝地人家憑檻見，遠山秋色捲簾看。（《永州法華寺高軒》，", "蟾宮空手下，澤國更誰來。", "水國二親應探榜，龍門三月又傷春。", "仙鳥卻回空說夢，清朝未達自嫌身。", "失意從他桃李春，嵩陽經過歇行塵。", "雲僧不見城中事，問是今年第幾人。", "因逢日者教重應，忍被雲僧勸卻歸。（賓于應舉，"]'),
('yuding-9','九日陪董內召登高','廖匡圖','唐','御定全唐诗','yuding','','[]','祝融峰下逢嘉節，相對那能不愴神。煙裏共尋幽澗菊，',40,'御定全唐詩/json/740.json','["祝融峰下逢嘉節，相對那能不愴神。煙裏共尋幽澗菊，", "自古登高盡惆悵，茱萸休笑淚盈巾。"]'),
('yuding-10','贈泉陵上人','廖匡圖','唐','御定全唐诗','yuding','','[]','暫把枯藤倚碧根，禪堂初創楚江濆。直疑松小難留鶴，',40,'御定全唐詩/json/740.json','["暫把枯藤倚碧根，禪堂初創楚江濆。直疑松小難留鶴，", "每來共憶曾游處，萬壑泉聲絕頂聞。"]'),
('yuding-11','和人贈沈彬','廖匡圖','唐','御定全唐诗','yuding','','[]','冥鴻跡在煙霞上，燕雀休誇大廈巢。名利最為浮世重，',40,'御定全唐詩/json/740.json','["冥鴻跡在煙霞上，燕雀休誇大廈巢。名利最為浮世重，", "深喜卜居連嶽色，水邊竹下得論交。"]'),
('yuding-12','松','廖匡圖','唐','御定全唐诗','yuding','','[]','曾于西晉封中散，又向東吳作大夫。濃翠自知千古在，',40,'御定全唐詩/json/740.json','["曾于西晉封中散，又向東吳作大夫。濃翠自知千古在，", "直待素秋搖落日，始將凡木鬥榮枯。"]'),
('yuding-13','句','廖匡圖','唐','御定全唐诗','yuding','','[]','正悲世上事無限，細看水中塵更多。',16,'御定全唐詩/json/740.json','["正悲世上事無限，細看水中塵更多。"]'),
('yuding-14','中秋月','廖凝','唐','御定全唐诗','yuding','','[]','九十日秋色，今宵已半分。孤光含列宿，四面絕纖雲。',48,'御定全唐詩/json/740.json','["九十日秋色，今宵已半分。孤光含列宿，四面絕纖雲。", "眾木排疏影，寒流疊細紋。遙遙望丹桂，心緒正紛紛。"]'),
('yuding-15','聞蟬','廖凝','唐','御定全唐诗','yuding','','[]','一聲初應候，萬木已西風。偏感異鄉客，先於離塞鴻。',48,'御定全唐詩/json/740.json','["一聲初應候，萬木已西風。偏感異鄉客，先於離塞鴻。", "日斜金穀靜，雨過石城空。此處不堪聽，蕭條千古同。"]'),
('yuding-16','彭澤解印','廖凝','唐','御定全唐诗','yuding','','[]','五鬥徒勞謾折腰，三年兩鬢為誰焦。',32,'御定全唐詩/json/740.json','["五鬥徒勞謾折腰，三年兩鬢為誰焦。", "今朝官滿重歸去，還挈來時舊酒瓢。"]'),
('yuding-17','句','廖凝','唐','御定全唐诗','yuding','','[]','滿汀漚不散，一局黑全輸。（《十歲詠棋》，',88,'御定全唐詩/json/740.json','["滿汀漚不散，一局黑全輸。（《十歲詠棋》，", "獵回千帳雪，探密大河冰。", "落盡最高樹，始知松柏青。", "飯僧春嶺蕨，醒酒雪潭魚。", "風清竹閣留僧宿，雨濕莎庭放吏衙。", "紅躑躅繁金殿暖，碧芙蓉笑水宮秋。"]'),
('yuding-18','贈廖凝','韋鼎','唐','御定全唐诗','yuding','','[]','君與白雲鄰，生涯久忍貧。姓名高雅道，寰海許何人。',48,'御定全唐詩/json/740.json','["君與白雲鄰，生涯久忍貧。姓名高雅道，寰海許何人。", "嶽氣秋來早，亭寒果落新。幾回吟石畔，孤鶴自相親。"]'),
('yuding-19','寄廬山白上人','左偃','唐','御定全唐诗','yuding','','[]','潦倒門前客，閑眠歲又殘。連天數峰雪，終日與誰看。',48,'御定全唐詩/json/740.json','["潦倒門前客，閑眠歲又殘。連天數峰雪，終日與誰看。", "萬丈高松古，千尋落水寒。仍聞有新作，懶寄入長安。"]'),
('yuding-20','寄韓侍郎','左偃','唐','御定全唐诗','yuding','','[]','謀身謀隱兩無成，拙計深慚負耦耕。漸老可堪懷故國，',40,'御定全唐詩/json/740.json','["謀身謀隱兩無成，拙計深慚負耦耕。漸老可堪懷故國，", "今日況聞搜草澤，獨悲憔悴臥升平。"]'),
('yuding-21','漢宮詞','左偃','唐','御定全唐诗','yuding','','[]','寒燭照清夜，笙歌隔蘚牆。一從飛燕入，便不見君王。',24,'御定全唐詩/json/740.json','["寒燭照清夜，笙歌隔蘚牆。一從飛燕入，便不見君王。"]'),
('yuding-22','送君去','左偃','唐','御定全唐诗','yuding','','[]','關河月未曉，行子心已急。佳人無一言，獨背殘燈泣。',24,'御定全唐詩/json/740.json','["關河月未曉，行子心已急。佳人無一言，獨背殘燈泣。"]'),
('yuding-23','秋晚野望','左偃','唐','御定全唐诗','yuding','','[]','倚筇聊一望，何處是秦川。草色初晴路，鴻聲欲暮天。',24,'御定全唐詩/json/740.json','["倚筇聊一望，何處是秦川。草色初晴路，鴻聲欲暮天。"]'),
('yuding-24','郊原晚望懷李秘書','左偃','唐','御定全唐诗','yuding','','[]','歸鳥入平野，寒雲在遠村。徒令睇望久，不復見王孫。',24,'御定全唐詩/json/740.json','["歸鳥入平野，寒雲在遠村。徒令睇望久，不復見王孫。"]'),
('yuding-25','言懷別同志','左偃','唐','御定全唐诗','yuding','','[]','漸老將誰托，勞生每自慚。何當重攜手，風雨滿江南。',24,'御定全唐詩/json/740.json','["漸老將誰托，勞生每自慚。何當重攜手，風雨滿江南。"]'),
('yuding-26','江上晚泊','左偃','唐','御定全唐诗','yuding','','[]','寒雲淡淡天無際，片帆落處沙鷗起。',32,'御定全唐詩/json/740.json','["寒雲淡淡天無際，片帆落處沙鷗起。", "水闊風高日複斜，扁舟獨宿蘆花裏。"]'),
('yuding-27','寄鑒上人','左偃','唐','御定全唐诗','yuding','','[]','一從攜手阻戈鋋，屈指如今已十年。',32,'御定全唐詩/json/740.json','["一從攜手阻戈鋋，屈指如今已十年。", "長記二林同宿夜，竹齋聽雨共忘眠。"]'),
('yuding-28','送人','左偃','唐','御定全唐诗','yuding','','[]','一莖兩莖華發生，千枝萬枝梨花白。',32,'御定全唐詩/json/740.json','["一莖兩莖華發生，千枝萬枝梨花白。", "春色江南獨未歸，今朝又送還鄉客。"]'),
('yuding-29','句','左偃','唐','御定全唐诗','yuding','','[]','胡笳聞欲死，漢月望還生。',24,'御定全唐詩/json/740.json','["胡笳聞欲死，漢月望還生。", "日華離碧海，雲影散青霄。"]'),
('yuding-0','景陽臺懷古','陳貺','唐','御定全唐诗','yuding','','[]','景陽六朝地，運極自依依。一會皆同是，到頭誰論非。',48,'御定全唐詩/json/741.json','["景陽六朝地，運極自依依。一會皆同是，到頭誰論非。", "酒濃沈遠慮，花好失前機。見此尤宜戒，正當家國肥。"]'),
('yuding-1','石城懷古','劉洞','唐','御定全唐诗','yuding','','[]','石城古岸頭，一望思悠悠。幾許六朝事，不禁江水流。',24,'御定全唐詩/json/741.json','["石城古岸頭，一望思悠悠。幾許六朝事，不禁江水流。"]'),
('yuding-2','句','劉洞','唐','御定全唐诗','yuding','','[]','千里長江皆渡馬，十年養士得何人。',75,'御定全唐詩/json/741.json','["千里長江皆渡馬，十年養士得何人。", "翻憶潘郎章奏內，愔愔日暮好沾巾。（《江南野錄》：", "金陵受圍，洞為七言詩，榜路傍云云。「家國愔愔，", "百骸同草木，萬象入心靈。"]'),
('yuding-3','旅懷','江為','唐','御定全唐诗','yuding','','[]','迢迢江漢路，秋色又堪驚。半夜聞鴻雁，多年別弟兄。',48,'御定全唐詩/json/741.json','["迢迢江漢路，秋色又堪驚。半夜聞鴻雁，多年別弟兄。", "高風雲影斷，微雨菊花明。欲寄東歸信，裴回無限情。"]'),
('yuding-4','江行','江為','唐','御定全唐诗','yuding','','[]','越信來年稀，孤舟幾夢歸。月寒花露重，江晚水煙微。',48,'御定全唐詩/json/741.json','["越信來年稀，孤舟幾夢歸。月寒花露重，江晚水煙微。", "峰直帆相望，沙空鳥自飛。何時洞庭上，春雨滿蓑衣。"]'),
('yuding-5','登潤州城','江為','唐','御定全唐诗','yuding','','[]','天末江城晚，登臨客望迷。春潮平島嶼，殘雨隔虹霓。',48,'御定全唐詩/json/741.json','["天末江城晚，登臨客望迷。春潮平島嶼，殘雨隔虹霓。", "鳥與孤帆遠，煙和獨樹低。鄉山何處是，目斷廣陵西。"]'),
('yuding-6','岳陽樓','江為','唐','御定全唐诗','yuding','','[]','倚樓高望極，展轉念前途。晚葉紅殘楚，秋江碧入吳。',48,'御定全唐詩/json/741.json','["倚樓高望極，展轉念前途。晚葉紅殘楚，秋江碧入吳。", "雲中來雁急，天末去帆孤。明月誰同我，悠悠上帝都。"]'),
('yuding-7','送客','江為','唐','御定全唐诗','yuding','','[]','明月孤舟遠，吟髭鑷更華。天形圍澤國，秋色露人家。',48,'御定全唐詩/json/741.json','["明月孤舟遠，吟髭鑷更華。天形圍澤國，秋色露人家。", "水館螢交影，霜洲橘委花。何當尋舊隱，泉石好生涯。"]'),
('yuding-8','臨刑詩','江為','唐','御定全唐诗','yuding','','[]','街鼓侵人急，西傾日欲斜。黃泉無旅店，今夜宿誰家。',24,'御定全唐詩/json/741.json','["街鼓侵人急，西傾日欲斜。黃泉無旅店，今夜宿誰家。"]'),
('yuding-9','塞下曲','江為','唐','御定全唐诗','yuding','','[]','萬里黃雲凍不飛，磧煙烽火夜深微。',32,'御定全唐詩/json/741.json','["萬里黃雲凍不飛，磧煙烽火夜深微。", "胡兒移帳寒笳絕，雪路時聞探馬歸。"]'),
('yuding-10','隋堤柳','江為','唐','御定全唐诗','yuding','','[]','錦纜龍舟萬里來，醉鄉繁盛忽塵埃。',32,'御定全唐詩/json/741.json','["錦纜龍舟萬里來，醉鄉繁盛忽塵埃。", "空餘兩岸千株柳，雨葉風花作恨媒。"]'),
('yuding-11','句','江為','唐','御定全唐诗','yuding','','[]','吟登蕭寺旃檀閣，醉倚王家玳瑁筵。',37,'御定全唐詩/json/741.json','["吟登蕭寺旃檀閣，醉倚王家玳瑁筵。", "遠遠朝宗出白雲，方圓隨處性長存。（《水》，"]'),
('yuding-12','詠鷹','高越','唐','御定全唐诗','yuding','','[]','雪爪星眸世所稀，摩天專待振毛衣。',32,'御定全唐詩/json/741.json','["雪爪星眸世所稀，摩天專待振毛衣。", "虞人莫謾張羅網，未肯平原淺草飛。"]'),
('yuding-0','惜花','張泌','唐','御定全唐诗','yuding','','[]','蝶散鶯啼尚數枝，日斜風定更離披。',32,'御定全唐詩/json/742.json','["蝶散鶯啼尚數枝，日斜風定更離披。", "看多記得傷心事，金谷樓前委地時。"]'),
('yuding-1','寄人','張泌','唐','御定全唐诗','yuding','','[]','別夢依依到謝家，小廊回合曲闌斜。',64,'御定全唐詩/json/742.json','["別夢依依到謝家，小廊回合曲闌斜。", "多情只有春庭月，猶為離人照落花。", "酷憐風月為多情，還到春時別恨生。", "倚柱尋思倍惆悵，一場春夢不分明。"]'),
('yuding-2','邊上','張泌','唐','御定全唐诗','yuding','','[]','戍樓吹角起征鴻，獵獵寒旌背晚風。千里暮煙愁不盡，',40,'御定全唐詩/json/742.json','["戍樓吹角起征鴻，獵獵寒旌背晚風。千里暮煙愁不盡，", "只此旅魂招未得，更堪回首夕陽中。"]'),
('yuding-3','長安道中早行','張泌','唐','御定全唐诗','yuding','','[]','客離孤館一燈殘，牢落星河欲曙天。雞唱未沈函穀月，',40,'御定全唐詩/json/742.json','["客離孤館一燈殘，牢落星河欲曙天。雞唱未沈函穀月，", "何事悠悠策羸馬，此中辛苦過流年。"]'),
('yuding-4','洞庭阻風','張泌','唐','御定全唐诗','yuding','','[]','空江浩蕩景蕭然，盡日菰蒲泊釣船。青草浪高三月渡，',40,'御定全唐詩/json/742.json','["空江浩蕩景蕭然，盡日菰蒲泊釣船。青草浪高三月渡，", "猶有漁人數家住，不成村落夕陽邊。"]'),
('yuding-5','春日旅泊桂州','張泌','唐','御定全唐诗','yuding','','[]','暖風芳草竟芊綿，多病多愁負少年。弱柳未勝寒食雨，',40,'御定全唐詩/json/742.json','["暖風芳草竟芊綿，多病多愁負少年。弱柳未勝寒食雨，", "獨有離人開淚眼，強憑杯酒亦潸然。"]'),
('yuding-6','晚次湘源縣','張泌','唐','御定全唐诗','yuding','','[]','煙郭遙聞向晚雞，水準舟靜浪聲齊。高林帶雨楊梅熟，',40,'御定全唐詩/json/742.json','["煙郭遙聞向晚雞，水準舟靜浪聲齊。高林帶雨楊梅熟，", "湘南自古多離怨，莫動哀吟易慘淒。"]'),
('yuding-7','惆悵吟','張泌','唐','御定全唐诗','yuding','','[]','秋風丹葉動荒城，慘澹雲遮日半明。晝夢卻因惆悵得，',40,'御定全唐詩/json/742.json','["秋風丹葉動荒城，慘澹雲遮日半明。晝夢卻因惆悵得，", "千古怨魂銷不得，一江寒浪若為平。"]'),
('yuding-8','秋晚過洞庭','張泌','唐','御定全唐诗','yuding','','[]','征帆初掛酒初酣，暮景離情兩不堪。千里晚霞雲夢北，',40,'御定全唐詩/json/742.json','["征帆初掛酒初酣，暮景離情兩不堪。千里晚霞雲夢北，", "莫把羈魂吊湘魄，九疑愁絕鎖煙嵐。"]'),
('yuding-9','題華嚴寺木塔','張泌','唐','御定全唐诗','yuding','','[]','六街晴色動秋光，雨霽憑高只易傷。一曲晚煙浮渭水，',40,'御定全唐詩/json/742.json','["六街晴色動秋光，雨霽憑高只易傷。一曲晚煙浮渭水，", "回首漢宮樓閣暮，數聲鐘鼓自微茫。"]'),
('yuding-10','經舊游','張泌','唐','御定全唐诗','yuding','','[]','暫到高唐曉又還，丁香結夢水潺潺。',32,'御定全唐詩/json/742.json','["暫到高唐曉又還，丁香結夢水潺潺。", "不知雲雨歸何處，歷歷空留十二山。"]'),
('yuding-11','碧戶','張泌','唐','御定全唐诗','yuding','','[]','碧戶扃魚鎖，蘭窗掩鏡臺。落花疑悵望，歸燕自裴回。',120,'御定全唐詩/json/742.json','["碧戶扃魚鎖，蘭窗掩鏡臺。落花疑悵望，歸燕自裴回。", "詠絮知難敵，傷春不易裁。恨從芳草起，愁為晚風來。", "衣惹湘雲薄，眉分楚岫開。香濃眠舊枕，夢好醉春杯。", "小障明金鳳，幽屏點翠苔。寶箏橫塞雁，怨笛落江梅。", "卓氏仍多酒，相如正富才。莫教琴上意，翻作鶴聲哀。"]'),
('yuding-12','芍藥','張泌','唐','御定全唐诗','yuding','','[]','香清粉澹怨殘春，蝶翅蜂須戀蕊塵。閑倚晚風生悵望，',40,'御定全唐詩/json/742.json','["香清粉澹怨殘春，蝶翅蜂須戀蕊塵。閑倚晚風生悵望，", "零落若教隨暮雨，又應愁殺別離人。"]'),
('yuding-13','春晚謠','張泌','唐','御定全唐诗','yuding','','[]','雨微微，煙霏霏，小庭半拆紅薔薇。鈿箏斜倚畫屏曲，',40,'御定全唐詩/json/742.json','["雨微微，煙霏霏，小庭半拆紅薔薇。鈿箏斜倚畫屏曲，", "淩亂楊花撲繡簾，晚窗時有流鶯語。"]'),
('yuding-14','所思','張泌','唐','御定全唐诗','yuding','','[]','空塘水碧春雨微，東風散漫楊柳飛。依依南浦夢猶在，',48,'御定全唐詩/json/742.json','["空塘水碧春雨微，東風散漫楊柳飛。依依南浦夢猶在，", "隔江紅杏一枝明，似玉佳人俯清沼。休向春台更回望，"]'),
('yuding-15','春夕言懷','張泌','唐','御定全唐诗','yuding','','[]','風透疏簾月滿庭，倚欄無事倍傷情。煙垂柳帶纖腰軟，',40,'御定全唐詩/json/742.json','["風透疏簾月滿庭，倚欄無事倍傷情。煙垂柳帶纖腰軟，", "幽窗謾結相思夢，欲化西園蝶未成。"]'),
('yuding-16','春江雨','張泌','唐','御定全唐诗','yuding','','[]','雨溟溟，風泠泠，老松瘦竹臨煙汀。空江冷落野雲重，',40,'御定全唐詩/json/742.json','["雨溟溟，風泠泠，老松瘦竹臨煙汀。空江冷落野雲重，", "子規叫斷獨未眠，罨岸春濤打船尾。"]'),
('yuding-17','送容州中丞赴鎮','張泌','唐','御定全唐诗','yuding','','[]','交趾同星坐，龍泉佩鬥文。燒香翠羽帳，看舞郁金裙。',48,'御定全唐詩/json/742.json','["交趾同星坐，龍泉佩鬥文。燒香翠羽帳，看舞郁金裙。", "鷁首沖瀧浪，犀渠拂嶺雲。莫教銅柱北，只說馬將軍。"]'),
('yuding-18','贈韓道士','張泌','唐','御定全唐诗','yuding','','[]','日暮秋風吹野花，上清歸客意無涯。桃源寂寂煙霞閉，',40,'御定全唐詩/json/742.json','["日暮秋風吹野花，上清歸客意無涯。桃源寂寂煙霞閉，", "東城南陌頻相見，應是壺中別有家。"]'),
('yuding-0','甘露寺','孫魴','唐','御定全唐诗','yuding','','[]','寒暄皆有景，孤絕畫難形。地拱千尋嶮，天垂四面青。',48,'御定全唐詩/json/743.json','["寒暄皆有景，孤絕畫難形。地拱千尋嶮，天垂四面青。", "晝燈籠雁塔，夜磬徹漁汀。最愛僧房好，波光滿戶庭。"]'),
('yuding-1','題金山寺','孫魴','唐','御定全唐诗','yuding','','[]','萬古波心寺，金山名目新。天多剩得月，地少不生塵。',48,'御定全唐詩/json/743.json','["萬古波心寺，金山名目新。天多剩得月，地少不生塵。", "過櫓妨僧定，驚濤濺佛身。誰言張處士，題後更無人。"]'),
('yuding-2','楊柳枝詞五首','孫魴','唐','御定全唐诗','yuding','','[]','靈和風暖太昌春，舞線搖絲向昔人。',160,'御定全唐詩/json/743.json','["靈和風暖太昌春，舞線搖絲向昔人。", "何似曉來江雨後，一行如畫隔遙津。", "彭澤初栽五樹時，只應閑看一枝垂。", "不知天意風流處，要與佳人學畫眉。", "暖傍離亭靜拂橋，入流穿檻綠陰搖。", "不知落日誰相送，魂斷千條與萬條。", "春來綠樹遍天涯，未見垂楊未可誇。", "晴日萬株煙一陣，閑坊兼是莫愁家。", "十首當年有舊詞，唱青歌翠幾無遺。", "未曾得向行人道，不謂離情莫折伊。"]'),
('yuding-3','句','孫魴','唐','御定全唐诗','yuding','','[]','遊子未歸去，野花愁破心。',64,'御定全唐詩/json/743.json','["遊子未歸去，野花愁破心。", "劃多灰漸冷，坐久席成痕。", "結宇孤峰上，安禪巨浪間。", "分開朝海浪，留住過江雲。", "劃多灰雜蒼虯跡，坐久煙消寶鴨香。"]'),
('yuding-4','入塞二首','沈彬','唐','御定全唐诗','yuding','','[]','欲為皇王服遠戎，萬人金甲鼓鼙中。陣雲黯塞三邊黑，',80,'御定全唐詩/json/743.json','["欲為皇王服遠戎，萬人金甲鼓鼙中。陣雲黯塞三邊黑，", "謗書未及明君爇，臥骨將軍已歿功。", "苦戰沙門臥箭痕，戍樓閑上望星文。生希國澤分偏將，", "功多地遠無人紀，漢閣笙歌日又曛。"]'),
('yuding-5','塞下三首','沈彬','唐','御定全唐诗','yuding','','[]','塞葉聲悲秋欲霜，寒山數點下牛羊。映霞旅雁隨疏雨，',120,'御定全唐詩/json/743.json','["塞葉聲悲秋欲霜，寒山數點下牛羊。映霞旅雁隨疏雨，", "胡兒向化新成長，猶自千回問漢王。", "貴主和親殺氣沉，燕山閑獵鼓鼙音。旗分雪草偷邊馬，", "金釵謾作封侯別，劈破佳人萬里心。", "月冷榆關過雁行，將軍寒笛老思鄉。貳師骨恨千夫壯，", "誰知漢武輕中國，閑奪天山草木荒。"]'),
('yuding-6','秋日','沈彬','唐','御定全唐诗','yuding','','[]','秋含砧杵搗斜陽，笛引西風顥氣涼。薜荔惹煙籠蟋蟀，',40,'御定全唐詩/json/743.json','["秋含砧杵搗斜陽，笛引西風顥氣涼。薜荔惹煙籠蟋蟀，", "腸斷舊遊從一別，潘安惆悵滿頭霜。"]'),
('yuding-7','金陵雜題二首','沈彬','唐','御定全唐诗','yuding','','[]','王氣生秦四百年，晉元東渡浪花船。正慚海內皆塗地，',80,'御定全唐詩/json/743.json','["王氣生秦四百年，晉元東渡浪花船。正慚海內皆塗地，", "千征萬戰英雄盡，落日牛羊食野田。", "暮潮聲落草光沉，賈客來帆宿岸陰。一笛月明何處酒，", "今日到來何物在，碧煙和雨鎖寒林。"]'),
('yuding-8','麻姑山','沈彬','唐','御定全唐诗','yuding','','[]','紺殿松蘿太古山，仙人曾此話桑田。閑傾雲液十分日，',40,'御定全唐詩/json/743.json','["紺殿松蘿太古山，仙人曾此話桑田。閑傾雲液十分日，", "我來游禮酬心願，欲共怡神契自然。"]'),
('yuding-9','題蘇仙山','沈彬','唐','御定全唐诗','yuding','','[]','眼穿林罅見郴州，井裏交連側局楸。味道不來閑處坐，',40,'御定全唐詩/json/743.json','["眼穿林罅見郴州，井裏交連側局楸。味道不來閑處坐，", "千古是非無處問，夕陽西去水東流。"]'),
('yuding-10','洪州解至長安，初舉納省卷夢仙謠','沈彬','唐','御定全唐诗','yuding','','[]','□□□□□□□，□□□□□□□。玉殿大開從客入，',40,'御定全唐詩/json/743.json','["□□□□□□□，□□□□□□□。玉殿大開從客入，", "□□□□□□□，□□□□□□□。"]'),
('yuding-11','憶仙謠','沈彬','唐','御定全唐诗','yuding','','[]','白榆風颯九天秋，王母朝回宴玉樓。日月漸長雙鳳睡，',40,'御定全唐詩/json/743.json','["白榆風颯九天秋，王母朝回宴玉樓。日月漸長雙鳳睡，", "詩酒近來狂不得，騎龍卻憶上清遊。"]'),
('yuding-12','納省卷贈為首劉象','沈彬','唐','御定全唐诗','yuding','','[]','曾應大中天子舉，四朝風月鬢蕭疏。不隨世祖重攜劍，',40,'御定全唐詩/json/743.json','["曾應大中天子舉，四朝風月鬢蕭疏。不隨世祖重攜劍，", "一枝何事於君借，仙桂年年幸有餘。"]'),
('yuding-13','贈王定保','沈彬','唐','御定全唐诗','yuding','','[]','仙桂曾攀第一枝，薄游湘水阻佳期。皋橋已失齊眉願，',40,'御定全唐詩/json/743.json','["仙桂曾攀第一枝，薄游湘水阻佳期。皋橋已失齊眉願，", "聞公已有平生約，謝絕女蘿依兔絲。"]'),
('yuding-14','結客少年場行','沈彬','唐','御定全唐诗','yuding','','[]','重義輕生一劍知，白虹貫日報讎歸。',32,'御定全唐詩/json/743.json','["重義輕生一劍知，白虹貫日報讎歸。", "片心惆悵清平世，酒市無人問布衣。"]'),
('yuding-15','陽朔碧蓮峰','沈彬','唐','御定全唐诗','yuding','','[]','陶潛彭澤五株柳，潘岳河陽一縣花。',32,'御定全唐詩/json/743.json','["陶潛彭澤五株柳，潘岳河陽一縣花。", "兩處爭如陽朔好，碧蓮峰裏住人家。"]'),
('yuding-16','再過金陵','沈彬','唐','御定全唐诗','yuding','','[]','玉樹歌終王氣收，雁行高送石城秋。',32,'御定全唐詩/json/743.json','["玉樹歌終王氣收，雁行高送石城秋。", "江山不管興亡事，一任斜陽伴客愁。"]'),
('yuding-17','都門送別','沈彬','唐','御定全唐诗','yuding','','[]','岸柳蕭疏野荻秋，都門行客莫回頭。',32,'御定全唐詩/json/743.json','["岸柳蕭疏野荻秋，都門行客莫回頭。", "一條灞水清如劍，不為離人割斷愁。"]'),
('yuding-18','吊邊人','沈彬','唐','御定全唐诗','yuding','','[]','殺聲沈後野風悲，漢月高時望不歸。',32,'御定全唐詩/json/743.json','["殺聲沈後野風悲，漢月高時望不歸。", "白骨已枯沙上草，家人猶自寄寒衣。"]'),
('yuding-19','句','沈彬','唐','御定全唐诗','yuding','','[]','尺素隱清輝，一毫分險阻。',207,'御定全唐詩/json/743.json','["尺素隱清輝，一毫分險阻。", "金翅動身摩日月，銀河轉浪洗乾坤。（《獻馬殷頌德》，", "須知手筆安排定，不怕山河整頓難。", "九衢冠蓋暗爭路，四海干戈多異心。", "地隈一水巡城轉，天約群山附郭來。（《題法華寺》，", "數家魚網疏雲外，一岸殘陽細雨中。", "松欹晚影離壇草，鐘撼秋聲入殿風。（《潘天錫同題古觀》，", "壓低吳楚遙涵水，約破雲霞獨倚天。（《望廬山》，", "半身落日離秦樹，一路平蕪入楚煙。", "清占月中三峽水，麗偷雲外十洲春。", "幽鳥喚人穿竹去，野猿尋果出雲來。"]'),
('yuding-0','僻居謝何明府見訪','伍喬','唐','御定全唐诗','yuding','','[]','公退琴堂動逸懷，閑披煙靄訪微才。馬嘶窮巷蛙聲息，',40,'御定全唐詩/json/744.json','["公退琴堂動逸懷，閑披煙靄訪微才。馬嘶窮巷蛙聲息，", "滿齋塵土一床蘚，多謝從容水飯回。"]'),
('yuding-1','冬日道中','伍喬','唐','御定全唐诗','yuding','','[]','去去天涯無定期，瘦童羸馬共依依。暮煙江口客來絕，',40,'御定全唐詩/json/744.json','["去去天涯無定期，瘦童羸馬共依依。暮煙江口客來絕，", "釣台吟閣滄洲在，應為初心未得歸。"]'),
('yuding-2','僻居酬友人','伍喬','唐','御定全唐诗','yuding','','[]','僻居雖愛近林泉，幽徑閒居碧蘚連。向竹掩扉隨鶴息，',24,'御定全唐詩/json/744.json','["僻居雖愛近林泉，幽徑閒居碧蘚連。向竹掩扉隨鶴息，"]'),
('yuding-3','游西山龍泉禪寺','伍喬','唐','御定全唐诗','yuding','','[]','疊巘層峰坐可觀，枕門流水更潺湲。曉鐘聲徹洞溪遠，',40,'御定全唐詩/json/744.json','["疊巘層峰坐可觀，枕門流水更潺湲。曉鐘聲徹洞溪遠，", "因嗟城郭營營事，不得長遊空鬢殘。"]'),
('yuding-4','宿灊山','伍喬','唐','御定全唐诗','yuding','','[]','一入仙山萬慮寬，夜深寧厭倚虛欄。鶴和雲影宿高木，',40,'御定全唐詩/json/744.json','["一入仙山萬慮寬，夜深寧厭倚虛欄。鶴和雲影宿高木，", "更陪羽客論真理，不覺初鐘叩曉殘。"]'),
('yuding-5','遊西禪','伍喬','唐','御定全唐诗','yuding','','[]','遠岫當軒列翠光，高僧一衲萬緣忘。碧松影裏地長潤，',40,'御定全唐詩/json/744.json','["遠岫當軒列翠光，高僧一衲萬緣忘。碧松影裏地長潤，", "遊人戀此吟終日，盛暑樓臺早有涼。"]'),
('yuding-6','寄史處士','伍喬','唐','御定全唐诗','yuding','','[]','長羨閒居一水湄，吟情高古有誰知。石樓待月橫琴久，',40,'御定全唐詩/json/744.json','["長羨閒居一水湄，吟情高古有誰知。石樓待月橫琴久，", "松門別後無消息，早晚重應躡屐隨。"]'),
('yuding-7','僻居秋思寄友人','伍喬','唐','御定全唐诗','yuding','','[]','門巷秋歸更寂寥，雨餘閑砌委蘭苗。夢回月夜蟲吟壁，',40,'御定全唐詩/json/744.json','["門巷秋歸更寂寥，雨餘閑砌委蘭苗。夢回月夜蟲吟壁，", "身名未立猶辛苦，何許流年晚鬢凋。"]'),
('yuding-8','寄落星史虛白處士','伍喬','唐','御定全唐诗','yuding','','[]','白雲峰下古溪頭，曾與提壺爛熳遊。登閣共看彭蠡水，',40,'御定全唐詩/json/744.json','["白雲峰下古溪頭，曾與提壺爛熳遊。登閣共看彭蠡水，", "別後相思時一望，暮山空碧水空流。"]'),
('yuding-9','九江旅夜寄山中故人','伍喬','唐','御定全唐诗','yuding','','[]','弱柳風高遠漏沈，坐來難便息愁吟。江城雪盡寒猶在，',40,'御定全唐詩/json/744.json','["弱柳風高遠漏沈，坐來難便息愁吟。江城雪盡寒猶在，", "此時遙羨閑眠侶，靜掩雲扉臥一林。"]'),
('yuding-10','聞杜牧赴闕','伍喬','唐','御定全唐诗','yuding','','[]','舊隱匡廬一草堂，今聞攜策謁吾皇。峽雲難卷從龍勢，',40,'御定全唐詩/json/744.json','["舊隱匡廬一草堂，今聞攜策謁吾皇。峽雲難卷從龍勢，", "他時得意交知仰，莫忘裁詩寄釣鄉。"]'),
('yuding-11','題西林寺水閣','伍喬','唐','御定全唐诗','yuding','','[]','竹翠苔花繞檻濃，此亭幽致詎曾逢。水分林下清泠派，',40,'御定全唐詩/json/744.json','["竹翠苔花繞檻濃，此亭幽致詎曾逢。水分林下清泠派，", "不知來往留題客，誰約重尋蓮社蹤。"]'),
('yuding-12','林居喜崔三博遠至','伍喬','唐','御定全唐诗','yuding','','[]','幾日區區在遠程，晚煙林徑喜相迎。姿容雖有塵中色，',40,'御定全唐詩/json/744.json','["幾日區區在遠程，晚煙林徑喜相迎。姿容雖有塵中色，", "留連話與方經宿，又欲攜書別我行。"]'),
('yuding-13','觀華夷圖','伍喬','唐','御定全唐诗','yuding','','[]','別手應難及此精，須知攢簇自心靈。始于毫末分諸國，',40,'御定全唐詩/json/744.json','["別手應難及此精，須知攢簇自心靈。始于毫末分諸國，", "筆端盡現寰區事，堪把長懸在戶庭。"]'),
('yuding-14','廬山書堂送祝秀才還鄉','伍喬','唐','御定全唐诗','yuding','','[]','束書辭我下重巔，相送同臨楚岸邊。歸思幾隨千里水，',40,'御定全唐詩/json/744.json','["束書辭我下重巔，相送同臨楚岸邊。歸思幾隨千里水，", "莫使蹉跎戀疏野，男兒酬志在當年。"]'),
('yuding-15','暮冬送何秀才毗陵','伍喬','唐','御定全唐诗','yuding','','[]','匹馬嘶風去思長，素琴孤劍稱戎裝。路塗多是過殘歲，',40,'御定全唐詩/json/744.json','["匹馬嘶風去思長，素琴孤劍稱戎裝。路塗多是過殘歲，", "毗陵城下饒嘉景，回日新詩應滿堂。"]'),
('yuding-16','龍潭張道者','伍喬','唐','御定全唐诗','yuding','','[]','碧洞幽岩獨息心，時人何路得相尋。養生不說憑諸藥，',40,'御定全唐詩/json/744.json','["碧洞幽岩獨息心，時人何路得相尋。養生不說憑諸藥，", "他年功就期飛去，應笑吾徒多苦吟。"]'),
('yuding-17','晚秋同何秀才溪上','伍喬','唐','御定全唐诗','yuding','','[]','閒步秋光思杳然，荷藜因共過林煙。期收野藥尋幽路，',40,'御定全唐詩/json/744.json','["閒步秋光思杳然，荷藜因共過林煙。期收野藥尋幽路，", "倒尊盡日忘歸處，山磬數聲敲暝天。"]'),
('yuding-18','送江少府授延陵後寄','伍喬','唐','御定全唐诗','yuding','','[]','五老雲中勤學者，遇時能不困風塵。束書西上謁明主，',40,'御定全唐詩/json/744.json','["五老雲中勤學者，遇時能不困風塵。束書西上謁明主，", "莫因官小慵之任，自古鸞棲有異人。"]'),
('yuding-19','觀山水障子','伍喬','唐','御定全唐诗','yuding','','[]','功績精妍世少倫，圖時應倍用心神。不知草木承何異，',40,'御定全唐詩/json/744.json','["功績精妍世少倫，圖時應倍用心神。不知草木承何異，", "更疑獨泛漁舟者，便是其中舊隱人。"]'),
('yuding-20','寄張學士洎','伍喬','唐','御定全唐诗','yuding','','[]','不知何處好消憂，公退攜壺即上樓。職事久參侯伯幕，',40,'御定全唐詩/json/744.json','["不知何處好消憂，公退攜壺即上樓。職事久參侯伯幕，", "遙想玉堂多暇日，花時誰伴出城遊。"]'),
('yuding-21','句','伍喬','唐','御定全唐诗','yuding','','[]','積靄沈諸壑，微陽在半峰。',12,'御定全唐詩/json/744.json','["積靄沈諸壑，微陽在半峰。"]'),
('yuding-0','塞下曲','陳陶','唐','御定全唐诗','yuding','','[]','邊頭能走馬，猿臂李將軍。射虎群胡伏，開弓絕塞聞。',96,'御定全唐詩/json/745.json','["邊頭能走馬，猿臂李將軍。射虎群胡伏，開弓絕塞聞。", "海山諳向背，攻守別風雲。只為坑降罪，輕車未轉勳。", "望湖關下戰，雜虜喪全師。鳥啄豺狼將，沙埋日月旗。", "牛羊奔赤狄，部落散燕耆。都護淩晨出，銘功瘞死屍。"]'),
('yuding-1','胡無人行','陳陶','唐','御定全唐诗','yuding','','[]','十萬羽林兒，臨洮破郅支。殺添胡地骨，降足漢營旗。',48,'御定全唐詩/json/745.json','["十萬羽林兒，臨洮破郅支。殺添胡地骨，降足漢營旗。", "塞闊牛羊散，兵休帳幕移。空流隴頭水，嗚咽向人悲。"]'),
('yuding-2','悲哉行','陳陶','唐','御定全唐诗','yuding','','[]','中嶽仇先生，遺余餌松方。服之一千日，肢體生異香。',72,'御定全唐詩/json/745.json','["中嶽仇先生，遺余餌松方。服之一千日，肢體生異香。", "步履如風旋，天涯不齎糧。仍雲為地仙，不得朝虛皇。", "狡兔有三穴，人生又何常。悲哉二廉士，餓死于首陽。"]'),
('yuding-3','塗山懷古','陳陶','唐','御定全唐诗','yuding','','[]','落拓書劍晚，清秋鷹正籠。塗山間來上，敬愛如登龍。',288,'御定全唐詩/json/745.json','["落拓書劍晚，清秋鷹正籠。塗山間來上，敬愛如登龍。", "覽古覺神王，翛然天地空。東南更何有，一醉先王風。", "惟昔放勳世，陰晦徹成洪。皇圖化魚鱉，天道漂無蹤。", "帝乃命舟楫，掇芳儒素中。高陳九州力，百道驅歸東。", "舊物複光明，洪爐再埏熔。經門不私子，足知天下公。", "亮曰那並生，唐虞禪華蟲。茲山朝萬國，一賦寰海同。", "十載有區宇，秋毫皆帝功。垂衣不驕德，子桀如何聾。", "握發聞禮賢，葺茅見卑宮。凡夫色難事，神聖安能恭。", "道隱三千年，遺芳播笙鏞。當時執圭處，佳氣仍童童。", "海嶼儼清廟，天人盛祇供。玄恩及花木，丹讖名崆峒。", "異代草澤臣，何由樹勳庸。堯階未曾識，誰信平生忠。", "恨不當際會，預為執鞭僮。勞歌下山去，懷德心無窮。"]'),
('yuding-4','遊子吟','陳陶','唐','御定全唐诗','yuding','','[]','棲烏喜林曙，驚蓬傷歲闌。關河三尺雪，何處是天山。',132,'御定全唐詩/json/745.json','["棲烏喜林曙，驚蓬傷歲闌。關河三尺雪，何處是天山。", "朔風無重衣，僕馬饑且寒。慘戚別妻子，遲回出門難。", "男兒值休明，豈是長泥蟠。何者為木偶，何人侍金鑾。", "鬱鬱守貧賤，悠悠亦無端。進不圖功名，退不處岩巒。", "窮通在何日，光景如跳丸。富貴苦不早，令人摧心肝。", "誓期春之陽，一振摩霄翰。"]'),
('yuding-5','懷仙吟二首','陳陶','唐','御定全唐诗','yuding','','[]','丹陵五牙客，昨日羅浮歸。赤斧尋不得，煙霞空滿衣。',156,'御定全唐詩/json/745.json','["丹陵五牙客，昨日羅浮歸。赤斧尋不得，煙霞空滿衣。", "試于華陽問，果遇三茅知。采藥向十洲，同行牧羊兒。", "十洲隔八海，浩渺不可期。空留雙白鶴，巢在長松枝。", "雲溪古流水，春晚桃花香。憶與我師別，片帆歸滄浪。", "滄浪在何許，相思淚如雨。黃鶴不復來，雲深離別處。", "石渠泉泠泠，三見菖蒲生。日夜勞夢魂，隨波注東溟。", "空懷別時惠，長讀消魔經。"]'),
('yuding-6','海昌望月','陳陶','唐','御定全唐诗','yuding','','[]','何處無今夕，豈期在海頭。賈客不愛月，嬋娟閑滄洲。',360,'御定全唐詩/json/745.json','["何處無今夕，豈期在海頭。賈客不愛月，嬋娟閑滄洲。", "浩然傷歲華，獨望湖邊樓。煙島青歷歷，藍田白悠悠。", "誰無破鏡期，繄我信虛舟。誰無桂枝念，繄我方摧輈。", "始見彎環春，又逢團圓秋。莫厭綾扇夕，百年多銀鉤。", "金盤誰雕鐫，玉窟難冥搜。重輪運時節，三五不自由。", "疑拋雲上鍋，欲摟天邊球。孀居應寒冷，搗藥青冥愁。", "兔子樹下蹲，蝦蟆池中游。如何名金波，不共水東流。", "天花辟膻腥，野雲無邊陬。蚌蛤乘大運，含珠相對酬。", "夜鵲思南鄉，露華清東甌。百寶安可覷，老龍鎖深湫。", "究究如情人，盜者即仇讎。海涯上皎潔，九門更清幽。", "亭亭勸金尊，夜久喘吳牛。夷俗皆輕擲，北山思今遊。", "雁聲故鄉來，客淚墮南洲。平生煙霞志，讀書覓封侯。", "四海尚白身，豈無故鄉羞。壈坎何足歎，壯如水中虯。", "獵獵谷底蘭，搖搖波上鷗。中途喪資斧，兩地生繁憂。", "一杯太陰君，鷦鷯豈無求。明日將片葉，三山東南浮。"]'),
('yuding-7','蒲門戍觀海作','陳陶','唐','御定全唐诗','yuding','','[]','廓落溟漲曉，蒲門鬱蒼蒼。登樓禮東君，旭日生扶桑。',120,'御定全唐詩/json/745.json','["廓落溟漲曉，蒲門鬱蒼蒼。登樓禮東君，旭日生扶桑。", "毫釐見蓬瀛，含吐金銀光。草木露未晞，蜃樓氣若藏。", "欲游蟠桃國，慮涉魑魅鄉。徐市惑秦朝，何人在岩廊。", "惜哉千童子，葬骨於眇茫。恭聞槎客言，東池接天潢。", "即此聘牛女，曰祈長壽方。靈津水清淺，余亦慕修航。"]'),
('yuding-8','番禺道中作','陳陶','唐','御定全唐诗','yuding','','[]','博羅程遠近，海塞愁先入。瘴雨出虹蝀，蠻江渡山急。',96,'御定全唐詩/json/745.json','["博羅程遠近，海塞愁先入。瘴雨出虹蝀，蠻江渡山急。", "常聞島夷俗，犀象滿城邑。雁至草猶春，潮回檣半濕。", "丹丘鳳凰隱，水廟蛟龍集。何處樹能言，幾鄉珠是泣。", "千年趙佗國，霸氣委原隰。齷齪笑終軍，長纓禍先及。"]'),
('yuding-9','贈江西周大夫','陳陶','唐','御定全唐诗','yuding','','[]','否極生大賢，九元降靈氣。獨立正始風，蔚然中興瑞。',228,'御定全唐詩/json/745.json','["否極生大賢，九元降靈氣。獨立正始風，蔚然中興瑞。", "淵倫照三古，磊落涵涇渭。真貌月懸秋，雄詞雷出地。", "具瞻先皇寵，欲踐東華貴。咫尺時不來，千秋鼎湖淚。", "因分三輔職，進領南平位。報政黃霸慚，提兵呂蒙醉。", "歲星臨鬥牛，水國嘉祥至。不獨蒼生蘇，仍兼六騶喜。", "恭聞廟堂略，欲斷匈奴臂。剗釋自宸衷，平戍在連帥。", "時康簪笏冗，世梗忠良議。丘壑非無人，松香有私志。", "三朝倚天劍，十萬浮雲騎。可使河曲清，群公信兒戲。", "滄溟用謙德，百谷走童稚。禦眾付深人，參籌須偉器。", "他年蓬蓽賤，願附鵷鸞翅。"]'),
('yuding-10','旅次銅山途中先寄溫州韓使君','陳陶','唐','御定全唐诗','yuding','','[]','亂山滄海曲，中有橫陽道。束馬過銅梁，苕華坐堪老。',120,'御定全唐詩/json/745.json','["亂山滄海曲，中有橫陽道。束馬過銅梁，苕華坐堪老。", "鳩鳴高崖裂，熊鬥深樹倒。絕壑無坤維，重林失蒼昊。", "躋攀寡儔侶，扶接念輿皂。俯仰栗嵌空，無因掇靈草。", "梯窮聞戍鼓，魂續賴丘禱。敞豁天地歸，縈紆村落好。", "悠悠思蔣徑，擾擾愧商皓。馳想永嘉侯，應傷此懷抱。"]'),
('yuding-11','種蘭','陳陶','唐','御定全唐诗','yuding','','[]','種蘭幽谷底，四遠聞馨香。春風長養深，枝葉趁人長。',228,'御定全唐詩/json/745.json','["種蘭幽谷底，四遠聞馨香。春風長養深，枝葉趁人長。", "智水潤其根，仁鋤護其芳。蒿藜不生地，惡鳥弓已藏。", "椒桂夾四隅，茅茨居中央。左鄰桃花塢，右接蓮子塘。", "一月熏手足，兩月熏衣裳。三月熏肌骨，四月熏心腸。", "幽人饑如何，采蘭充餱糧。幽人渴如何，醞蘭為酒漿。", "地無青苗租，白日如散王。不嘗仙人藥，端坐紅霞房。", "日夕望美人，佩花正煌煌。美人久不來，佩花徒生光。", "刈獲及葳蕤，無令見雪霜。清芬信神鬼，一葉豈可忘。", "舉頭愧青天，鼓腹詠時康。下有賢公卿，上有聖明王。", "無階答風雨，願獻蘭一筐。"]'),
('yuding-12','草木言','陳陶','唐','御定全唐诗','yuding','','[]','何生我蒼蒼，何育我黃黃。草木無知識，幸君同三光。',216,'御定全唐詩/json/745.json','["何生我蒼蒼，何育我黃黃。草木無知識，幸君同三光。", "始自受姓名，葳蕤立衣裳。山河既分麗，齊首乳青陽。", "甘辛各有榮，好醜不相防。常憂刀斧劫，竊慕仁壽鄉。", "願天雨無暴，願地風無狂。雨足因衰憊，風多因夭傷。", "在山不為桂，徒辱君高岡。在水不為蓮，徒占君深塘。", "勿輕培塿阜，或有奇棟樑。勿輕蒙朧澤，或有奇馨香。", "涓毫可粗差，朝菌壽為長。擁腫若無取，大椿命為傷。", "婆娑不材生，苒苒向秋荒。幸遭熏風日，有得皆簸揚。", "所愧雨露恩，願效幽微芳。希君頻采擇，勿使枯雪霜。"]'),
('yuding-13','題僧院紫竹','陳陶','唐','御定全唐诗','yuding','','[]','喜游蛟井寺，複見炎州竹。杳靄萬丈間，嘯風清獨速。',324,'御定全唐詩/json/745.json','["喜游蛟井寺，複見炎州竹。杳靄萬丈間，嘯風清獨速。", "江南正霜霰，吐秀弄顓頊。似瑞驚堅貞，如魔試金粟。", "筍非孝子泣，文異湘靈哭。金碧誰與鄰，蕭森自成族。", "新聞赤帝種，子落毛人穀。遠祖賜鷦鵬，遺芳遍南陸。", "對煙蘇麻醜，夾澗筼簹伏。美譽動丹青，瑰姿豔秦蜀。", "因緣鹿苑識，想像蛇丘劚。幾葉別黃茅，何年依白足。", "龍樹蟄一花，砌瑤掃雲屋。色靜曼仙花，名高給孤獨。", "青蔥太子樹，灑落觀音目。法雨每沾濡，玉毫時照燭。", "離居鸞節變，住冷金顏縮。豈念葛陂榮，幸無祖父辱。", "光搖水精串，影送蓮花軸。江鶩日相尋，野鶚時寄宿。", "幽香入茶灶，靜翠直棋局。肯羨垣上蒿，自多籬下菊。", "從來道生一，況伴龜藏六。棲托詎星回，檀欒已雲矗。", "霞杯傳縹葉，羽管吹紫玉。久絕釣竿歌，聊裁竹枝曲。", "愧生黃金地，千秋為師綠。"]'),
('yuding-14','早發始興','陳陶','唐','御定全唐诗','yuding','','[]','雲裏山已曙，舟中火初爇。綠浦待行橈，玄猿催落月。',48,'御定全唐詩/json/745.json','["雲裏山已曙，舟中火初爇。綠浦待行橈，玄猿催落月。", "沿流信多美，況複秋風發。掛席借前期，晨雞莫嘲哳。"]'),
('yuding-15','寄元孚道人','陳陶','唐','御定全唐诗','yuding','','[]','梵宇章句客，佩蘭三十年。長乘碧雲馬，時策翰林鞭。',120,'御定全唐詩/json/745.json','["梵宇章句客，佩蘭三十年。長乘碧雲馬，時策翰林鞭。", "曩事五嶽游，金衣曳祥煙。高攀桐君手，左倚鸑鷟肩。", "哭玉秋雨中，摘星春風前。橫輈截洪偃，憑幾見廣宣。", "爾來寤華胥，石壁孤雲眠。龍降始得偈，龜老方巢蓮。", "內殿無文僧，騶虞誰能牽。因之問楚水，吊屈幾潺湲。"]'),
('yuding-16','和西江李助副使早登開元寺閣','陳陶','唐','御定全唐诗','yuding','','[]','虛豁登寶閣，三休極層構。獨立天地間，煙雲滿襟袖。',192,'御定全唐詩/json/745.json','["虛豁登寶閣，三休極層構。獨立天地間，煙雲滿襟袖。", "鼇荒初落日，劍野呈綺繡。秋檻祝融微，陰軒九江湊。", "拂簷皇姑舍，錯落白榆秀。倚砌天竺祠，蛟龍蟠古甃。", "翛然觀六合，一指齊宇宙。書劍忽若□，青雲日方晝。", "南朝空蒼莽，楚澤稀耕耨。萬事溺頹波，一航安可涭。", "徒雲寄麟泣，六五終難就。資斧念餘生，湖光隱圭竇。", "早聞群黃鶴，飄舉此江岫。陵穀空靄然，人樵已雛鷇。", "燕宮豸冠客，憑覽發清奏。珠玉難嗣音，摐轅愧孤陋。"]'),
('yuding-17','將歸鐘陵留贈南海李尚書','陳陶','唐','御定全唐诗','yuding','','[]','楚國有田舍，炎州長夢歸。懷恩似秋燕，屢繞玉堂飛。',120,'御定全唐詩/json/745.json','["楚國有田舍，炎州長夢歸。懷恩似秋燕，屢繞玉堂飛。", "越酒豈不甘，海魚寧無肥。山裘醉歌舞，事與初心違。", "曄曄文昌公，英靈世間稀。長江浩無際，龍蜃皆歸依。", "賤子感一言，草茅發光輝。從來雞鳧質，得假鳳凰威。", "常欲討玄珠，青雲報巍巍。龍門竟多故，雙淚別旍旗。"]'),
('yuding-18','宿島徑夷山舍','陳陶','唐','御定全唐诗','yuding','','[]','百里遵島徑，蓬征信邅回。暝依漁樵宿，似過黃金台。',120,'御定全唐詩/json/745.json','["百里遵島徑，蓬征信邅回。暝依漁樵宿，似過黃金台。", "缺齧心未理，寥寥夜猿哀。山深石床冷，海近腥氣來。", "主人意不淺，屢獻流霞杯。對月撫長劍，愁襟紛莫開。", "九衢平如水，胡為涉崔嵬。一飯未遑飽，鵬圖信悠哉。", "山濤謔細君，吾豈厭蓬萊。明發又驅馬，客思一裴回。"]'),
('yuding-19','避世翁','陳陶','唐','御定全唐诗','yuding','','[]','海上一蓑笠，終年垂釣絲。滄洲有深意，冠蓋何由知。',132,'御定全唐詩/json/745.json','["海上一蓑笠，終年垂釣絲。滄洲有深意，冠蓋何由知。", "直鉤不營魚，蝸室無妻兒。渴飲寒泉水，饑餐紫朮芝。", "鶴發披兩肩，高懷如澄陂。嘗聞仙老言，雲是古鴟夷。", "石竇閟雷雨，金潭養蛟螭。乘槎上玉津，騎鹿遊峨嵋。", "以人為語默，與世為雄雌。茲焉乃磻溪，豹變應須時。", "自古隱淪客，無非王者師。"]'),
('yuding-20','冬夜吟','陳陶','唐','御定全唐诗','yuding','','[]','黑夜天寒愁散玉，東皇海上張仙燭。侯家歌舞按梨園，',64,'御定全唐詩/json/745.json','["黑夜天寒愁散玉，東皇海上張仙燭。侯家歌舞按梨園，", "散帙高編折桂枝，披紗密甃青雲地。霜白溪松轉斜蓋，", "輾轉城烏啼紫天，曈曚千騎衙樓前。"]'),
('yuding-21','西川座上聽金五雲唱歌','陳陶','唐','御定全唐诗','yuding','','[]','蜀王殿上華筵開，五雲歌從天上來。滿堂羅綺悄無語，',168,'御定全唐詩/json/745.json','["蜀王殿上華筵開，五雲歌從天上來。滿堂羅綺悄無語，", "白雲飄颻席上聞，貫珠歷歷聲中見。舊樣釵篦淺淡衣，", "曲終暫起更衣過，還向南行座頭坐。低眉欲語謝貴侯，", "中丞禦史不足比，水殿一聲愁殺人。武皇鑄鼎登真籙，", "卑官到官年未周，堂衡祿罷東西遊。蜀江水急駐不得，", "願持卮酒更唱歌，歌是伊州第三遍。唱著右丞征戍詞，", "五雲處處可憐許，明朝道向褒中去。須臾宴罷各東西，"]'),
('yuding-22','飛龍引','陳陶','唐','御定全唐诗','yuding','','[]','有熊之君好神仙，餐霞煉石三千年。一旦黃龍下九天，',120,'御定全唐詩/json/745.json','["有熊之君好神仙，餐霞煉石三千年。一旦黃龍下九天，", "紫鸞八九墮玉笙，金鏡空留照魑魅。羽幢褵褷銀漢秋，", "瑞風颯遝天光淺，瑤闕峨峨橫露苑。沆瀣樓頭紫鳳歌，", "散花童子鶴衣短，投壺姹女蛾眉長。彤庭侍宴瑤池席，", "仙流萬緘蟲篆春，三十六洞交風雲。千年小兆一蟬蛻，"]'),
('yuding-23','謫仙詞','陳陶','唐','御定全唐诗','yuding','','[]','牧龍丈人病高秋，群童擊節星漢愁。瑤台鳳輦不勝恨，',48,'御定全唐詩/json/745.json','["牧龍丈人病高秋，群童擊節星漢愁。瑤台鳳輦不勝恨，", "蜺旌失手遠於天，三島空雲對秋月。人間磊磊浮漚客，"]'),
('yuding-24','步虛引','陳陶','唐','御定全唐诗','yuding','','[]','小隱山人十洲客，莓苔為衣雙耳白。青編為我忽降書，',40,'御定全唐詩/json/745.json','["小隱山人十洲客，莓苔為衣雙耳白。青編為我忽降書，", "朝天半夜聞玉雞，星斗離離礙龍翼。"]'),
('yuding-25','獨搖手','陳陶','唐','御定全唐诗','yuding','','[]','漢宮新燕矜蛾眉，春台豔妝蓮一枝。迎春侍宴瑤華池，',64,'御定全唐詩/json/745.json','["漢宮新燕矜蛾眉，春台豔妝蓮一枝。迎春侍宴瑤華池，", "愁鴻連翾蠶曳絲，颯遝明珠掌中移。仙人龍鳳雲雨吹，", "仙蛾泣月清露垂，六宮燒燭愁風欷。"]'),
('yuding-26','空城雀','陳陶','唐','御定全唐诗','yuding','','[]','古城濛濛花覆水，昔日住人今住鬼。野雀荒台遺子孫，',48,'御定全唐詩/json/745.json','["古城濛濛花覆水，昔日住人今住鬼。野雀荒台遺子孫，", "近村紅栗香壓枝，嗷嗷黃口訴朝饑。生來未見鳳凰語，"]'),
('yuding-27','雞鳴曲','陳陶','唐','御定全唐诗','yuding','','[]','雞聲春曉上林中，一聲驚落蝦蟆宮。二聲喚破枕邊夢，',40,'御定全唐詩/json/745.json','["雞聲春曉上林中，一聲驚落蝦蟆宮。二聲喚破枕邊夢，", "愧君飲食長相呼，為君晝鳴下高樹。"]'),
('yuding-28','小笛弄','陳陶','唐','御定全唐诗','yuding','','[]','一尺玲瓏握中翠，仙娥月浦呼龍子。五夜流珠粲夢卿，',48,'御定全唐詩/json/745.json','["一尺玲瓏握中翠，仙娥月浦呼龍子。五夜流珠粲夢卿，", "蛇蠍愁聞骨髓寒，江山恨老眠秋霧。綺席鴛鴦冷朱翠，"]'),
('yuding-29','將進酒','陳陶','唐','御定全唐诗','yuding','','[]','金尊莫倚青春健，齷齪浮生如走電。琴瑟盤傾從世珠，',112,'御定全唐詩/json/745.json','["金尊莫倚青春健，齷齪浮生如走電。琴瑟盤傾從世珠，", "靈鼇柱骨半枯朽，驪龍德悔愁耕人。周孔蓍龜久淪沒，", "姮娥弄簫香雨收，江濱迸瑟魚龍愁。靈芝九折楚蓮醉，", "銀鴨金鵝言待誰，隋家嶽瀆皇家有。珊瑚座上淩香雲，", "文康調笑麒麟起，一曲飛龍壽天地。"]'),
('yuding-30','錢塘對酒麴','陳陶','唐','御定全唐诗','yuding','','[]','風天雁悲西陵愁，使君紅旗弄濤頭。東海神魚騎未得，',72,'御定全唐詩/json/745.json','["風天雁悲西陵愁，使君紅旗弄濤頭。東海神魚騎未得，", "南州彩鳳為君生，古獄愁蛇待恩澤。三清羽童來何遲，", "鴟夷公子休悲悄，六鼇如鏡天始老。尊前事去月團圓，"]'),
('yuding-31','巫山高','陳陶','唐','御定全唐诗','yuding','','[]','玉峰青雲十二枝，金母和雲賜瑤姬。花宮磊砢楚宮外，',48,'御定全唐詩/json/745.json','["玉峰青雲十二枝，金母和雲賜瑤姬。花宮磊砢楚宮外，", "青鸞不在懶吹簫，斑竹題詩寄江妾。飄颻絲散巴子天，"]'),
('yuding-32','贈別離','陳陶','唐','御定全唐诗','yuding','','[]','碧玉飛天星墜地，玉劍分風交合水。楊柳聽歌莫向隅，',72,'御定全唐詩/json/745.json','["碧玉飛天星墜地，玉劍分風交合水。楊柳聽歌莫向隅，", "蠻天列嶂儼相待，風官掃道迎游龍。天姥剪霞鋪曉空，", "山妖水魅騎旋風，魘夢齧魂黃瘴中。借君朗鑒入崆峒，"]'),
('yuding-33','關山月','陳陶','唐','御定全唐诗','yuding','','[]','昔年嫖姚護羌月，今照嫖姚雙鬢雪。青塚曾無尺寸歸，',48,'御定全唐詩/json/745.json','["昔年嫖姚護羌月，今照嫖姚雙鬢雪。青塚曾無尺寸歸，", "漢城應期破鏡時，胡塵萬里嬋娟隔。度磧沖雲朔風起，"]'),
('yuding-34','殿前生桂樹','陳陶','唐','御定全唐诗','yuding','','[]','仙娥玉宮秋夜明，桂枝拂檻參差瓊。香風下天漏丁丁，',40,'御定全唐詩/json/745.json','["仙娥玉宮秋夜明，桂枝拂檻參差瓊。香風下天漏丁丁，", "東海即為郎斟酌，綺疏長懸七星杓。"]'),
('yuding-35','古鏡篇','陳陶','唐','御定全唐诗','yuding','','[]','紫皇玉鏡蟾蜍字，墮地千年光不死。發匣身沈古井寒，',48,'御定全唐詩/json/745.json','["紫皇玉鏡蟾蜍字，墮地千年光不死。發匣身沈古井寒，", "野老曾耕太白星，神狐夜哭秋天片。下國青銅旋磨滅，"]'),
('yuding-36','自歸山','陳陶','唐','御定全唐诗','yuding','','[]','海岳南歸遠，天門北望深。暫為青瑣客，難換白雲心。',48,'御定全唐詩/json/745.json','["海岳南歸遠，天門北望深。暫為青瑣客，難換白雲心。", "富貴老閒事，猿猱思舊林。清平無樂志，尊酒有瑤琴。"]'),
('yuding-37','渡浙江','陳陶','唐','御定全唐诗','yuding','','[]','適越一輕艘，淩兢截鷺濤。曙光金海近，晴雪玉峰高。',48,'御定全唐詩/json/745.json','["適越一輕艘，淩兢截鷺濤。曙光金海近，晴雪玉峰高。", "靜寇思投筆，傷時欲釣鼇。壯心殊未展，登涉漫勞勞。"]'),
('yuding-38','清源途中旅思','陳陶','唐','御定全唐诗','yuding','','[]','古木閩州道，驅羸落照間。投村礙野水，問店隔荒山。',48,'御定全唐詩/json/745.json','["古木閩州道，驅羸落照間。投村礙野水，問店隔荒山。", "身事幾時了，蓬飄何日閑。看花滯南國，鄉月十灣環。"]'),
('yuding-39','南海送韋七使君赴象州任','陳陶','唐','御定全唐诗','yuding','','[]','一鶚韋公子，新恩頒郡符。島夷通荔浦，龍節過蒼梧。',48,'御定全唐詩/json/745.json','["一鶚韋公子，新恩頒郡符。島夷通荔浦，龍節過蒼梧。", "地理金城近，天涯玉樹孤。聖朝朱紱貴，從此展雄圖。"]'),
('yuding-40','送沈次魯南遊','陳陶','唐','御定全唐诗','yuding','','[]','高臺贈君別，滿握軒轅風。落日一揮手，金鵝雲雨空。',48,'御定全唐詩/json/745.json','["高臺贈君別，滿握軒轅風。落日一揮手，金鵝雲雨空。", "鼇洲石樑外，劍浦羅浮東。茲興不可接，翛翛煙際鴻。"]'),
('yuding-41','南海石門戍懷古','陳陶','唐','御定全唐诗','yuding','','[]','漢家征百越，落地喪貔貅。大野朱旗沒，長江赤血流。',48,'御定全唐詩/json/745.json','["漢家征百越，落地喪貔貅。大野朱旗沒，長江赤血流。", "鬼神尋覆族，宮廟變荒丘。唯有朝台月，千年照戍樓。"]'),
('yuding-42','賦得池塘生春草','陳陶','唐','御定全唐诗','yuding','','[]','謝公遺詠處，池水夾通津。古往人何在，年來草自春。',48,'御定全唐詩/json/745.json','["謝公遺詠處，池水夾通津。古往人何在，年來草自春。", "色宜波際綠，香異雨中新。今日青青意，空悲行路人。"]'),
('yuding-43','題居上人法華新院','陳陶','唐','御定全唐诗','yuding','','[]','浮名深般若，方寺設蓮華。鐘唄成僧國，湖山稱法家。',48,'御定全唐詩/json/745.json','["浮名深般若，方寺設蓮華。鐘唄成僧國，湖山稱法家。", "一塵多寶塔，千佛大牛車。能誘泥犁客，超然識聚沙。"]'),
('yuding-44','送秦煉師','陳陶','唐','御定全唐诗','yuding','','[]','紫府靜沉沉，松軒思別吟。水流甯有意，雲泛本無心。',48,'御定全唐詩/json/745.json','["紫府靜沉沉，松軒思別吟。水流甯有意，雲泛本無心。", "錦洞桃花遠，青山竹葉深。不因時賣藥，何路更相尋。"]'),
('yuding-45','哭寶月三藏大禪師','陳陶','唐','御定全唐诗','yuding','','[]','五峰習聖罷，幹竺化身歸。帝子傳真印，門人哭寶衣。',48,'御定全唐詩/json/745.json','["五峰習聖罷，幹竺化身歸。帝子傳真印，門人哭寶衣。", "一囊窮海沒，三藏故園稀。無複天花落，悲風滿鐵圍。"]'),
('yuding-46','湓城贈別','陳陶','唐','御定全唐诗','yuding','','[]','楚岸青楓樹，長隨送遠心。九江春水闊，三峽暮雲深。',48,'御定全唐詩/json/745.json','["楚岸青楓樹，長隨送遠心。九江春水闊，三峽暮雲深。", "氣調桓伊笛，才華蔡琰琴。迢迢嫁湘漢，誰不重黃金。"]'),
('yuding-47','贈別','陳陶','唐','御定全唐诗','yuding','','[]','海國一尺綺，冰壺萬縷絲。以君西攀桂，贈此金蓮枝。',48,'御定全唐詩/json/745.json','["海國一尺綺，冰壺萬縷絲。以君西攀桂，贈此金蓮枝。", "高鳥思茂林，窮魚樂洿池。平生握中寶，無使歲寒移。"]'),
('yuding-0','贈溫州韓使君','陳陶','唐','御定全唐诗','yuding','','[]','康樂風流五百年，永嘉鈴閣又登賢。嚴城鼓動魚驚海，',40,'御定全唐詩/json/746.json','["康樂風流五百年，永嘉鈴閣又登賢。嚴城鼓動魚驚海，", "今來誰似韓家貴，越絕麾幢雁影連。"]'),
('yuding-1','閒居寄太學盧景博士','陳陶','唐','御定全唐诗','yuding','','[]','無路青冥奪錦袍，恥隨黃雀住蓬蒿。碧雲夢後山風起，',40,'御定全唐詩/json/746.json','["無路青冥奪錦袍，恥隨黃雀住蓬蒿。碧雲夢後山風起，", "閑來長得留侯癖，羅列楂梨校六韜。"]'),
('yuding-2','贈漳州張怡使君','陳陶','唐','御定全唐诗','yuding','','[]','舊德徐方天下聞，當年熊軾繼清芬。井田異政光蠻竹，',40,'御定全唐詩/json/746.json','["舊德徐方天下聞，當年熊軾繼清芬。井田異政光蠻竹，", "幾時征拜征西越，學著縵胡從使君。"]'),
('yuding-3','贈容南韋中丞','陳陶','唐','御定全唐诗','yuding','','[]','普寧都護軍威重，九驛梯航壓要津。十二銅魚尊畫戟，',40,'御定全唐詩/json/746.json','["普寧都護軍威重，九驛梯航壓要津。十二銅魚尊畫戟，", "不獨來蘇發歌詠，天涯半是泣珠人。"]'),
('yuding-4','投贈福建路羅中丞','陳陶','唐','御定全唐诗','yuding','','[]','越豔新謠不厭聽，樓船高臥靜南溟。未聞建水窺龍劍，',40,'御定全唐詩/json/746.json','["越豔新謠不厭聽，樓船高臥靜南溟。未聞建水窺龍劍，", "皇恩幾日西歸去，玉樹扶疏正滿庭。"]'),
('yuding-5','贈江南李偕副使','陳陶','唐','御定全唐诗','yuding','','[]','世祿三朝壓鳳池，杜陵公子漢庭知。雷封始賀堂溪劍，',40,'御定全唐詩/json/746.json','["世祿三朝壓鳳池，杜陵公子漢庭知。雷封始賀堂溪劍，", "從軍莫厭千場醉，即是金鑾寵命時。"]'),
('yuding-6','賀容府韋中丞大府賢兄新除黔南經略','陳陶','唐','御定全唐诗','yuding','','[]','蓬瀛簪笏舊聯行，紫極差池降寵章。列國山河分雁字，',40,'御定全唐詩/json/746.json','["蓬瀛簪笏舊聯行，紫極差池降寵章。列國山河分雁字，", "烽戍悠悠限巴越，佇聽歌詠兩甘棠。"]'),
('yuding-7','和容南韋中丞題瑞亭白燕、白鼠、六眸龜、嘉蓮','陳陶','唐','御定全唐诗','yuding','','[]','伏波恩信動南夷，交趾喧傳四瑞詩。燕鼠孕靈褒上德，',40,'御定全唐詩/json/746.json','["伏波恩信動南夷，交趾喧傳四瑞詩。燕鼠孕靈褒上德，", "盡寫流傳在軒檻，嘉祥從此百年知。"]'),
('yuding-8','題豫章西山香城寺','陳陶','唐','御定全唐诗','yuding','','[]','十地嚴宮禮竺皇，栴檀樓閣半天香。祇園樹老梵聲小，',40,'御定全唐詩/json/746.json','["十地嚴宮禮竺皇，栴檀樓閣半天香。祇園樹老梵聲小，", "何年七七金人降，金錫珠壇滿上方。"]'),
('yuding-9','送江西周尚書赴滑台','陳陶','唐','御定全唐诗','yuding','','[]','楚謠襦袴整三千，喉舌新恩下九天。天角雄都分節鉞，',40,'御定全唐詩/json/746.json','["楚謠襦袴整三千，喉舌新恩下九天。天角雄都分節鉞，", "多病無因酬一顧，鄢陵千騎去翩翩。"]'),
('yuding-10','閩中送任畹端公還京','陳陶','唐','御定全唐诗','yuding','','[]','燕台下榻玉為人，月桂曾輸次第春。幾日酬恩坐炎瘴，',40,'御定全唐詩/json/746.json','["燕台下榻玉為人，月桂曾輸次第春。幾日酬恩坐炎瘴，", "多少嘉謨奏風俗，鬥牛孤劍在平津。"]'),
('yuding-11','豫章江樓望西山有懷','陳陶','唐','御定全唐诗','yuding','','[]','水護星壇列太虛，煙霓十八上仙居。時人未識遼東鶴，',40,'御定全唐詩/json/746.json','["水護星壇列太虛，煙霓十八上仙居。時人未識遼東鶴，", "桃花穀口春深淺，欲訪先生赤鯉魚。"]'),
('yuding-12','經徐稚墓','陳陶','唐','御定全唐诗','yuding','','[]','郟鄏妖興炎漢衰，先生南國臥明夷。鳳凰屢降玄纁禮，',40,'御定全唐詩/json/746.json','["郟鄏妖興炎漢衰，先生南國臥明夷。鳳凰屢降玄纁禮，", "千年壟樹何人哭，寂寞蒼苔內史碑。"]'),
('yuding-13','鐘陵道中作','陳陶','唐','御定全唐诗','yuding','','[]','原隰經霜蕙草黃，塞鴻消息怨流芳。秋山落照見麋鹿，',40,'御定全唐詩/json/746.json','["原隰經霜蕙草黃，塞鴻消息怨流芳。秋山落照見麋鹿，", "曾逢齧缺話東海，長憶蕭家青玉床。"]'),
('yuding-14','旅泊塗江','陳陶','唐','御定全唐诗','yuding','','[]','煙雨南江一葉微，松潭漁父夜相依。斷沙雁起金精出，',40,'御定全唐詩/json/746.json','["煙雨南江一葉微，松潭漁父夜相依。斷沙雁起金精出，", "無因得似滄溟叟，始憶離巢已倦飛。"]'),
('yuding-15','上建溪','陳陶','唐','御定全唐诗','yuding','','[]','崆峒一派瀉蒼煙，長揖丹丘逐水仙。雲樹杳冥通上界，',40,'御定全唐詩/json/746.json','["崆峒一派瀉蒼煙，長揖丹丘逐水仙。雲樹杳冥通上界，", "已判猿催鬢先白，幾重灘瀨在秋天。"]'),
('yuding-16','冬日暮旅泊廬陵','陳陶','唐','御定全唐诗','yuding','','[]','螺亭倚棹哭飄蓬，白浪欺船自向東。楚國蕙蘭增悵望，',40,'御定全唐詩/json/746.json','["螺亭倚棹哭飄蓬，白浪欺船自向東。楚國蕙蘭增悵望，", "棄置侯鯖任羈束，不勞龜瓦問窮通。"]'),
('yuding-17','登寶曆寺閣','陳陶','唐','御定全唐诗','yuding','','[]','金碧高層世界空，憑蜺長嘯八蠻風。橫軒水壯蛟龍府，',40,'御定全唐詩/json/746.json','["金碧高層世界空，憑蜺長嘯八蠻風。橫軒水壯蛟龍府，", "不堪懷古勞悲笑，安得鵬摶顥氣中。"]'),
('yuding-18','寄兵部任畹郎中','陳陶','唐','御定全唐诗','yuding','','[]','常思劍浦越清塵，豆蔻花紅十二春。昆玉已成廊廟器，',40,'御定全唐詩/json/746.json','["常思劍浦越清塵，豆蔻花紅十二春。昆玉已成廊廟器，", "好向昌時薦遺逸，莫教千古吊靈均。"]'),
('yuding-19','贈江南從事張侍郎','陳陶','唐','御定全唐诗','yuding','','[]','平南門館鳳凰毛，二十華軒立最高。幾處談天致雲雨，',40,'御定全唐詩/json/746.json','["平南門館鳳凰毛，二十華軒立最高。幾處談天致雲雨，", "江徼無虞才不展，銜杯終日詠離騷。"]'),
('yuding-20','劍池','陳陶','唐','御定全唐诗','yuding','','[]','秦帝南巡厭火精，蒼黃埋劍故豐城。霸圖繚戾金龍蟄，',40,'御定全唐詩/json/746.json','["秦帝南巡厭火精，蒼黃埋劍故豐城。霸圖繚戾金龍蟄，", "永懷惆悵中宵作，不見春雷發匣聲。"]'),
('yuding-21','洛城見賀自真飛升','陳陶','唐','御定全唐诗','yuding','','[]','子晉鸞飛古洛川，金桃再熟賀郎仙。三清樂奏嵩丘下，',40,'御定全唐詩/json/746.json','["子晉鸞飛古洛川，金桃再熟賀郎仙。三清樂奏嵩丘下，", "誰能白晝相悲泣，太極光陰億萬年。"]'),
('yuding-22','謫仙吟贈趙道士','陳陶','唐','御定全唐诗','yuding','','[]','汗漫東游黃鶴雛，縉雲仙子住清都。三元麟鳳推高座，',40,'御定全唐詩/json/746.json','["汗漫東游黃鶴雛，縉雲仙子住清都。三元麟鳳推高座，", "若為失意居蓬島，鼇足塵飛桑樹枯。"]'),
('yuding-23','夜別溫商梓州','陳陶','唐','御定全唐诗','yuding','','[]','鳳凰城裏花時別，玄武江邊月下逢。客舍莫辭先買酒，',40,'御定全唐詩/json/746.json','["鳳凰城裏花時別，玄武江邊月下逢。客舍莫辭先買酒，", "明日又行西蜀去，不堪天際遠山重。"]'),
('yuding-24','題贈高閑上人','陳陶','唐','御定全唐诗','yuding','','[]','簷蔔花間客，軒轅席上珍。筆江秋菡萏，僧國瑞麒麟。',192,'御定全唐詩/json/746.json','["簷蔔花間客，軒轅席上珍。筆江秋菡萏，僧國瑞麒麟。", "內殿初招隱，曹溪得後塵。龍蛇驚粉署，花雨對金輪。", "白馬方依漢，朱星又入秦。劇談淩鑿齒，清論倒波旬。", "拂石先天古，降龍舊國春。珠還合浦老，龍去玉州貧。", "鴛鷺輸黃絹，場壇繞白蘋。鼎湖閑入夢，金閣靜通神。", "海氣成方丈，山泉落淨巾。獮猴深愛月，鷗鳥不猜人。", "拂嶽蕭蕭竹，垂空澹澹津。漢珠難覓對，荊璞本來真。", "伊傅多聯壁，劉雷競買鄰。江邊有國寶，時為劚星辰。"]'),
('yuding-25','哭王贊府','陳陶','唐','御定全唐诗','yuding','','[]','白水流今古，青山送死生。驅馳三楚掾，倏忽一空名。',144,'御定全唐詩/json/746.json','["白水流今古，青山送死生。驅馳三楚掾，倏忽一空名。", "金玉埋皋壤，芝蘭哭弟兄。龍頭孤後進，鵬翅失前程。", "愁變風雲色，悲連鼓角聲。落星辭聖代，寒夢閉佳城。", "伊昔來江邑，從容副國英。德逾棲棘美，公亞飲冰清。", "大廈亡孤直，群儒憶老成。白駒悲裏巷，梁木慟簪纓。", "隴遂添新草，珠還滿舊籝。蒼蒼難可問，原上晚煙橫。"]'),
('yuding-26','聖帝擊壤歌四十聲','陳陶','唐','御定全唐诗','yuding','','[]','百六承堯緒，艱難土運昌。太虛橫彗孛，中野鬥豺狼。',481,'御定全唐詩/json/746.json','["百六承堯緒，艱難土運昌。太虛橫彗孛，中野鬥豺狼。", "帝曰更吾嗣，時哉憶聖唐。英星垂將校，神岳誕忠良。", "煉石醫元氣，屠鼇正昊蒼。掃原鋪一德，驅祲立三光。", "大道重蘇息，真風再發揚。芟夷逾舊跡，神聖掩前王。", "郊酒酣寥廓，鴻恩受渺茫。地圖龜負出，天誥鳳銜將。", "雜貢來山峙，群夷入雁行。紫泥搜海岱，鴻筆富岩廊。", "鷹象敷宸極，寰瀛作瑞坊。泥丸封八表，金鏡照中央。", "構殿基麟趾，開藩表鳳翔。鑾輿親稼穡，朱幌務蠶桑。", "戎羯輸天馬，靈仙侍玉房。宮儀水搜甲，門衛綠沈槍。", "陶鑄超三古，車書混萬方。時巡望虞舜，搜狩法殷湯。", "化合謳謠滿，年豐鬼蜮藏。政源歸牧馬，公法付神羊。", "寶鼎無靈應，金甌肯破傷。封山昭茂績，祠執答嘉祥。", "在昔宮闈僭，仍罹羿浞殃。牝雞何譈ca，猘犬漫劻勷。", "苗禱三靈怒，桓偷九族亡。鯨鯢尋掛網，魑魅旋投荒。", "松柏霜逾翠，芝蘭露更香。聖謨流祚遠，仙系發源長。", "島嶼征徭薄，漪瀾泛稻涼。鳧魚饜餐啖，荷薜足衣裳。", "寤寐華胥國，嬉遊太素鄉。鷹鸇飛接翼，忠孝住連牆。", "有叟能調鼎，無媒隱釣璜。乾坤資識量，江海入文章。", "野鶴思蓬闕，山麋憶廟堂。泥沙空淬礪，星斗屢低昂。", "曆草何因見，衢尊豈暫忘。終隨嘉橘賦，霄漢謁羲皇。"]'),
('yuding-27','續古二十九首','陳陶','唐','御定全唐诗','yuding','','[]','大堯登寶位，麟鳳煥宸居。海曲沾恩澤，還生比目魚。',576,'御定全唐詩/json/746.json','["大堯登寶位，麟鳳煥宸居。海曲沾恩澤，還生比目魚。", "生值揖遜曆，長歌東南春。釣鼇年三十，未見天子巡。", "軒轅承化日，群鳳戲池台。大朴衰喪後，仲尼生不來。", "大道歸孟門，蕭蘭日爭長。想得巢居時，碧江應無浪。", "矻矻蓬捨下，慕君麒麟閣。笑殺王子喬，寥天乘白鶴。", "杳杳巫峽雲，悠悠漢江水。愁殺幾少年，春風相憶地。", "吳洲采芳客，桂棹木蘭船。日晚欲有寄，裴回春風前。", "仙家風景晏，浮世年華速。邂逅漢武時，蟠桃海東熟。", "南國珊瑚樹，好裁天馬鞭。魚龍不解語，海曲空蟬娟。", "周穆恣遊幸，橫天驅八龍。甯知泰山下，日日望登封。", "秦國饒羅網，中原絕麟鳳。萬乘巡海回，鮑魚空相送。", "秦家無廟略，遮虜續長城。萬姓隴頭死，中原荊棘生。", "秦作東海橋，中州鬼辛苦。縱得跨蓬萊，群仙亦飛去。", "隋煬棄中國，龍舟巡海涯。春風廣陵苑，不見秦宮花。", "範子相句踐，滅吳成大勳。雖然五湖去，終愧磻溪雲。", "麟鳳識翔蟄，聖賢明卷舒。哀哉嵇叔夜，智不及鶢鶋。", "戰地三尺骨，將軍一身貴。自古若吊冤，落花少於淚。", "楚國千里旱，土龍日已多。九穀竟枯死，好雲閑嵯峨。", "漢家三殿色，恩澤若飄風。今日黃金屋，明朝長信宮。", "南園杏花發，北渚梅花落。吳女妒西施，容華日消鑠。", "山雞理毛羽，自言勝烏鳶。一朝逢鸑鷟，羞死南海邊。", "秦家卷衣貴，本是倡家子。金殿一承恩，貂蟬滿鄉里。", "魏宮薛家女，秀色傾三殿。武帝鼎湖歸，一身似秋扇。", "嬋娟越機裏，織得雙棲鳳。慰此殊世花，金梭忽停弄。"]'),
('yuding-28','永嘉贈別','陳陶','唐','御定全唐诗','yuding','','[]','芳草溫陽客，歸心浙水西。臨風青桂楫，幾日白蘋溪。',24,'御定全唐詩/json/746.json','["芳草溫陽客，歸心浙水西。臨風青桂楫，幾日白蘋溪。"]'),
('yuding-29','有所思','陳陶','唐','御定全唐诗','yuding','','[]','欲唱玄雲曲，知音複誰是。采掇情未來，臨池畫春水。',24,'御定全唐詩/json/746.json','["欲唱玄雲曲，知音複誰是。采掇情未來，臨池畫春水。"]'),
('yuding-30','吳苑思','陳陶','唐','御定全唐诗','yuding','','[]','今人地藏古人骨，古人花為今人發。',32,'御定全唐詩/json/746.json','["今人地藏古人骨，古人花為今人發。", "江南何處葬西施，謝豹空聞采香月。"]'),
('yuding-31','古意','陳陶','唐','御定全唐诗','yuding','','[]','麻姑井邊一株杏，花開不如古時紅。',32,'御定全唐詩/json/746.json','["麻姑井邊一株杏，花開不如古時紅。", "西鄰蔡家十歲女，年年二月賣東風。"]'),
('yuding-32','朝元引四首','陳陶','唐','御定全唐诗','yuding','','[]','帝燭熒煌下九天，蓬萊宮曉玉爐煙。',128,'御定全唐詩/json/746.json','["帝燭熒煌下九天，蓬萊宮曉玉爐煙。", "無央鸞鳳隨金母，來賀熏風一萬年。", "正殿雲開露冕旒，下方珠翠壓鼇頭。", "天雞唱罷南山曉，春色光輝十二樓。", "萬宇靈祥擁帝居，東華元老薦屠蘇。", "龍池遙望非煙拜，五色曈曨在玉壺。", "寶祚河宮一向清，龜魚天篆益分明。", "近臣誰獻登封草，五嶽齊呼萬歲聲。"]'),
('yuding-33','宿天竺寺','陳陶','唐','御定全唐诗','yuding','','[]','一宵何期此靈境，五粒松香金地冷。',32,'御定全唐詩/json/746.json','["一宵何期此靈境，五粒松香金地冷。", "西僧示我高隱心，月在中峰葛洪井。"]'),
('yuding-34','賦得古蓮塘','陳陶','唐','御定全唐诗','yuding','','[]','闔閭宮娃能採蓮，明珠作佩龍為船。',32,'御定全唐詩/json/746.json','["闔閭宮娃能採蓮，明珠作佩龍為船。", "三千巧笑不復見，江頭廢苑花年年。"]'),
('yuding-35','雙桂詠','陳陶','唐','御定全唐诗','yuding','','[]','青冥結根易傾倒，沃洲山中雙樹好。',32,'御定全唐詩/json/746.json','["青冥結根易傾倒，沃洲山中雙樹好。", "琉璃宮殿無斧聲，石上蕭蕭伴僧老。"]'),
('yuding-36','夏日懷天臺','陳陶','唐','御定全唐诗','yuding','','[]','竹齋睡餘柘漿清，麟鳳誘我勞此生。',32,'御定全唐詩/json/746.json','["竹齋睡餘柘漿清，麟鳳誘我勞此生。", "勿憶天臺掩書坐，澗雲起盡紅崢嶸。"]'),
('yuding-37','臨風歎','陳陶','唐','御定全唐诗','yuding','','[]','芙蓉樓中飲君酒，驪駒結言春楊柳。',32,'御定全唐詩/json/746.json','["芙蓉樓中飲君酒，驪駒結言春楊柳。", "豫章花落不見歸，一望東風堪白首。"]'),
('yuding-38','春日行','陳陶','唐','御定全唐诗','yuding','','[]','鶗鴂初鳴洲渚滿，龍蛇洗鱗春水暖。',32,'御定全唐詩/json/746.json','["鶗鴂初鳴洲渚滿，龍蛇洗鱗春水暖。", "病多欲問山寺僧，湖上人傳石橋斷。"]'),
('yuding-39','春歸去','陳陶','唐','御定全唐诗','yuding','','[]','九十春光在何處，古人今人留不住。',32,'御定全唐詩/json/746.json','["九十春光在何處，古人今人留不住。", "年年白眼向黔婁，唯放蠐螬飛上樹。"]'),
('yuding-40','蜀葵詠','陳陶','唐','御定全唐诗','yuding','','[]','綠衣宛地紅倡倡，熏風似舞諸女郎。',32,'御定全唐詩/json/746.json','["綠衣宛地紅倡倡，熏風似舞諸女郎。", "南鄰蕩子婦無賴，錦機春夜成文章。"]'),
('yuding-41','南昌道中','陳陶','唐','御定全唐诗','yuding','','[]','古道夤緣蔓黃葛，桓伊塚西春水闊。',32,'御定全唐詩/json/746.json','["古道夤緣蔓黃葛，桓伊塚西春水闊。", "村翁莫倚橫浦罾，一半魚蝦屬鵜獺。"]'),
('yuding-42','子規思','陳陶','唐','御定全唐诗','yuding','','[]','春山杜鵑來幾日，夜啼南家複北家。',32,'御定全唐詩/json/746.json','["春山杜鵑來幾日，夜啼南家複北家。", "野人聽此坐惆悵，恐畏踏落東園花。"]'),
('yuding-43','吳興秋思二首','陳陶','唐','御定全唐诗','yuding','','[]','不是苕溪厭看月，天涯有程雲樹涼。',64,'御定全唐詩/json/746.json','["不是苕溪厭看月，天涯有程雲樹涼。", "何意汀洲剩風雨，白蘋今日似瀟湘。", "日夕鯤魚夢南國，苕陽水高迷渡頭。", "故山秋風憶歸去，白雲又被王孫留。"]'),
('yuding-44','閩川夢歸','陳陶','唐','御定全唐诗','yuding','','[]','千里潺湲建溪路，夢魂一夕西歸去。',32,'御定全唐詩/json/746.json','["千里潺湲建溪路，夢魂一夕西歸去。", "龍舼欲上巴獸灘，越王金雞報天曙。"]'),
('yuding-45','竹十一首','陳陶','唐','御定全唐诗','yuding','','[]','不厭東溪綠玉君，天壇雙鳳有時聞。',352,'御定全唐詩/json/746.json','["不厭東溪綠玉君，天壇雙鳳有時聞。", "一峰曉似朝仙處，青節森森倚絳雲。", "萬枝朝露學瀟湘，杳靄孤亭白石涼。", "誰道乖龍不得雨，春雷入地馬鞭狂。", "嘯入新篁一裏行，萬竿如甕鎖龍泓。", "驚巢翡翠無尋處，閑倚雲根刻姓名。", "青嵐帚亞思吾祖，綠潤偏多憶蔡邕。", "長聽南園風雨夜，恐生鱗甲盡為龍。", "迸玉閑抽上釣磯，翠苗番次脫霞衣。", "山童泥乞青驄馬，騎過春泉掣手飛。", "須題內史琅玕塢，幾醉山陽瑟瑟村。", "剩養萬莖將掃俗，莫教凡鳥鬧雲門。", "一溪雲母間靈花，似到封侯逸士家。", "誰識雌雄九成律，子喬丹井在深涯。", "燕燕雛時紫米香，野溪羞色過東牆。", "諸兒莫拗成蹊筍，從結高籠養鳳凰。", "一節呼龍萬里秋，數莖垂海六鼇愁。", "更須瀑布峰前種，雲裏闌幹過子猷。", "丘壑誰堪話碧鮮，靜尋春譜認嬋娟。", "會當小殺青瑤簡，圖寫龜魚把上天。", "玄圃千春閉玉叢，湛陽一祖碧雲空。", "不須騷屑愁江島，今日南枝在國風。"]'),
('yuding-46','鐘陵秋夜','陳陶','唐','御定全唐诗','yuding','','[]','洪崖嶺上秋月明，野客枕底章江清。',32,'御定全唐詩/json/746.json','["洪崖嶺上秋月明，野客枕底章江清。", "蓬壺宮闕不可夢，一一入樓歸雁聲。"]'),
('yuding-47','江上逢故人','陳陶','唐','御定全唐诗','yuding','','[]','十年蓬轉金陵道，長哭青雲身不早。',32,'御定全唐詩/json/746.json','["十年蓬轉金陵道，長哭青雲身不早。", "故鄉逢盡白頭人，清江顏色何曾老。"]'),
('yuding-48','水調詞十首','陳陶','唐','御定全唐诗','yuding','','[]','黠虜迢迢未肯和，五陵年少重橫戈。',320,'御定全唐詩/json/746.json','["黠虜迢迢未肯和，五陵年少重橫戈。", "誰家不結空閨恨，玉箸闌幹妾最多。", "羽管慵調怨別離，西園新月伴愁眉。", "容華不分隨年去，獨有妝樓明鏡知。", "憶餞良人玉塞行，梨花三見換啼鶯。", "邊場豈得勝閨閣，莫逞雕弓過一生。", "惆悵江南早雁飛，年年辛苦寄寒衣。", "征人豈不思鄉國，只是皇恩未放歸。", "水閣蓮開燕引雛，朝朝攀折望金吾。", "聞道磧西春不到，花時還憶故園無。", "自從清野戍遼東，舞袖香銷羅幌空。", "幾度長安發梅柳，節旄零落不成功。", "長夜孤眠倦錦衾，秦樓霜月苦邊心。", "征衣一倍裝綿厚，猶慮交河雪凍深。", "瀚海長征古別離，華山歸馬是何時。", "仍聞萬乘尊猶屈，裝束千嬌嫁郅支。", "沙塞依稀落日邊，寒宵魂夢怯山川。", "離居漸覺笙歌懶，君逐嫖姚已十年。", "萬里輪台音信稀，傳聞移帳護金微。", "會須麟閣留蹤跡，不斬天驕莫議歸。"]'),
('yuding-49','送謝山人歸江夏','陳陶','唐','御定全唐诗','yuding','','[]','黃鶴春風二千里，山人佳期碧江水。',32,'御定全唐詩/json/746.json','["黃鶴春風二千里，山人佳期碧江水。", "攜琴一醉楊柳堤，日暮龍沙白雲起。"]'),
('yuding-50','閒居雜興五首','陳陶','唐','御定全唐诗','yuding','','[]','虞韶九奏音猶在，只是巴童自棄遺。',160,'御定全唐詩/json/746.json','["虞韶九奏音猶在，只是巴童自棄遺。", "閑臥清秋憶師曠，好風搖動古松枝。", "一顧成周力有餘，白雲閑釣五溪魚。", "中原莫道無麟鳳，自是皇家結網疏。", "長愛真人王子喬，五松山月伴吹簫。", "從他浮世悲生死，獨駕蒼鱗入九霄。", "越裏娃童錦作襦，豔歌聲壓郢中姝。", "無人說向張京兆，一曲江南十斛珠。", "雲堆西望賊連營，分閫何當舉義兵。", "莫道羔裘無壯節，古來成事盡書生。"]'),
('yuding-51','泉州刺桐花詠兼呈趙使君','陳陶','唐','御定全唐诗','yuding','','[]','仿佛三株植世間，風光滿地赤城閑。',192,'御定全唐詩/json/746.json','["仿佛三株植世間，風光滿地赤城閑。", "無因秉燭看奇樹，長伴劉公醉玉山。", "海曲春深滿郡霞，越人多種刺桐花。", "可憐虎竹西樓色，錦帳三千阿母家。", "石氏金園無此豔，南都舊賦乏靈材。", "只因赤帝宮中樹，丹鳳新銜出世來。", "猗猗小豔夾通衢，晴日熏風笑越姝。", "只是紅芳移不得，刺桐屏障滿中都。", "不勝攀折悵年華，紅樹南看見海涯。", "故國春風歸去盡，何人堪寄一枝花。", "赤帝常聞海上游，三千幢蓋擁炎州。", "今來樹似離宮色，紅翠斜欹十二樓。"]'),
('yuding-52','投贈福建桂常侍二首','陳陶','唐','御定全唐诗','yuding','','[]','後來台席更何人，都護朝天拜近臣。',64,'御定全唐詩/json/746.json','["後來台席更何人，都護朝天拜近臣。", "長笑當時漢卿士，等閒恩澤畫麒麟。", "匝地歌鐘鎮海隅，城池鞅掌舊名都。", "不知珠履三千外，更許侯嬴寄食無。"]'),
('yuding-53','隴西行四首','陳陶','唐','御定全唐诗','yuding','','[]','漢主東封報太平，無人金闕議邊兵。',128,'御定全唐詩/json/746.json','["漢主東封報太平，無人金闕議邊兵。", "縱饒奪得林胡塞，磧地桑麻種不生。", "誓掃匈奴不顧身，五千貂錦喪胡塵。", "可憐無定河邊骨，猶是春閨夢裏人。", "隴戍三看塞草青，樓煩新替護羌兵。", "同來死者傷離別，一夜孤魂哭舊營。", "黠虜生擒未有涯，黑山營陣識龍蛇。", "自從貴主和親後，一半胡風似漢家。"]'),
('yuding-54','答蓮花妓','陳陶','唐','御定全唐诗','yuding','','[]','近來詩思清于水，老去風情薄似雲。',32,'御定全唐詩/json/746.json','["近來詩思清于水，老去風情薄似雲。", "已向升天得門戶，錦衾深愧卓文君。"]'),
('yuding-55','鏡道中吹簫','陳陶','唐','御定全唐诗','yuding','','[]','金欄白的善篸zC，雙鳳夜伴江南棲。',33,'御定全唐詩/json/746.json','["金欄白的善篸zC，雙鳳夜伴江南棲。", "十洲人聽玉樓曉，空向千山桃杏枝。"]'),
('yuding-56','贈野老','陳陶','唐','御定全唐诗','yuding','','[]','何年種芝白雲裏，人傳先生老萊子。',32,'御定全唐詩/json/746.json','["何年種芝白雲裏，人傳先生老萊子。", "消磨世上名利心，澹若岩間一流水。"]'),
('yuding-57','酬元亨上人','陳陶','唐','御定全唐诗','yuding','','[]','一衲淨居雲夢合，秋來詩思祝融高。',32,'御定全唐詩/json/746.json','["一衲淨居雲夢合，秋來詩思祝融高。", "何因知我津涯闊，遠寄東溟六巨鼇。"]'),
('yuding-58','題徐稚湖亭','陳陶','唐','御定全唐诗','yuding','','[]','伏龍山橫洲渚地，人如白蘋自生死。',32,'御定全唐詩/json/746.json','["伏龍山橫洲渚地，人如白蘋自生死。", "洪崖成道二千年，唯有徐君播青史。"]'),
('yuding-59','鄱陽秋夕','陳陶','唐','御定全唐诗','yuding','','[]','憶昔鄱陽旅遊日，曾聽南家爭擣衣。',32,'御定全唐詩/json/746.json','["憶昔鄱陽旅遊日，曾聽南家爭擣衣。", "今夜重開舊砧杵，當時還見雁南飛。"]'),
('yuding-60','飛龍引','陳陶','唐','御定全唐诗','yuding','','[]','長洲茂苑朝夕池，映日含風結細漪。坐當伏檻紅蓮披，',40,'御定全唐詩/json/746.json','["長洲茂苑朝夕池，映日含風結細漪。坐當伏檻紅蓮披，", "苕苕翡翠但相逐，桂樹鴛鴦恒並宿。"]'),
('yuding-61','句','陳陶','唐','御定全唐诗','yuding','','[]','蟬聲將月短，草色與秋長。',124,'御定全唐詩/json/746.json','["蟬聲將月短，草色與秋長。", "比屋歌黃竹，何人撼白榆。", "好看如鏡夜，莫笑似弓時。", "江湖水清淺，不足掉鯨尾。", "飲水狼子瘦，思日鷓鴣寒。", "一鼎雄雌金液火，十年寒暑鹿麑裘。", "寄語東流任斑鬢，向隅終守鐵梭飛。", "乾坤見了文章懶，龍虎成來印綬疏。", "近來世上無徐庶，誰向桑麻識臥龍。"]'),
('yuding-0','春日作','李中','唐','御定全唐诗','yuding','','[]','和氣來無象，物情還暗新。乾坤一夕雨，草木萬方春。',48,'御定全唐詩/json/747.json','["和氣來無象，物情還暗新。乾坤一夕雨，草木萬方春。", "染水煙光媚，催花鳥語頻。高臺曠望處，歌詠屬詩人。"]'),
('yuding-1','寒江暮泊寄左偃','李中','唐','御定全唐诗','yuding','','[]','維舟蘆荻岸，離恨若為寬。煙火人家遠，汀洲暮雨寒。',48,'御定全唐詩/json/747.json','["維舟蘆荻岸，離恨若為寬。煙火人家遠，汀洲暮雨寒。", "天涯孤夢去，篷底一燈殘。不是憑騷雅，相思寫亦難。"]'),
('yuding-2','喜春雨有寄','李中','唐','御定全唐诗','yuding','','[]','青春終日雨，公子莫思晴。任阻西園會，且觀南畝耕。',48,'御定全唐詩/json/747.json','["青春終日雨，公子莫思晴。任阻西園會，且觀南畝耕。", "最憐滋壟麥，不恨濕林鶯。父老應相賀，豐年兆已成。"]'),
('yuding-3','魏夫人壇','李中','唐','御定全唐诗','yuding','','[]','仙壇遺跡在，苔合落花明。絳節何年返，白雲終日生。',48,'御定全唐詩/json/747.json','["仙壇遺跡在，苔合落花明。絳節何年返，白雲終日生。", "旋新芳草色，依舊偃松聲。欲問希夷事，音塵隔上清。"]'),
('yuding-4','訪洞神宮邵道者不遇','李中','唐','御定全唐诗','yuding','','[]','閑來仙觀問希夷，雲滿星壇水滿池。',32,'御定全唐詩/json/747.json','["閑來仙觀問希夷，雲滿星壇水滿池。", "羽客不知何處去，洞前花落立多時。"]'),
('yuding-5','寄贈致仕沈彬郎中','李中','唐','御定全唐诗','yuding','','[]','鶴氅換朝服，逍遙雲水鄉。有時乘一葉，載酒入三湘。',48,'御定全唐詩/json/747.json','["鶴氅換朝服，逍遙雲水鄉。有時乘一葉，載酒入三湘。", "塵夢年來息，詩魔老亦狂。蓴羹與鱸膾，秋興最宜長。"]'),
('yuding-6','贈別','李中','唐','御定全唐诗','yuding','','[]','行杯酌罷歌聲歇，不覺前汀月又生。',32,'御定全唐詩/json/747.json','["行杯酌罷歌聲歇，不覺前汀月又生。", "自是離人魂易斷，落花芳草本無情。"]'),
('yuding-7','送劉恭遊廬山兼寄令上人','李中','唐','御定全唐诗','yuding','','[]','松桂煙霞蔽梵宮，詩流閑去訪支公。',32,'御定全唐詩/json/747.json','["松桂煙霞蔽梵宮，詩流閑去訪支公。", "石堂磬斷相逢夜，五老月生溪影空。"]'),
('yuding-8','宿廬山白雲峰重道者院','李中','唐','御定全唐诗','yuding','','[]','絕頂松堂喜暫遊，一宵玄論接浮丘。雲開碧落星河近，',40,'御定全唐詩/json/747.json','["絕頂松堂喜暫遊，一宵玄論接浮丘。雲開碧落星河近，", "他時書劍酬恩了，願逐鸞車看十洲。"]'),
('yuding-9','海上從事秋日書懷','李中','唐','御定全唐诗','yuding','','[]','悠悠旅宦役塵埃，舊業那堪信未回。千里夢隨殘月斷，',40,'御定全唐詩/json/747.json','["悠悠旅宦役塵埃，舊業那堪信未回。千里夢隨殘月斷，", "唯有搜吟遣懷抱，涼風時複上高臺。"]'),
('yuding-10','訪蔡文慶處士留題','李中','唐','御定全唐诗','yuding','','[]','幽人棲息處，一到滌塵心。蘚色花陰闊，棋聲竹徑深。',48,'御定全唐詩/json/747.json','["幽人棲息處，一到滌塵心。蘚色花陰闊，棋聲竹徑深。", "籬根眠野鹿，池面戲江禽。多謝相留宿，開樽拂素琴。"]'),
('yuding-11','寄廬岳鑒上人','李中','唐','御定全唐诗','yuding','','[]','嶽寺棲瓶錫，常人親亦難。病披青衲重，晚剃白髭寒。',48,'御定全唐詩/json/747.json','["嶽寺棲瓶錫，常人親亦難。病披青衲重，晚剃白髭寒。", "烘壁茶煙暗，填溝木葉幹。昔年皆禮謁，頻到碧雲端。"]'),
('yuding-12','書小齋壁','李中','唐','御定全唐诗','yuding','','[]','其誰肯見尋，冷淡少知音。塵土侵閑榻，煙波隔故林。',48,'御定全唐詩/json/747.json','["其誰肯見尋，冷淡少知音。塵土侵閑榻，煙波隔故林。", "竹風醒晚醉，窗月伴秋吟。道在唯求己，明時豈陸沈。"]'),
('yuding-13','懷王道者','李中','唐','御定全唐诗','yuding','','[]','閑思王道者，逸格世難群。何處眠青嶂，從來愛白雲。',48,'御定全唐詩/json/747.json','["閑思王道者，逸格世難群。何處眠青嶂，從來愛白雲。", "酒沽應獨醉，藥熟許誰分。正作趨名計，如何得見君。"]'),
('yuding-14','桃花','李中','唐','御定全唐诗','yuding','','[]','只應紅杏是知音，灼灼偏宜間竹陰。幾樹半開金穀曉，',40,'御定全唐詩/json/747.json','["只應紅杏是知音，灼灼偏宜間竹陰。幾樹半開金穀曉，", "誰步宋牆明月下，好香和影上衣襟。"]'),
('yuding-15','思舊遊有感','李中','唐','御定全唐诗','yuding','','[]','長憶銜杯處，酕醄尚未闌。江南正煙雨，樓上恰春寒。',48,'御定全唐詩/json/747.json','["長憶銜杯處，酕醄尚未闌。江南正煙雨，樓上恰春寒。", "好樹藏鶯密，平蕪徹野寬。如今無處覓，音信隔波瀾。"]'),
('yuding-16','依韻和智謙上人送李相公赴昭武軍','李中','唐','御定全唐诗','yuding','','[]','暫別廟堂上，雄藩去豁情。秋風生雁渚，晚霧濕龍旌。',48,'御定全唐詩/json/747.json','["暫別廟堂上，雄藩去豁情。秋風生雁渚，晚霧濕龍旌。", "吟裏過侯服，夢中歸帝城。下車軍庶樂，千里月華清。"]'),
('yuding-17','姑蘇懷古','李中','唐','御定全唐诗','yuding','','[]','闔閭興霸日，繁盛複風流。歌舞一場夢，煙波千古愁。',96,'御定全唐詩/json/747.json','["闔閭興霸日，繁盛複風流。歌舞一場夢，煙波千古愁。", "樵人歸野徑，漁笛起扁舟。觸目牽傷感，將行又駐留。", "蘇台蹤跡在，曠望向江濱。往事誰堪問，連空草自春。", "花疑西子臉，濤想伍胥神。吟盡情難盡，斜陽照路塵。"]'),
('yuding-18','贈史虛白','李中','唐','御定全唐诗','yuding','','[]','致主嘉謀尚未伸，慨然深志與誰論。喚回古意琴開匣，',40,'御定全唐詩/json/747.json','["致主嘉謀尚未伸，慨然深志與誰論。喚回古意琴開匣，", "九重夢卜時終在，莫向深雲獨閉門。"]'),
('yuding-19','贈蒯亮處士','李中','唐','御定全唐诗','yuding','','[]','著得新書義更幽，負琴何處不遨遊。玄宮寄宿月華冷，',40,'御定全唐詩/json/747.json','["著得新書義更幽，負琴何處不遨遊。玄宮寄宿月華冷，", "吾君側席求賢切，未可懸瓢枕碧流。"]'),
('yuding-20','春夕偶作','李中','唐','御定全唐诗','yuding','','[]','早是春愁觸目生，那堪春夕酒初醒。',32,'御定全唐詩/json/747.json','["早是春愁觸目生，那堪春夕酒初醒。", "貫珠聲罷人歸去，半落桃花月在庭。"]'),
('yuding-21','子規','李中','唐','御定全唐诗','yuding','','[]','暮春滴血一聲聲，花落年年不忍聽。',32,'御定全唐詩/json/747.json','["暮春滴血一聲聲，花落年年不忍聽。", "帶月莫啼江畔樹，酒醒遊子在離亭。"]'),
('yuding-22','書王秀才壁','李中','唐','御定全唐诗','yuding','','[]','茅舍何寥落，門庭長綠蕪。貧來賣書劍，病起憶江湖。',48,'御定全唐詩/json/747.json','["茅舍何寥落，門庭長綠蕪。貧來賣書劍，病起憶江湖。", "對枕暮山碧，伴吟涼月孤。前賢多晚達，莫歎有霜須。"]'),
('yuding-23','春日途中作','李中','唐','御定全唐诗','yuding','','[]','幹祿趨名者，迢迢別故林。春風短亭路，芳草異鄉心。',48,'御定全唐詩/json/747.json','["幹祿趨名者，迢迢別故林。春風短亭路，芳草異鄉心。", "雨過江山出，鶯啼村落深。未知將雅道，何處謝知音。"]'),
('yuding-24','依韻和蠡澤王去微秀才見寄','李中','唐','御定全唐诗','yuding','','[]','咫尺風騷客，難諧面繼酬。相思對煙雨，一雁下汀洲。',48,'御定全唐詩/json/747.json','["咫尺風騷客，難諧面繼酬。相思對煙雨，一雁下汀洲。", "花影誰家塢，笛聲何處樓。支筇朗吟罷，搔首獨遲留。"]'),
('yuding-25','送孫孔二秀才游廬山','李中','唐','御定全唐诗','yuding','','[]','廬山多勝景，偏稱二君遊。松徑蒼苔合，花陰碧澗流。',48,'御定全唐詩/json/747.json','["廬山多勝景，偏稱二君遊。松徑蒼苔合，花陰碧澗流。", "傾壺同坐石，搜句共登樓。莫學天臺客，逢山即駐留。"]'),
('yuding-26','春日野望懷故人','李中','唐','御定全唐诗','yuding','','[]','野外登臨望，蒼蒼煙景昏。暖風醫病草，甘雨洗荒村。',48,'御定全唐詩/json/747.json','["野外登臨望，蒼蒼煙景昏。暖風醫病草，甘雨洗荒村。", "雲散天邊野，潮回島上痕。故人不可見，倚杖役吟魂。"]'),
('yuding-27','游玄真觀','李中','唐','御定全唐诗','yuding','','[]','閑吟游古觀，靜慮相神仙。上景非難度，陰功不易全。',48,'御定全唐詩/json/747.json','["閑吟游古觀，靜慮相神仙。上景非難度，陰功不易全。", "醮壇松作蓋，丹井蘚成錢。浩浩紅塵裏，誰來叩自然。"]'),
('yuding-28','劍客','李中','唐','御定全唐诗','yuding','','[]','恩酬期必報，豈是輒輕生。神劍沖霄去，誰為平不平。',24,'御定全唐詩/json/747.json','["恩酬期必報，豈是輒輕生。神劍沖霄去，誰為平不平。"]'),
('yuding-29','鶴','李中','唐','御定全唐诗','yuding','','[]','警露精神異，沖天羽翼新。千年一歸日，誰識令威身。',24,'御定全唐詩/json/747.json','["警露精神異，沖天羽翼新。千年一歸日，誰識令威身。"]'),
('yuding-30','送致仕沈彬郎中游茅山','李中','唐','御定全唐诗','yuding','','[]','掛卻朝冠披鶴氅，羽人相伴恣遨遊。忽因風月思茅嶺，',40,'御定全唐詩/json/747.json','["掛卻朝冠披鶴氅，羽人相伴恣遨遊。忽因風月思茅嶺，", "華陽洞府年光永，莫向仙鄉擬駐留。"]'),
('yuding-31','題廬山東寺遠大師影堂','李中','唐','御定全唐诗','yuding','','[]','遠公遺跡在東林，往事名存動苦吟。杉檜已依靈塔老，',40,'御定全唐詩/json/747.json','["遠公遺跡在東林，往事名存動苦吟。杉檜已依靈塔老，", "十八賢人消息斷，蓮池千載月沉沉。"]'),
('yuding-32','庭葦','李中','唐','御定全唐诗','yuding','','[]','品格清於竹，詩家景最幽。從栽向池沼，長似在汀洲。',72,'御定全唐詩/json/747.json','["品格清於竹，詩家景最幽。從栽向池沼，長似在汀洲。", "玩好招溪叟，棲堪待野鷗。影疏當夕照，花亂正深秋。", "韻細堪清耳，根牢好系舟。故溪高岸上，冷淡有誰遊。"]'),
('yuding-33','寄左偃','李中','唐','御定全唐诗','yuding','','[]','每病風騷路，荒涼人莫遊。惟君還似我，成癖未能休。',48,'御定全唐詩/json/747.json','["每病風騷路，荒涼人莫遊。惟君還似我，成癖未能休。", "舍寐緣孤月，忘形為九秋。垂名如不朽，那恨雪生頭。"]'),
('yuding-34','宿山店書懷寄東林令圖上人','李中','唐','御定全唐诗','yuding','','[]','一宿山前店，旅情安可窮。猿聲鄉夢後，月影竹窗中。',48,'御定全唐詩/json/747.json','["一宿山前店，旅情安可窮。猿聲鄉夢後，月影竹窗中。", "南楚征途闊，東吳舊業空。虎溪蓮社客，應笑此飄蓬。"]'),
('yuding-35','途中聞子規','李中','唐','御定全唐诗','yuding','','[]','春殘杜宇愁，越客思悠悠。雨歇孤村裏，花飛遠水頭。',48,'御定全唐詩/json/747.json','["春殘杜宇愁，越客思悠悠。雨歇孤村裏，花飛遠水頭。", "微風聲漸咽，高樹血應流。因此頻回首，家山隔幾州。"]'),
('yuding-36','春日書懷','李中','唐','御定全唐诗','yuding','','[]','千峰雪盡鳥聲春，日永孤吟野水濱。',32,'御定全唐詩/json/747.json','["千峰雪盡鳥聲春，日永孤吟野水濱。", "霄漢路岐升未得，花時空拂滿衣塵。"]'),
('yuding-37','所思代人','李中','唐','御定全唐诗','yuding','','[]','巫峽雲深湘水遙，更無消息夢空勞。',32,'御定全唐詩/json/747.json','["巫峽雲深湘水遙，更無消息夢空勞。", "夢回深夜不成寐，起立閒庭花月高。"]'),
('yuding-38','春晚過明氏閒居','李中','唐','御定全唐诗','yuding','','[]','寥寥陋巷獨扃門，自樂清虛不厭貧。數局棋中消永日，',40,'御定全唐詩/json/747.json','["寥寥陋巷獨扃門，自樂清虛不厭貧。數局棋中消永日，", "羨爾朗吟無外事，滄洲何必去垂綸。"]'),
('yuding-39','贈重安寂道者','李中','唐','御定全唐诗','yuding','','[]','寒松肌骨鶴心情，混俗陶陶隱姓名。白髮只聞悲短景，',40,'御定全唐詩/json/747.json','["寒松肌骨鶴心情，混俗陶陶隱姓名。白髮只聞悲短景，", "每許相親應計分，琴餘常見話蓬瀛。"]'),
('yuding-40','江邊吟','李中','唐','御定全唐诗','yuding','','[]','風暖汀洲吟興生，遠山如畫雨新晴。殘陽影裏水東注，',40,'御定全唐詩/json/747.json','["風暖汀洲吟興生，遠山如畫雨新晴。殘陽影裏水東注，", "盤桓漁舍忘歸去，雲靜高空月又明。"]'),
('yuding-41','獻張義方常侍','李中','唐','御定全唐诗','yuding','','[]','雄飛看是逼岩廊，逸思常聞不暫忘。公署靜眠思水石，',40,'御定全唐詩/json/747.json','["雄飛看是逼岩廊，逸思常聞不暫忘。公署靜眠思水石，", "乘興有時招羽客，橫琴移月啟茅堂。"]'),
('yuding-42','贈永真杜翱少府','李中','唐','御定全唐诗','yuding','','[]','藍袍竹簡佐琴堂，縣僻人稀覺日長。愛靜不嫌官況冷，',40,'御定全唐詩/json/747.json','["藍袍竹簡佐琴堂，縣僻人稀覺日長。愛靜不嫌官況冷，", "騫翥會應霄漢去，漁竿休更戀滄浪。"]'),
('yuding-43','獻中書韓舍人','李中','唐','御定全唐诗','yuding','','[]','丹墀朝退後，靜院即冥搜。盡日捲簾坐，前峰當檻秋。',48,'御定全唐詩/json/747.json','["丹墀朝退後，靜院即冥搜。盡日捲簾坐，前峰當檻秋。", "烹茶留野客，展畫看滄洲。見說東林夜，尋常秉燭遊。"]'),
('yuding-44','獻徐舍人','李中','唐','御定全唐诗','yuding','','[]','清名喧四海，何止並南金。奧學群英伏，多才萬乘欽。',144,'御定全唐詩/json/747.json','["清名喧四海，何止並南金。奧學群英伏，多才萬乘欽。", "秩參金殿峻，步曆紫微深。顧問承中旨，絲綸演帝心。", "褒雄饒義路，賈馬避詞林。下直無他事，開門對遠岑。", "軒窗來晚吹，池沼歇秋霖。蘚點生棋石，茶煙過竹陰。", "希夷元已達，躁競豈能侵。羽客閑陪飲，詩人伴靜吟。", "自慚為滯物，多幸辱虛襟。此日重遭遇，心期出陸沈。"]'),
('yuding-45','新秋有感','李中','唐','御定全唐诗','yuding','','[]','門巷涼秋至，高梧一葉驚。漸添衾簟爽，頓覺夢魂清。',96,'御定全唐詩/json/747.json','["門巷涼秋至，高梧一葉驚。漸添衾簟爽，頓覺夢魂清。", "暗促蓮開豔，乍催蟬發聲。雨降炎氣減，竹引冷煙生。", "戍客添歸思，行人怯遠程。未逢征雁下，漸聽夜砧鳴。", "張翰思鱸興，班姬詠扇情。音塵兩難問，蛩砌月空明。"]'),
('yuding-46','秋雨','李中','唐','御定全唐诗','yuding','','[]','竟日散如絲，吟看半掩扉。秋聲在梧葉，潤氣逼書幃。',96,'御定全唐詩/json/747.json','["竟日散如絲，吟看半掩扉。秋聲在梧葉，潤氣逼書幃。", "曲澗泉承去，危簷燕帶歸。寒蛩悲旅壁，亂蘚滑漁磯。", "爽欲除幽簟，涼須換熟衣。疏篷誰夢斷，荒徑獨遊稀。", "偏稱江湖景，不妨鷗鷺飛。最憐為瑞處，南畝稻苗肥。"]'),
('yuding-47','寄廬山白大師','李中','唐','御定全唐诗','yuding','','[]','長憶尋師處，東林寓泊時。一秋同看月，無夜不論詩。',72,'御定全唐詩/json/747.json','["長憶尋師處，東林寓泊時。一秋同看月，無夜不論詩。", "泉美茶香異，堂深磬韻遲。鹿馴眠蘚徑，猿苦叫霜枝。", "別後音塵隔，年來鬢髮衰。趨名方汲汲，未果再遊期。"]'),
('yuding-48','訪龍光智謙上人','李中','唐','御定全唐诗','yuding','','[]','忽起尋師興，穿雲不覺勞。相留看山雪，盡日論風騷。',48,'御定全唐詩/json/747.json','["忽起尋師興，穿雲不覺勞。相留看山雪，盡日論風騷。", "竹影搖禪榻，茶煙上毳袍。夢魂曾去否，舊國阻波濤。"]'),
('yuding-49','送仙客','李中','唐','御定全唐诗','yuding','','[]','危言危行是男兒，倚伏相牽豈足悲。',32,'御定全唐詩/json/747.json','["危言危行是男兒，倚伏相牽豈足悲。", "莫向汀洲時獨立，悠悠斜日照江蘺。"]'),
('yuding-50','祀風師迎神曲','李中','唐','御定全唐诗','yuding','','[]','太皞禦氣，勾芒肇功。蒼龍青旗，爰候祥風。',40,'御定全唐詩/json/747.json','["太皞禦氣，勾芒肇功。蒼龍青旗，爰候祥風。", "律以和應，□以感通。鼎俎修蚃，時惟禮崇。"]'),
('yuding-51','柳二首','李中','唐','御定全唐诗','yuding','','[]','春來無樹不青青，似共東風別有情。',64,'御定全唐詩/json/747.json','["春來無樹不青青，似共東風別有情。", "閑憶舊居湓水畔，數枝煙雨屬啼鶯。", "最愛青青水國中，莫愁門外間花紅。", "纖纖無力勝春色，撼起啼鶯恨晚風。"]'),
('yuding-52','送廬阜僧歸山陽','李中','唐','御定全唐诗','yuding','','[]','山陽舊社終經夢，容易言歸不可留。瓶貯瀑泉離五老，',40,'御定全唐詩/json/747.json','["山陽舊社終經夢，容易言歸不可留。瓶貯瀑泉離五老，", "遙想枚皋宅邊寺，不知涼月共誰遊。"]'),
('yuding-53','投所知','李中','唐','御定全唐诗','yuding','','[]','孤琴塵翳劍慵磨，自顧泥蟠欲奈何。千里交親消息斷，',40,'御定全唐詩/json/747.json','["孤琴塵翳劍慵磨，自顧泥蟠欲奈何。千里交親消息斷，", "唯賴明公憐道在，敢攜蓑笠釣煙波。"]'),
('yuding-54','寄左偃','李中','唐','御定全唐诗','yuding','','[]','蕭條陋巷綠苔侵，何事君心似我心。貧戶懶開元愛靜，',40,'御定全唐詩/json/747.json','["蕭條陋巷綠苔侵，何事君心似我心。貧戶懶開元愛靜，", "況是清朝重文物，無愁當路少知音。"]'),
('yuding-55','遊北山洞神宮','李中','唐','御定全唐诗','yuding','','[]','悶見塵中光景促，仙鄉來禮紫陽君。人居淡寂應難老，',40,'御定全唐詩/json/747.json','["悶見塵中光景促，仙鄉來禮紫陽君。人居淡寂應難老，", "羨師向此朝星斗，一炷清香午夜焚。"]'),
('yuding-56','思簡寂觀舊遊寄重道者','李中','唐','御定全唐诗','yuding','','[]','閑憶當年遊物外，羽人曾許駐仙鄉。溪頭烘藥煙霞暖，',40,'御定全唐詩/json/747.json','["閑憶當年遊物外，羽人曾許駐仙鄉。溪頭烘藥煙霞暖，", "俗緣未斷歸浮世，空望林泉意欲狂。"]'),
('yuding-57','雲','李中','唐','御定全唐诗','yuding','','[]','悠悠離洞壑，冉冉上天津。捧日終為異，從龍自有因。',120,'御定全唐詩/json/747.json','["悠悠離洞壑，冉冉上天津。捧日終為異，從龍自有因。", "高行四海雨，暖拂萬山春。靜與霞相近，閑將鶴最親。", "帝鄉歸莫問，楚殿夢曾頻。白向封中起，碧從詩裏新。", "冷容橫釣浦，輕縷絆蟾輪。不滯濃還淡，無心卷複伸。", "非煙聊擬議，幹呂在逡巡。會作五般色，為祥覆紫宸。"]'),
('yuding-58','徐司徒池亭','李中','唐','御定全唐诗','yuding','','[]','亭榭跨池塘，泓澄入座涼。扶疏皆竹柏，冷淡似瀟湘。',96,'御定全唐詩/json/747.json','["亭榭跨池塘，泓澄入座涼。扶疏皆竹柏，冷淡似瀟湘。", "萍嫩鋪波面，苔深鎖岸傍。朝回游不厭，僧到賞難忘。", "最稱收殘雨，偏宜帶夕陽。吟堪期謝脁，醉好命嵇康。", "奢侈心難及，清虛趣最長。月明垂釣興，何必憶滄浪。"]'),
('yuding-59','賦得江邊草','李中','唐','御定全唐诗','yuding','','[]','岸春芳草合，幾處思纏綿。向暮江蘺雨，初晴杜若煙。',48,'御定全唐詩/json/747.json','["岸春芳草合，幾處思纏綿。向暮江蘺雨，初晴杜若煙。", "靜宜幽鷺立，遠稱碧波連。送別王孫處，萋萋南浦邊。"]'),
('yuding-60','江行夜泊','李中','唐','御定全唐诗','yuding','','[]','扁舟倦行役，寂寂宿江幹。半夜風雷過，一天星斗寒。',48,'御定全唐詩/json/747.json','["扁舟倦行役，寂寂宿江幹。半夜風雷過，一天星斗寒。", "潮平沙觜沒，霜苦雁聲殘。漁父何疏逸，扣舷歌未闌。"]'),
('yuding-61','訪山叟留題','李中','唐','御定全唐诗','yuding','','[]','策杖尋幽客，相攜入竹扃。野雲生晚砌，病鶴立秋庭。',48,'御定全唐詩/json/747.json','["策杖尋幽客，相攜入竹扃。野雲生晚砌，病鶴立秋庭。", "茶美睡心爽，琴清塵慮醒。輪蹄應少到，門巷草青青。"]'),
('yuding-62','江行晚泊寄湓城知友','李中','唐','御定全唐诗','yuding','','[]','孤舟相憶久，何處倍關情。野渡帆初落，秋風蟬一聲。',48,'御定全唐詩/json/747.json','["孤舟相憶久，何處倍關情。野渡帆初落，秋風蟬一聲。", "江浮殘照闊，雲散亂山橫。漸去湓城遠，那堪新月生。"]'),
('yuding-63','秋夕書懷','李中','唐','御定全唐诗','yuding','','[]','功名未立誠非晚，骨肉分飛又入秋。',32,'御定全唐詩/json/747.json','["功名未立誠非晚，骨肉分飛又入秋。", "枕上不堪殘夢斷，壁蛩窗月夜悠悠。"]'),
('yuding-64','感興','李中','唐','御定全唐诗','yuding','','[]','漁休渭水興周日，龍起南陽相蜀時。',32,'御定全唐詩/json/747.json','["漁休渭水興周日，龍起南陽相蜀時。", "不遇文王與先主，經天才業擬何為。"]'),
('yuding-65','舟中望九華山','李中','唐','御定全唐诗','yuding','','[]','排空蒼翠異，輟棹看崔嵬。一面雨初歇，九峰雲正開。',72,'御定全唐詩/json/747.json','["排空蒼翠異，輟棹看崔嵬。一面雨初歇，九峰雲正開。", "當時思水石，便欲上樓臺。隱去心難遂，吟餘首懶回。", "僧休傳紫閣，屏歇寫天臺。中有忘機者，逍遙不可陪。"]'),
('yuding-66','漁父','李中','唐','御定全唐诗','yuding','','[]','煙冷暮江濱，高歌散誕身。移舟過蓼岸，待月正絲綸。',48,'御定全唐詩/json/747.json','["煙冷暮江濱，高歌散誕身。移舟過蓼岸，待月正絲綸。", "亦與樵翁約，同遊酒市春。白頭雲水上，不識獨醒人。"]'),
('yuding-67','贈上都紫極宮劉日新先生','李中','唐','御定全唐诗','yuding','','[]','道德吾君重，含貞本去華。因知煉神骨，何必在煙霞。',48,'御定全唐詩/json/747.json','["道德吾君重，含貞本去華。因知煉神骨，何必在煙霞。", "棋散庭花落，詩成海月斜。瀛洲舊仙侶，應許寄丹砂。"]'),
('yuding-68','勉同志','李中','唐','御定全唐诗','yuding','','[]','讀書與磨劍，旦夕但忘疲。儻若功名立，那愁變化遲。',48,'御定全唐詩/json/747.json','["讀書與磨劍，旦夕但忘疲。儻若功名立，那愁變化遲。", "塵從侵硯席，苔任滿庭墀。明代搜揚切，升沈莫問龜。"]'),
('yuding-69','寄劉鈞秀才','李中','唐','御定全唐诗','yuding','','[]','掩戶當春晝，知君志在詩。閑花半落處，幽客未來時。',48,'御定全唐詩/json/747.json','["掩戶當春晝，知君志在詩。閑花半落處，幽客未來時。", "野鳥穿莎徑，江雲過竹籬。會須明月夜，與子水邊期。"]'),
('yuding-70','離亭前思有寄','李中','唐','御定全唐诗','yuding','','[]','酒醒江亭客，纏綿恨別離。笙歌筵散後，風月夜長時。',48,'御定全唐詩/json/747.json','["酒醒江亭客，纏綿恨別離。笙歌筵散後，風月夜長時。", "耿耿看燈暗，悠悠結夢遲。若無騷雅分，何計達相思。"]'),
('yuding-71','贈上都先業大師','李中','唐','御定全唐诗','yuding','','[]','懶向人前著紫衣，虛堂閑倚一條藜。雖承雨露居龍闕，',40,'御定全唐詩/json/747.json','["懶向人前著紫衣，虛堂閑倚一條藜。雖承雨露居龍闕，", "有時乘興尋師去，煮茗同吟到日西。"]'),
('yuding-72','思九江舊居三首','李中','唐','御定全唐诗','yuding','','[]','結茅曾在碧江隈，多病貧身養拙來。雨歇汀洲垂釣去，',120,'御定全唐詩/json/747.json','["結茅曾在碧江隈，多病貧身養拙來。雨歇汀洲垂釣去，", "遊宦等閒千里隔，空餘魂夢到漁台。", "門前煙水似瀟湘，放曠優遊興味長。虛閣靜眠聽遠浪，", "犬吠疏籬明月上，鄰翁攜酒到茅堂。", "無機終日狎沙鷗，得意高吟景且幽。檻底江流偏稱月，", "別後再遊心未遂，設屏惟畫白蘋洲。"]'),
('yuding-73','贈東林白大師','李中','唐','御定全唐诗','yuding','','[]','虎溪久駐靈蹤，禪外詩魔尚濃。卷宿吟銷永日，',35,'御定全唐詩/json/747.json','["虎溪久駐靈蹤，禪外詩魔尚濃。卷宿吟銷永日，", "自說年來老病，出門漸覺疏慵。"]'),
('yuding-74','春曉','李中','唐','御定全唐诗','yuding','','[]','殘燭猶存月尚明，幾家幃幌夢魂驚。',32,'御定全唐詩/json/747.json','["殘燭猶存月尚明，幾家幃幌夢魂驚。", "星河漸沒行人動，歷歷林梢百舌聲。"]'),
('yuding-75','聽鄭羽人彈琴','李中','唐','御定全唐诗','yuding','','[]','仙鄉景已清，仙子啟琴聲。秋月空山寂，淳風一夜生。',48,'御定全唐詩/json/747.json','["仙鄉景已清，仙子啟琴聲。秋月空山寂，淳風一夜生。", "莎間蟲罷響，松頂鶴初驚。因感浮華世，誰憐太古情。"]'),
('yuding-76','秋夕書事寄友人','李中','唐','御定全唐诗','yuding','','[]','信斷關河遠，相思秋夜深。砌蛩聲咽咽，簷月影沉沉。',48,'御定全唐詩/json/747.json','["信斷關河遠，相思秋夜深。砌蛩聲咽咽，簷月影沉沉。", "未遂青雲志，那堪素發侵。吟餘成不寐，徹曙四鄰砧。"]'),
('yuding-77','秋日途中','李中','唐','御定全唐诗','yuding','','[]','竹林已蕭索，客思正如讎。舊業吳江外，新蟬楚驛頭。',48,'御定全唐詩/json/747.json','["竹林已蕭索，客思正如讎。舊業吳江外，新蟬楚驛頭。", "遙天疏雨過，列岫亂雲收。今夕誰家宿，孤吟月色秋。"]'),
('yuding-78','秋夜吟寄左偃','李中','唐','御定全唐诗','yuding','','[]','與君詩興素來狂，況入清秋夜景長。溪閣共誰看好月，',40,'御定全唐詩/json/747.json','["與君詩興素來狂，況入清秋夜景長。溪閣共誰看好月，", "會約垂名繼前哲，任他玄發盡如霜。"]'),
('yuding-79','竹','李中','唐','御定全唐诗','yuding','','[]','森森移得自山莊，植向空庭野興長。便有好風來枕簟，',40,'御定全唐詩/json/747.json','["森森移得自山莊，植向空庭野興長。便有好風來枕簟，", "閑約羽人同賞處，安排棋局就清涼。"]'),
('yuding-80','懷廬岳舊游寄劉鈞因感鑒上人','李中','唐','御定全唐诗','yuding','','[]','昔年廬嶽閒遊日，乘興因尋物外僧。寄宿愛聽松葉雨，',40,'御定全唐詩/json/747.json','["昔年廬嶽閒遊日，乘興因尋物外僧。寄宿愛聽松葉雨，", "一念支公安可見，影堂何處暮雲凝。"]'),
('yuding-81','依韻酬智謙上人見寄','李中','唐','御定全唐诗','yuding','','[]','性拙才非逸，同心友亦稀。風昏秋病眼，霜濕夜吟衣。',48,'御定全唐詩/json/747.json','["性拙才非逸，同心友亦稀。風昏秋病眼，霜濕夜吟衣。", "鶯穀期猶負，蘭陔養不違。吾師惠佳句，勝得楚金歸。"]'),
('yuding-82','落花','李中','唐','御定全唐诗','yuding','','[]','年年三月暮，無計惜殘紅。酷恨西園雨，生憎南陌風。',48,'御定全唐詩/json/747.json','["年年三月暮，無計惜殘紅。酷恨西園雨，生憎南陌風。", "片隨流水遠，色逐斷霞空。悵望叢林下，悠悠飲興窮。"]'),
('yuding-83','題柳','李中','唐','御定全唐诗','yuding','','[]','折向離亭畔，春光滿手生。群花豈無豔，柔質自多情。',48,'御定全唐詩/json/747.json','["折向離亭畔，春光滿手生。群花豈無豔，柔質自多情。", "夾岸籠溪月，兼風撼野鶯。隋堤三月暮，飛絮想縱橫。"]'),
('yuding-84','贈謙明上人','李中','唐','御定全唐诗','yuding','','[]','雖寄上都眠竹寺，逸情終憶白雲端。閑登鐘阜林泉晚，',40,'御定全唐詩/json/747.json','["雖寄上都眠竹寺，逸情終憶白雲端。閑登鐘阜林泉晚，", "常聞秋夕多無寐，月在高臺獨憑欄。"]'),
('yuding-85','書蔡隱士壁','李中','唐','御定全唐诗','yuding','','[]','病後霜髭出，衡門寂寞中。蠹侵書帙損，塵覆酒樽空。',48,'御定全唐詩/json/747.json','["病後霜髭出，衡門寂寞中。蠹侵書帙損，塵覆酒樽空。", "池暗菰蒲雨，徑香蘭蕙風。幽閒已得趣，不見蔔窮通。"]'),
('yuding-86','贈鐘尊師游茅山','李中','唐','御定全唐诗','yuding','','[]','筇杖擔琴背俗塵，路尋茅嶺有誰群。仙翁物外應相遇，',40,'御定全唐詩/json/747.json','["筇杖擔琴背俗塵，路尋茅嶺有誰群。仙翁物外應相遇，", "伊予亦有朝修志，異日遨遊願見君。"]'),
('yuding-87','訪徐長史留題水閣','李中','唐','御定全唐诗','yuding','','[]','君家池閣靜，一到且淹留。坐聽蒹葭雨，如看島嶼秋。',48,'御定全唐詩/json/747.json','["君家池閣靜，一到且淹留。坐聽蒹葭雨，如看島嶼秋。", "杯盤深有興，吟笑迥忘憂。更愛幽奇處，雙雙下野鷗。"]'),
('yuding-88','夕陽','李中','唐','御定全唐诗','yuding','','[]','影未沈山水面紅，遙天雨過促征鴻。',32,'御定全唐詩/json/747.json','["影未沈山水面紅，遙天雨過促征鴻。", "魂銷舉子不回首，閑照槐花驛路中。"]'),
('yuding-89','鸂鶒','李中','唐','御定全唐诗','yuding','','[]','流品是鴛鴦，翻飛雲水鄉。風高離極浦，煙暝下方塘。',48,'御定全唐詩/json/747.json','["流品是鴛鴦，翻飛雲水鄉。風高離極浦，煙暝下方塘。", "比鷺行藏別，穿荷羽翼香。雙雙浴輕浪，誰見在瀟湘。"]'),
('yuding-90','所思','李中','唐','御定全唐诗','yuding','','[]','離思春來切，誰能慰寂寥。花飛寒食過，雲重楚山遙。',48,'御定全唐詩/json/747.json','["離思春來切，誰能慰寂寥。花飛寒食過，雲重楚山遙。", "耿耿夢徒往，悠悠鬢易凋。那堪對明月，獨立水邊橋。"]'),
('yuding-0','春閨辭二首','李中','唐','御定全唐诗','yuding','','[]','捲簾遲日暖，睡起思沉沉。遼海音塵遠，春風旅館深。',96,'御定全唐詩/json/748.json','["捲簾遲日暖，睡起思沉沉。遼海音塵遠，春風旅館深。", "疏篁留鳥語，曲砌轉花陰。寄語長征客，流年不易禁。", "不得遼陽信，春心何以安。鳥啼窗樹曉，夢斷碧煙殘。", "綠鑒開還懶，紅顏駐且難。相思誰可訴，時取舊書看。"]'),
('yuding-1','臘中作','李中','唐','御定全唐诗','yuding','','[]','冬至雖雲遠，渾疑朔漠中。勁風吹大野，密雪翳高空。',48,'御定全唐詩/json/748.json','["冬至雖雲遠，渾疑朔漠中。勁風吹大野，密雪翳高空。", "泉凍如頑石，人藏類蟄蟲。豪家應不覺，獸炭滿爐紅。"]'),
('yuding-2','海城秋日書懷寄朐山孫明府','李中','唐','御定全唐诗','yuding','','[]','槐柳蟬聲起渡頭，海城孤客思悠悠。青雲展志知何日，',40,'御定全唐詩/json/748.json','["槐柳蟬聲起渡頭，海城孤客思悠悠。青雲展志知何日，", "鳴琴良宰揮毫士，應笑蹉跎身未酬。"]'),
('yuding-3','題柴司徒亭假山','李中','唐','御定全唐诗','yuding','','[]','疊石峨峨象翠微，遠山魂夢便應稀。從教蘚長添峰色，',40,'御定全唐詩/json/748.json','["疊石峨峨象翠微，遠山魂夢便應稀。從教蘚長添峰色，", "知君創得茲幽致，公退吟看到落暉。"]'),
('yuding-4','都下寒食夜作','李中','唐','御定全唐诗','yuding','','[]','香塵未歇暝煙收，城滿笙歌事勝遊。',32,'御定全唐詩/json/748.json','["香塵未歇暝煙收，城滿笙歌事勝遊。", "自是離人睡長早，千家簾卷月當樓。"]'),
('yuding-5','客中春思','李中','唐','御定全唐诗','yuding','','[]','又聽黃鳥綿蠻，目斷家鄉未還。',28,'御定全唐詩/json/748.json','["又聽黃鳥綿蠻，目斷家鄉未還。", "春水引將客夢，悠悠繞遍關山。"]'),
('yuding-6','所思','李中','唐','御定全唐诗','yuding','','[]','門掩殘花寂寂，簾垂斜月悠悠。',28,'御定全唐詩/json/748.json','["門掩殘花寂寂，簾垂斜月悠悠。", "縱有一庭萱草，何曾與我忘憂。"]'),
('yuding-7','江館秋思因成自勉','李中','唐','御定全唐诗','yuding','','[]','江邊候館幽，汀鳥暝煙收。客思雖悲月，詩魔又愛秋。',48,'御定全唐詩/json/748.json','["江邊候館幽，汀鳥暝煙收。客思雖悲月，詩魔又愛秋。", "聲名都是幻，窮達未能憂。散逸憐漁父，波中漾小舟。"]'),
('yuding-8','贈朐山楊宰','李中','唐','御定全唐诗','yuding','','[]','訟閑征賦畢，吏散捲簾時。聽雨入秋竹，留僧覆舊棋。',48,'御定全唐詩/json/748.json','["訟閑征賦畢，吏散捲簾時。聽雨入秋竹，留僧覆舊棋。", "得詩書落葉，煮茗汲寒池。化俗功成後，煙霄會有期。"]'),
('yuding-9','廬山','李中','唐','御定全唐诗','yuding','','[]','控壓潯陽景，崔嵬古及今。勢雄超地表，翠盛接天心。',168,'御定全唐詩/json/748.json','["控壓潯陽景，崔嵬古及今。勢雄超地表，翠盛接天心。", "湓浦春煙列，星灣晚景沈。圖經宜細覽，題詠卒難任。", "靖節門遙對，庾公樓俯臨。參差含積雪，隱映見歸禽。", "峭拔推雙劍，清虛數二林。白蓮池宛在，翠輦事難尋。", "天近星河冷，龍歸洞穴深。谷春攢錦繡，石潤疊瓊琳。", "玄鶴傳仙拜，青猿伴客吟。泉通九江遠，雲出幾州陰。", "冬有靈湯溢，夏無炎暑侵。他年如遂隱，五老是知音。"]'),
('yuding-10','送孫霽書記赴壽陽辟命','李中','唐','御定全唐诗','yuding','','[]','辟命羨君赴，其如愴別情。酒闌汀樹晚，帆展野風生。',96,'御定全唐詩/json/748.json','["辟命羨君赴，其如愴別情。酒闌汀樹晚，帆展野風生。", "淮靜寒煙斂，村遙夜火明。醉沈朐嶺夢，吟達壽春城。", "舊友搖鞭接，元戎掃榻迎。雪晴蓮幕啟，雲散桂山橫。", "王粲從軍畫，陳琳草檄名。知君提健筆，重振此嘉聲。"]'),
('yuding-11','聽蟬寄朐山孫明府','李中','唐','御定全唐诗','yuding','','[]','忽聽新蟬發，客情其奈何。西風起槐柳，故國阻煙波。',48,'御定全唐詩/json/748.json','["忽聽新蟬發，客情其奈何。西風起槐柳，故國阻煙波。", "壟笛悲猶少，巴猿恨未多。不知陶靖節，還動此心麼。"]'),
('yuding-12','秋江夜泊寄劉鈞正字','李中','唐','御定全唐诗','yuding','','[]','閑憶詩人思倍勞，維舟清夜泥風騷。魚龍不動澄江遠，',40,'御定全唐詩/json/748.json','["閑憶詩人思倍勞，維舟清夜泥風騷。魚龍不動澄江遠，", "此時吟苦君知否，雙鬢從他有二毛。"]'),
('yuding-13','贈朐山孫明府','李中','唐','御定全唐诗','yuding','','[]','縣庭無事似山齋，滿砌青青旋長苔。閑撫素琴曹吏散，',40,'御定全唐詩/json/748.json','["縣庭無事似山齋，滿砌青青旋長苔。閑撫素琴曹吏散，", "幾度訪君留我醉，甕香皆值酒新開。"]'),
('yuding-14','贈海上書記張濟員外','李中','唐','御定全唐诗','yuding','','[]','鵬霄休歎志難伸，貧病雖縈道且存。阮瑀不能專筆硯，',40,'御定全唐詩/json/748.json','["鵬霄休歎志難伸，貧病雖縈道且存。阮瑀不能專筆硯，", "劍有塵埃書有蠹，昔年心事共誰論。"]'),
('yuding-15','對竹','李中','唐','御定全唐诗','yuding','','[]','懶穿幽徑沖鳴鳥，忍踏清陰損翠苔。',32,'御定全唐詩/json/748.json','["懶穿幽徑沖鳴鳥，忍踏清陰損翠苔。", "不似閉門欹枕聽，秋聲如雨入軒來。"]'),
('yuding-16','送朐山孫明府赴壽陽幕府辟命','李中','唐','御定全唐诗','yuding','','[]','堪羨元戎虛右席，便承綸綍起金台。菊叢憔悴陶潛去，',40,'御定全唐詩/json/748.json','["堪羨元戎虛右席，便承綸綍起金台。菊叢憔悴陶潛去，", "預愁別後相思處，月入閑窗遠夢回。"]'),
('yuding-17','經廢宅','李中','唐','御定全唐诗','yuding','','[]','一夢奢華去不還，斷牆花發豈堪看。',32,'御定全唐詩/json/748.json','["一夢奢華去不還，斷牆花發豈堪看。", "玉纖素綆知何處，金井梧枯碧甃寒。"]'),
('yuding-18','溪邊吟','李中','唐','御定全唐诗','yuding','','[]','鸂鶒雙飛下碧流，蓼花蘋穗正含秋。',32,'御定全唐詩/json/748.json','["鸂鶒雙飛下碧流，蓼花蘋穗正含秋。", "茜裙二八採蓮去，笑沖微雨上蘭舟。"]'),
('yuding-19','得故人消息','李中','唐','御定全唐诗','yuding','','[]','多難分離久，相思每淚垂。夢歸殘月曉，信到落花時。',48,'御定全唐詩/json/748.json','["多難分離久，相思每淚垂。夢歸殘月曉，信到落花時。", "未必乖良會，何當有後期。那堪樓上望，煙水接天涯。"]'),
('yuding-20','芳草','李中','唐','御定全唐诗','yuding','','[]','二月正綿綿，離情被爾牽。四郊初過雨，萬里正鋪煙。',48,'御定全唐詩/json/748.json','["二月正綿綿，離情被爾牽。四郊初過雨，萬里正鋪煙。", "眷戀殘花惹，留連醉客眠。飄香是杜若，最憶楚江邊。"]'),
('yuding-21','江南春','李中','唐','御定全唐诗','yuding','','[]','千家事勝遊，景物可忘憂。水國樓臺晚，春郊煙雨收。',48,'御定全唐詩/json/748.json','["千家事勝遊，景物可忘憂。水國樓臺晚，春郊煙雨收。", "鷓鴣啼竹樹，杜若媚汀洲。永巷歌聲遠，王孫會莫愁。"]'),
('yuding-22','悼亡','李中','唐','御定全唐诗','yuding','','[]','巷深芳草細，門靜綠楊低。室邇人何處，花殘月又西。',48,'御定全唐詩/json/748.json','["巷深芳草細，門靜綠楊低。室邇人何處，花殘月又西。", "武陵期已負，巫峽夢終迷。獨立銷魂久，雙雙好鳥啼。"]'),
('yuding-23','春晏寄從弟德潤','李中','唐','御定全唐诗','yuding','','[]','相思禁煙近，樓上動吟魂。水國春寒在，人家暮雨昏。',48,'御定全唐詩/json/748.json','["相思禁煙近，樓上動吟魂。水國春寒在，人家暮雨昏。", "朱橋通竹樹，香徑匝蘭蓀。安得吾宗會，高歌醉一尊。"]'),
('yuding-24','贈致仕沈彬郎中','李中','唐','御定全唐诗','yuding','','[]','自言婚嫁畢，塵事不關心。老去詩魔在，春來酒病深。',48,'御定全唐詩/json/748.json','["自言婚嫁畢，塵事不關心。老去詩魔在，春來酒病深。", "山翁期采藥，海月伴鳴琴。多謝維舟處，相留接靜吟。"]'),
('yuding-25','憶溪居','李中','唐','御定全唐诗','yuding','','[]','竹軒臨水靜無塵，別後鳧鷖入夢頻。',32,'御定全唐詩/json/748.json','["竹軒臨水靜無塵，別後鳧鷖入夢頻。", "杜若菰蒲煙雨歇，一溪春色屬何人。"]'),
('yuding-26','登下蔡縣樓','李中','唐','御定全唐诗','yuding','','[]','長涯煙水又含秋，吏散時時獨上樓。',32,'御定全唐詩/json/748.json','["長涯煙水又含秋，吏散時時獨上樓。", "信斷蘭台鄉國遠，依稀王粲在荊州。"]'),
('yuding-27','下蔡春偶作','李中','唐','御定全唐诗','yuding','','[]','旅館飄飄類斷蓬，悠悠心緒有誰同。一宵風雨花飛後，',40,'御定全唐詩/json/748.json','["旅館飄飄類斷蓬，悠悠心緒有誰同。一宵風雨花飛後，", "采蘭扇枕何時遂，洗慮焚香叩上穹。"]'),
('yuding-28','再游洞神宮懷邵羽人有感','李中','唐','御定全唐诗','yuding','','[]','重向煙蘿省舊遊，因尋遺跡想浮丘。峰頭鶴去三清遠，',40,'御定全唐詩/json/748.json','["重向煙蘿省舊遊，因尋遺跡想浮丘。峰頭鶴去三清遠，", "自慚未得沖虛術，白髮無情漸滿頭。"]'),
('yuding-29','秋雨二首','李中','唐','御定全唐诗','yuding','','[]','飄灑當窮巷，苔深落葉鋪。送寒來客館，滴夢在庭梧。',96,'御定全唐詩/json/748.json','["飄灑當窮巷，苔深落葉鋪。送寒來客館，滴夢在庭梧。", "逼砌蛩聲斷，侵窗竹影孤。遙思漁叟興，蓑笠在江湖。", "竟日聲蕭颯，兼風不暫闌。竹窗秋睡美，荻浦夜漁寒。", "地僻苔生易，林疏鳥宿難。誰知苦吟者，坐聽一燈殘。"]'),
('yuding-30','經古觀有感','李中','唐','御定全唐诗','yuding','','[]','古觀寥寥枕碧溪，偶思前事立殘暉。漆園化蝶名空在，',40,'御定全唐詩/json/748.json','["古觀寥寥枕碧溪，偶思前事立殘暉。漆園化蝶名空在，", "回頭因歎浮生事，夢裏光陰疾若飛。"]'),
('yuding-31','吉水春暮訪蔡文慶處士留題','李中','唐','御定全唐诗','yuding','','[]','無事無憂鬢任蒼，濁醪閑酌送韶光。溟蒙雨過池塘暖，',40,'御定全唐詩/json/748.json','["無事無憂鬢任蒼，濁醪閑酌送韶光。溟蒙雨過池塘暖，", "戀君清話難留處，歸路迢迢又夕陽。"]'),
('yuding-32','烈祖孝高挽歌二首','李中','唐','御定全唐诗','yuding','','[]','誰解叩幹關，音容去不還。位方尊北極，壽忽殞南山。',96,'御定全唐詩/json/748.json','["誰解叩幹關，音容去不還。位方尊北極，壽忽殞南山。", "鳳輦應難問，龍髯不可攀。千秋遺恨處，雲物鎖橋山。", "仙馭歸何處，蒼蒼問且難。華夷喧道德，陵壟葬衣冠。", "禦水穿城咽，宮花泣露寒。九疑消息斷，空望白雲端。"]'),
('yuding-33','贈海上觀音院文依上人','李中','唐','御定全唐诗','yuding','','[]','煙霞海邊寺，高臥出門慵。白日少來客，清風生古松。',48,'御定全唐詩/json/748.json','["煙霞海邊寺，高臥出門慵。白日少來客，清風生古松。", "虛窗從燕入，壞屐任苔封。幾度陪師話，相留到暮鐘。"]'),
('yuding-34','秋夕病中作','李中','唐','御定全唐诗','yuding','','[]','臥病當秋夕，悠悠枕上情。不堪拋月色，無計避蟲聲。',48,'御定全唐詩/json/748.json','["臥病當秋夕，悠悠枕上情。不堪拋月色，無計避蟲聲。", "煎藥惟憂澀，停燈又怕明。曉臨清鑒裏，應有白髭生。"]'),
('yuding-35','寄黃鶚秀才','李中','唐','御定全唐诗','yuding','','[]','長憶狂遊日，惜春心恰同。預愁花片落，不遣酒壺空。',48,'御定全唐詩/json/748.json','["長憶狂遊日，惜春心恰同。預愁花片落，不遣酒壺空。", "草軟眠難舍，鶯嬌聽莫窮。如今千里隔，搔首對秋風。"]'),
('yuding-36','春日書懷寄朐山孫明府','李中','唐','御定全唐诗','yuding','','[]','一作邊城客，閑門兩度春。鶯花深院雨，書劍滿床塵。',48,'御定全唐詩/json/748.json','["一作邊城客，閑門兩度春。鶯花深院雨，書劍滿床塵。", "紫閣期終負，青雲道未伸。猶憐陶靖節，詩酒每相親。"]'),
('yuding-37','柴司徒宅牡丹','李中','唐','御定全唐诗','yuding','','[]','暮春欄檻有佳期，公子開顏乍拆時。翠幄密籠鶯未識，',40,'御定全唐詩/json/748.json','["暮春欄檻有佳期，公子開顏乍拆時。翠幄密籠鶯未識，", "只恐卻隨雲雨去，來年還是動相思。"]'),
('yuding-38','贈王道者','李中','唐','御定全唐诗','yuding','','[]','混俗從教鬢似銀，世人無分得相親。槎流海上波濤闊，',40,'御定全唐詩/json/748.json','["混俗從教鬢似銀，世人無分得相親。槎流海上波濤闊，", "仙家變化誰能測，只恐洪崖是此身。"]'),
('yuding-39','春閨辭二首','李中','唐','御定全唐诗','yuding','','[]','塵昏菱鑒懶修容，雙臉桃花落盡紅。',64,'御定全唐詩/json/748.json','["塵昏菱鑒懶修容，雙臉桃花落盡紅。", "玉塞夢歸殘燭在，曉鶯窗外囀梧桐。", "邊無音信暗消魂，茜袖香裙積淚痕。", "海燕歸來門半掩，悠悠花落又黃昏。"]'),
('yuding-40','暮春懷故人','李中','唐','御定全唐诗','yuding','','[]','池館寂寥三月盡，落花重疊蓋莓苔。惜春眷戀不忍掃，',40,'御定全唐詩/json/748.json','["池館寂寥三月盡，落花重疊蓋莓苔。惜春眷戀不忍掃，", "琅玕繡段安可得，流水浮雲共不回。"]'),
('yuding-41','秋日登潤州城樓','李中','唐','御定全唐诗','yuding','','[]','虛樓一望極封疆，積雨晴來野景長。水接海門鋪遠色，',40,'御定全唐詩/json/748.json','["虛樓一望極封疆，積雨晴來野景長。水接海門鋪遠色，", "吟罷倚欄深有思，清風留我到斜陽。"]'),
('yuding-42','晚春客次偶吟','李中','唐','御定全唐诗','yuding','','[]','暫駐征輪野店間，悠悠時節又春殘。落花風急宿酲解，',40,'御定全唐詩/json/748.json','["暫駐征輪野店間，悠悠時節又春殘。落花風急宿酲解，", "卻憐村寺僧相引，閑上虛樓共倚欄。"]'),
('yuding-43','對雨寄朐山林番明府','李中','唐','御定全唐诗','yuding','','[]','竟日如絲不暫停，莎階閑聽滴秋聲。斜飄虛閣琴書潤，',40,'御定全唐詩/json/748.json','["竟日如絲不暫停，莎階閑聽滴秋聲。斜飄虛閣琴書潤，", "遙知公退琴堂靜，坐對蕭騷飲興生。"]'),
('yuding-44','落花','李中','唐','御定全唐诗','yuding','','[]','殘紅引動詩魔，懷古牽情奈何。半落銅台月曉，',35,'御定全唐詩/json/748.json','["殘紅引動詩魔，懷古牽情奈何。半落銅台月曉，", "誰見長門深鎖，黃昏細雨相和。"]'),
('yuding-45','燕','李中','唐','御定全唐诗','yuding','','[]','豪家五色泥香，銜得營巢太忙。',28,'御定全唐詩/json/748.json','["豪家五色泥香，銜得營巢太忙。", "喧覺佳人晝夢，雙雙猶在雕梁。"]'),
('yuding-46','鶯','李中','唐','御定全唐诗','yuding','','[]','羽毛特異諸禽，出穀堪聽好音。',28,'御定全唐詩/json/748.json','["羽毛特異諸禽，出穀堪聽好音。", "薄暮欲棲何處，雨昏楊柳深深。"]'),
('yuding-47','宿山中寺','李中','唐','御定全唐诗','yuding','','[]','寄宿深山寺，惟逢老病僧。風吹幾世樹，雲暗暮秋燈。',48,'御定全唐詩/json/748.json','["寄宿深山寺，惟逢老病僧。風吹幾世樹，雲暗暮秋燈。", "瞑目忘塵慮，談空入上乘。明晨返名路，何計戀南能。"]'),
('yuding-48','海上載筆依韻酬左偃見寄','李中','唐','御定全唐诗','yuding','','[]','都城分別後，海嶠夢魂迷。吟興疏煙月，邊情起鼓鼙。',48,'御定全唐詩/json/748.json','["都城分別後，海嶠夢魂迷。吟興疏煙月，邊情起鼓鼙。", "戍旗風颭小，營柳霧籠低。草檄無餘刃，難將阮瑀齊。"]'),
('yuding-49','春晚招魯從事','李中','唐','御定全唐诗','yuding','','[]','袞袞利名役，常嗟聚會稀。有心游好景，無術駐殘暉。',48,'御定全唐詩/json/748.json','["袞袞利名役，常嗟聚會稀。有心游好景，無術駐殘暉。", "南陌草爭茂，西園花亂飛。期君舉杯酒，不醉莫言歸。"]'),
('yuding-50','和易秀才春日見寄','李中','唐','御定全唐诗','yuding','','[]','每恨多流落，吾徒不易親。相逢千里客，共醉百花春。',48,'御定全唐詩/json/748.json','["每恨多流落，吾徒不易親。相逢千里客，共醉百花春。", "小檻山當面，閑階柳拂塵。何時卜西上，明月桂枝新。"]'),
('yuding-51','送黃秀才','李中','唐','御定全唐诗','yuding','','[]','雨餘飛絮亂，相別思難任。酒罷河橋晚，帆開煙水深。',48,'御定全唐詩/json/748.json','["雨餘飛絮亂，相別思難任。酒罷河橋晚，帆開煙水深。", "蟾宮須展志，漁艇莫牽心。岐路從茲遠，雙魚信勿沈。"]'),
('yuding-52','庭竹','李中','唐','御定全唐诗','yuding','','[]','偶自山僧院，移歸傍砌栽。好風終日起，幽鳥有時來。',48,'御定全唐詩/json/748.json','["偶自山僧院，移歸傍砌栽。好風終日起，幽鳥有時來。", "篩月牽詩興，籠煙伴酒杯。南窗睡輕起，蕭颯雨聲回。"]'),
('yuding-53','送戴秀才','李中','唐','御定全唐诗','yuding','','[]','已是殊鄉客，送君重慘然。河橋乍分首，槐柳正鳴蟬。',48,'御定全唐詩/json/748.json','["已是殊鄉客，送君重慘然。河橋乍分首，槐柳正鳴蟬。", "短棹離幽浦，孤帆觸遠煙。清朝重文物，變化莫遷延。"]'),
('yuding-54','病中作','李中','唐','御定全唐诗','yuding','','[]','閑齋病初起，心緒複悠悠。開篋群書蠹，聽蟬滿樹秋。',48,'御定全唐詩/json/748.json','["閑齋病初起，心緒複悠悠。開篋群書蠹，聽蟬滿樹秋。", "詩魔還漸動，藥債未能酬。為憶前山色，扶持上小樓。"]'),
('yuding-55','離家','李中','唐','御定全唐诗','yuding','','[]','送別人歸春日斜，獨鞭羸馬指天涯。',32,'御定全唐詩/json/748.json','["送別人歸春日斜，獨鞭羸馬指天涯。", "月生江上鄉心動，投宿匆忙近酒家。"]'),
('yuding-56','村行','李中','唐','御定全唐诗','yuding','','[]','極目青青壟麥齊，野塘波闊下鳧鷖。陽烏景暖林桑密，獨立閑聽戴勝啼。',32,'御定全唐詩/json/748.json','["極目青青壟麥齊，野塘波闊下鳧鷖。陽烏景暖林桑密，獨立閑聽戴勝啼。"]'),
('yuding-57','獻喬侍郎','李中','唐','御定全唐诗','yuding','','[]','位望誰能並，當年志已伸。人間傳鳳藻，天上演龍綸。',240,'御定全唐詩/json/748.json','["位望誰能並，當年志已伸。人間傳鳳藻，天上演龍綸。", "賈馬才無敵，褒雄譽益臻。除奸深繫念，致主迥忘身。", "諫疏縱橫上，危言果敢陳。忠貞雖貫世，消長豈由人。", "慷慨辭朝闕，迢遙涉路塵。千山明夕照，孤棹渡長津。", "杜宇聲方切，江蘺色正新。卷舒唯合道，喜慍不勞神。", "禪客陪清論，漁翁作近鄰。靜吟窮野景，狂醉養天真。", "格論思名士，輿情渴直臣。九霄恩複降，比戶意皆忻。", "卻入鴛鸞序，終身顧問頻。漏殘丹禁曉，日暖玉墀春。", "鑒物心如水，憂時鬢若銀。惟期康庶事，永要敘彝倫。", "貴賤知無間，孤寒必許親。幾多沈滯者，拭目望陶鈞。"]'),
('yuding-58','獻中書張舍人','李中','唐','御定全唐诗','yuding','','[]','仙桂從攀後，人間播大名。飛騰諧素志，霄漢是前程。',144,'御定全唐詩/json/748.json','["仙桂從攀後，人間播大名。飛騰諧素志，霄漢是前程。", "持憲威聲振，司言品秩清。簾開春酒醒，月上草麻成。", "丹陛淩晨對，青雲逐步生。照人裴玉瑩，鑒物憲陂明。", "下直無他事，閒遊恣逸情。林僧開戶接，溪叟掃苔迎。", "煮茗山房冷，垂綸野艇輕。神清宜放曠，詩苦益縱橫。", "餘刃時皆仰，嘉謀眾佇行。四方觀啟沃，畢竟念孤平。"]'),
('yuding-59','海上和郎戩員外赴倅職','李中','唐','御定全唐诗','yuding','','[]','宋玉逢秋何起悲，新恩委寄好開眉。班升鴛鷺頻經歲，',40,'御定全唐詩/json/748.json','["宋玉逢秋何起悲，新恩委寄好開眉。班升鴛鷺頻經歲，", "一朝鳳詔重征入，鵬化那教尺鷃知。"]'),
('yuding-60','又送赴關','李中','唐','御定全唐诗','yuding','','[]','心似白雲歸帝鄉，暫停良畫別龔黃。煙波乍曉浮蘭棹，',40,'御定全唐詩/json/748.json','["心似白雲歸帝鄉，暫停良畫別龔黃。煙波乍曉浮蘭棹，", "想應敷對忠言後，不放鄉雲離太陽。"]'),
('yuding-61','書郭判官幽齋壁','李中','唐','御定全唐诗','yuding','','[]','不妨公退尚清虛，創得幽齋興有餘。要引好風清戶牖，',40,'御定全唐詩/json/748.json','["不妨公退尚清虛，創得幽齋興有餘。要引好風清戶牖，", "更有野情堪愛處，石床苔蘚似匡廬。"]'),
('yuding-62','石棋局獻時宰','李中','唐','御定全唐诗','yuding','','[]','得從嶽叟誠堪重，卻獻皋夔事更宜。公退啟枰書院靜，',40,'御定全唐詩/json/748.json','["得從嶽叟誠堪重，卻獻皋夔事更宜。公退啟枰書院靜，", "預想幽窗風雨夜，一燈閑照覆圖時。"]'),
('yuding-63','海城秋夕寄懷舍弟','李中','唐','御定全唐诗','yuding','','[]','鳥棲庭樹夜悠悠，枕上誰知淚暗流。千里夢魂迷舊業，',40,'御定全唐詩/json/748.json','["鳥棲庭樹夜悠悠，枕上誰知淚暗流。千里夢魂迷舊業，", "早晚萊衣同著去，免悲流落在邊州。"]'),
('yuding-64','和夏侯秀才春日見寄','李中','唐','御定全唐诗','yuding','','[]','綿蠻黃鳥不堪聽，觸目離愁怕酒醒。雲散碧山當晚檻，',40,'御定全唐詩/json/748.json','["綿蠻黃鳥不堪聽，觸目離愁怕酒醒。雲散碧山當晚檻，", "晝夢不成吟有興，揮毫書在枕邊屏。"]'),
('yuding-65','送夏侯秀才','李中','唐','御定全唐诗','yuding','','[]','江村搖落暮蟬鳴，執手臨岐動別情。古岸相看殘照在，',40,'御定全唐詩/json/748.json','["江村搖落暮蟬鳴，執手臨岐動別情。古岸相看殘照在，", "況是清朝至公在，預知喬木定遷鶯。"]'),
('yuding-66','江南重會友人感舊二首','李中','唐','御定全唐诗','yuding','','[]','江南重會面，聊話十年心。共立黃花畔，空驚素發侵。',96,'御定全唐詩/json/748.json','["江南重會面，聊話十年心。共立黃花畔，空驚素發侵。", "斜陽浮遠水，歸鳥下疏林。牽動詩魔處，涼風村落砧。", "長江落照天，物景似當年。憶昔攜村酒，相將上釣船。", "狂歌紅蓼岸，驚起白鷗眠。今日趨名急，臨風一黯然。"]'),
('yuding-67','己未歲冬捧宣頭離下蔡','李中','唐','御定全唐诗','yuding','','[]','詔下如春煦，巢南志不違。空將感恩淚，滴盡冒寒衣。',48,'御定全唐詩/json/748.json','["詔下如春煦，巢南志不違。空將感恩淚，滴盡冒寒衣。", "覆載元容善，形骸果得歸。無心慚季路，負米覲親闈。"]'),
('yuding-68','哭舍弟二首','李中','唐','御定全唐诗','yuding','','[]','鴻雁離群後，成行憶日存。誰知歸故里，只得奠吟魂。',96,'御定全唐詩/json/748.json','["鴻雁離群後，成行憶日存。誰知歸故里，只得奠吟魂。", "蟲蠹書盈篋，人稀草擁門。從茲長慟後，獨自奉晨昏。", "浮生多夭枉，惟爾最堪悲。同氣未歸日，慈親臨老時。", "舊詩傳海嶠，新塚枕江湄。遺稚嗚嗚處，黃昏繞繐帷。"]'),
('yuding-69','書情寄詩友','李中','唐','御定全唐诗','yuding','','[]','默默誰知我，裴回野水邊。詩情長若舊，吾事更無先。',48,'御定全唐詩/json/748.json','["默默誰知我，裴回野水邊。詩情長若舊，吾事更無先。", "芳草人稀地，殘陽雁過天。靜思吟友外，此意複誰憐。"]'),
('yuding-70','讀蜀志','李中','唐','御定全唐诗','yuding','','[]','鼎分天地日，先主力元微。魚水從相得，山河遂有歸。',48,'御定全唐詩/json/748.json','["鼎分天地日，先主力元微。魚水從相得，山河遂有歸。", "任賢無間忌，報國盡神機。草昧爭雄者，君臣似此稀。"]'),
('yuding-71','獻張拾遺','李中','唐','御定全唐诗','yuding','','[]','官資清貴近丹墀，性格孤高世所稀。金殿日開親鳳扆，',40,'御定全唐詩/json/748.json','["官資清貴近丹墀，性格孤高世所稀。金殿日開親鳳扆，", "獻替頻陳忠譽播，鵬霄萬里展雄飛。"]'),
('yuding-72','獻中書湯舍人','李中','唐','御定全唐诗','yuding','','[]','慶雲呈瑞為明時，演暢絲綸在紫微。鑾殿對時親舜日，',40,'御定全唐詩/json/748.json','["慶雲呈瑞為明時，演暢絲綸在紫微。鑾殿對時親舜日，", "隔座銀屏看是設，一門清貴古今稀。"]'),
('yuding-73','海上太守新創東亭','李中','唐','御定全唐诗','yuding','','[]','使君心智杳難同，選勝開亭景莫窮。高敞軒窗迎海月，',48,'御定全唐詩/json/748.json','["使君心智杳難同，選勝開亭景莫窮。高敞軒窗迎海月，", "滿徑苔紋疏雨後，入簷山色夕陽中。偏宜下榻延徐孺，"]'),
('yuding-74','宮詞二首','李中','唐','御定全唐诗','yuding','','[]','門鎖簾垂月影斜，翠華咫尺隔天涯。',64,'御定全唐詩/json/748.json','["門鎖簾垂月影斜，翠華咫尺隔天涯。", "香鋪羅幌不成夢，背壁銀缸落盡花。", "金波寒透水精簾，燒盡沈檀手自添。", "風遞笙歌門已掩，翠華何處夜厭厭。"]'),
('yuding-75','採蓮女','李中','唐','御定全唐诗','yuding','','[]','晚涼含笑上蘭舟，波底紅妝影欲浮。',32,'御定全唐詩/json/748.json','["晚涼含笑上蘭舟，波底紅妝影欲浮。", "陌上少年休植足，荷香深處不回頭。"]'),
('yuding-76','鐘陵春思','李中','唐','御定全唐诗','yuding','','[]','沉沉樓影月當午，冉冉風香花正開。',32,'御定全唐詩/json/748.json','["沉沉樓影月當午，冉冉風香花正開。", "芳草迢迢滿南陌，王孫何處不歸來。"]'),
('yuding-77','贈夏秀才','李中','唐','御定全唐诗','yuding','','[]','軒車紫陌競尋春，獨掩衡門病起身。步月怕傷三徑蘚，',40,'御定全唐詩/json/748.json','["軒車紫陌競尋春，獨掩衡門病起身。步月怕傷三徑蘚，", "況是青雲知己在，原思生計莫憂貧。"]'),
('yuding-78','夏日書依上人壁','李中','唐','御定全唐诗','yuding','','[]','門外塵飛暑氣濃，院中蕭索似山中。',32,'御定全唐詩/json/748.json','["門外塵飛暑氣濃，院中蕭索似山中。", "最憐煮茗相留處，疏竹當軒一榻風。"]'),
('yuding-79','下蔡春暮旅懷','李中','唐','御定全唐诗','yuding','','[]','柳過春霖絮亂飛，旅中懷抱獨淒淒。月生淮上雲初散，',40,'御定全唐詩/json/748.json','["柳過春霖絮亂飛，旅中懷抱獨淒淒。月生淮上雲初散，", "拜恩為養慈親急，願向明朝捧紫泥。"]'),
('yuding-80','捧宣頭許歸侍養','李中','唐','御定全唐诗','yuding','','[]','泥書捧處聖恩新，許覲庭闈養二親。',32,'御定全唐詩/json/748.json','["泥書捧處聖恩新，許覲庭闈養二親。", "螻蟻至微寧足數，未知何處答穹旻。"]'),
('yuding-81','途中作','李中','唐','御定全唐诗','yuding','','[]','煙波涉曆指家林，欲到家林懼卻深。',32,'御定全唐詩/json/748.json','["煙波涉曆指家林，欲到家林懼卻深。", "得信慈親痾瘵減，當時寬勉采蘭心。"]'),
('yuding-82','都下再會友人','李中','唐','御定全唐诗','yuding','','[]','誰言多難後，重會喜淹留。欲話關河夢，先驚鬢髮秋。',48,'御定全唐詩/json/748.json','["誰言多難後，重會喜淹留。欲話關河夢，先驚鬢髮秋。", "浮雲空冉冉，遠水自悠悠。多謝開青眼，攜壺共上樓。"]'),
('yuding-0','登毗陵青山樓','李中','唐','御定全唐诗','yuding','','[]','高樓閑上對晴空，豁目開襟半日中。千里吳山清不斷，',40,'御定全唐詩/json/749.json','["高樓閑上對晴空，豁目開襟半日中。千里吳山清不斷，", "吟罷倚欄何限意，回頭城郭暮煙籠。"]'),
('yuding-1','晉陵罷任寓居，依韻和陳銳秀才見寄','李中','唐','御定全唐诗','yuding','','[]','掩門三徑莓苔綠，車馬誰來陋巷間。臥棄琴書公幹病，',40,'御定全唐詩/json/749.json','["掩門三徑莓苔綠，車馬誰來陋巷間。臥棄琴書公幹病，", "濟物未能伸一術，敢於明代愛青山。"]'),
('yuding-2','春苔','李中','唐','御定全唐诗','yuding','','[]','春霖催得鎖煙濃，竹院莎齋徑小通。',32,'御定全唐詩/json/749.json','["春霖催得鎖煙濃，竹院莎齋徑小通。", "誰愛落花風味處，莫愁門巷襯殘紅。"]'),
('yuding-3','夏雲','李中','唐','御定全唐诗','yuding','','[]','如峰形狀在西郊，未見從龍上泬寥。',32,'御定全唐詩/json/749.json','["如峰形狀在西郊，未見從龍上泬寥。", "多謝好風吹起後，化為甘雨濟田苗。"]'),
('yuding-4','書夏秀才幽居壁','李中','唐','御定全唐诗','yuding','','[]','永巷苔深戶半開，床頭書劍積塵埃。',32,'御定全唐詩/json/749.json','["永巷苔深戶半開，床頭書劍積塵埃。", "最憐小檻疏篁晚，幽鳥雙雙何處來。"]'),
('yuding-5','紅花','李中','唐','御定全唐诗','yuding','','[]','紅花顏色掩千花，任是猩猩血未加。',32,'御定全唐詩/json/749.json','["紅花顏色掩千花，任是猩猩血未加。", "染出輕羅莫相貴，古人崇儉誡奢華。"]'),
('yuding-6','安福縣秋吟寄陳銳秘書','李中','唐','御定全唐诗','yuding','','[]','縣庭事簡得餘功，詩興秋來不可窮。臥聽寒蛩莎砌月，',40,'御定全唐詩/json/749.json','["縣庭事簡得餘功，詩興秋來不可窮。臥聽寒蛩莎砌月，", "苦恨交親多契闊，未知良會幾時同。"]'),
('yuding-7','新喻縣酬王仲華少府見貽','李中','唐','御定全唐诗','yuding','','[]','事簡開樽有逸情，共忻官舍月華清。每慚花欠河陽景，',40,'御定全唐詩/json/749.json','["事簡開樽有逸情，共忻官舍月華清。每慚花欠河陽景，", "與君盡力行公道，敢向昌朝俟陟明。"]'),
('yuding-8','暮春有感寄宋維員外','李中','唐','御定全唐诗','yuding','','[]','杜宇聲中老病心，此心無計駐光陰。西園雨過好花盡，',40,'御定全唐詩/json/749.json','["杜宇聲中老病心，此心無計駐光陰。西園雨過好花盡，", "明年才候東風至，結駟期君預去尋。"]'),
('yuding-9','題吉水縣廳前新栽小松','李中','唐','御定全唐诗','yuding','','[]','劚開幽澗蘚苔斑，移得孤根植砌前。影小未遮官舍月，',40,'御定全唐詩/json/749.json','["劚開幽澗蘚苔斑，移得孤根植砌前。影小未遮官舍月，", "輸我婆娑欄檻內，晚風蕭颯學幽泉。"]'),
('yuding-10','《贈念法華經》綬上人','李中','唐','御定全唐诗','yuding','','[]','五更初起掃松堂，瞑目先焚一炷香。',32,'御定全唐詩/json/749.json','["五更初起掃松堂，瞑目先焚一炷香。", "念徹蓮經誰得見，千峰岩外曉蒼蒼。"]'),
('yuding-11','秋日途中','李中','唐','御定全唐诗','yuding','','[]','信步騰騰野岩邊，離家都為利名牽。',32,'御定全唐詩/json/749.json','["信步騰騰野岩邊，離家都為利名牽。", "疏林一路斜陽裏，颯颯西風滿耳蟬。"]'),
('yuding-12','宿韋校書幽居','李中','唐','御定全唐诗','yuding','','[]','溪上高眠與鶴閑，開樽留我待柴關。',32,'御定全唐詩/json/749.json','["溪上高眠與鶴閑，開樽留我待柴關。", "園林月白秋霖歇，一夜泉聲似故山。"]'),
('yuding-13','依韻和友人秋夕見寄','李中','唐','御定全唐诗','yuding','','[]','夕風庭葉落，誰見此時情。不作關河夢，空聞砧杵聲。',48,'御定全唐詩/json/749.json','["夕風庭葉落，誰見此時情。不作關河夢，空聞砧杵聲。", "會須求至理，何必歎無成。好約高僧宿，同看海月生。"]'),
('yuding-14','吉水作尉酬高援秀才見贈','李中','唐','御定全唐诗','yuding','','[]','佐邑慚無術，敢言貧與清。風騷誰是主，煙月自關情。',48,'御定全唐詩/json/749.json','["佐邑慚無術，敢言貧與清。風騷誰是主，煙月自關情。", "卷箔當山色，開窗就竹聲。憐君惠嘉句，資我欲垂名。"]'),
('yuding-15','送智雄上人','李中','唐','御定全唐诗','yuding','','[]','忽起游方念，飄然不可留。未知攜一錫，乘興向何州。',48,'御定全唐詩/json/749.json','["忽起游方念，飄然不可留。未知攜一錫，乘興向何州。", "古岸春雲散，遙天晚雨收。想應重會面，風月又清秋。"]'),
('yuding-16','覽友人卷','李中','唐','御定全唐诗','yuding','','[]','新詩開卷處，造化竭精英。雪霽楚山碧，月高湘水清。',48,'御定全唐詩/json/749.json','["新詩開卷處，造化竭精英。雪霽楚山碧，月高湘水清。", "初吟塵慮息，再味古風生。自此寰區內，喧騰二雅名。"]'),
('yuding-17','送人南游','李中','唐','御定全唐诗','yuding','','[]','浪跡天涯去，南荒必動情。草青虞帝廟，雲暗夜郎城。',48,'御定全唐詩/json/749.json','["浪跡天涯去，南荒必動情。草青虞帝廟，雲暗夜郎城。", "越鳥驚鄉夢，蠻風解宿酲。早思歸故里，華髮等閒生。"]'),
('yuding-18','晉陵縣夏日作','李中','唐','御定全唐诗','yuding','','[]','事簡公庭靜，開簾暑氣中。依經煎綠茗，入竹就清風。',48,'御定全唐詩/json/749.json','["事簡公庭靜，開簾暑氣中。依經煎綠茗，入竹就清風。", "至論招禪客，忘機憶釣翁。晚涼安枕簟，海月出牆東。"]'),
('yuding-19','郵亭早起','李中','唐','御定全唐诗','yuding','','[]','郵舍殘燈在，村林雞唱頻。星河吟裏曉，川陸望中春。',48,'御定全唐詩/json/749.json','["郵舍殘燈在，村林雞唱頻。星河吟裏曉，川陸望中春。", "舊友青雲貴，殊鄉素發新。悠悠念行計，難更駐征輪。"]'),
('yuding-20','客中寒食','李中','唐','御定全唐诗','yuding','','[]','旅次經寒食，思鄉淚濕巾。音書天外斷，桃李雨中春。',48,'御定全唐詩/json/749.json','["旅次經寒食，思鄉淚濕巾。音書天外斷，桃李雨中春。", "欲飲都無緒，唯吟似有因。輸他郊郭外，多少踏青人。"]'),
('yuding-21','旅館秋夕','李中','唐','御定全唐诗','yuding','','[]','寥寥山館裏，獨坐酒初醒。舊業多年別，秋霖一夜聽。',48,'御定全唐詩/json/749.json','["寥寥山館裏，獨坐酒初醒。舊業多年別，秋霖一夜聽。", "砌蛩聲漸息，窗燭影猶停。早晚無他事，休如泛水萍。"]'),
('yuding-22','宿青溪米處士幽居','李中','唐','御定全唐诗','yuding','','[]','寄宿溪光裏，夜涼高士家。養風窗外竹，叫月水中蛙。',48,'御定全唐詩/json/749.json','["寄宿溪光裏，夜涼高士家。養風窗外竹，叫月水中蛙。", "靜慮同搜句，清神旋煮茶。唯憂曉雞唱，塵裏事如麻。"]'),
('yuding-23','維舟秋浦，逢故人張矩同泊','李中','唐','御定全唐诗','yuding','','[]','卸帆清夜碧江濱，冉冉涼風動白蘋。波上正吟新霽月，',40,'御定全唐詩/json/749.json','["卸帆清夜碧江濱，冉冉涼風動白蘋。波上正吟新霽月，", "且飲一壺銷百恨，會須遭遇識通津。"]'),
('yuding-24','代別','李中','唐','御定全唐诗','yuding','','[]','明日鳴鞭天一涯，悠悠此夕怯分離。紅樓有恨金波轉，',40,'御定全唐詩/json/749.json','["明日鳴鞭天一涯，悠悠此夕怯分離。紅樓有恨金波轉，", "花時定是慵開鑒，獨向春風忍掃眉。"]'),
('yuding-25','悼懷王喪妃','李中','唐','御定全唐诗','yuding','','[]','花綻花開事可驚，暫來浮世返蓬瀛。楚宮夢斷雲空在，',40,'御定全唐詩/json/749.json','["花綻花開事可驚，暫來浮世返蓬瀛。楚宮夢斷雲空在，", "音容寂寞春牢落，誰會樓中獨立情。"]'),
('yuding-26','酒醒','李中','唐','御定全唐诗','yuding','','[]','睡覺花陰芳草軟，不知明月出牆東。',32,'御定全唐詩/json/749.json','["睡覺花陰芳草軟，不知明月出牆東。", "杯盤狼藉人何處，聚散空驚似夢中。"]'),
('yuding-27','送虞道士','李中','唐','御定全唐诗','yuding','','[]','煙霞聚散通三島，星斗分明在一壺。',32,'御定全唐詩/json/749.json','["煙霞聚散通三島，星斗分明在一壺。", "笑說餘杭沽酒去，蔡家重要會麻姑。"]'),
('yuding-28','懷舊夜吟寄趙杞','李中','唐','御定全唐诗','yuding','','[]','長笛聲中海月飛，桃花零落滿庭墀。魂銷事去無尋處，',40,'御定全唐詩/json/749.json','["長笛聲中海月飛，桃花零落滿庭墀。魂銷事去無尋處，", "悠悠方寸何因解，明日江樓望渺彌。"]'),
('yuding-29','宿臨江驛','李中','唐','御定全唐诗','yuding','','[]','候館寥寥輟棹過，酒醒無奈旅愁何。雨昏郊郭行人少，',40,'御定全唐詩/json/749.json','["候館寥寥輟棹過，酒醒無奈旅愁何。雨昏郊郭行人少，", "篇章早晚逢知己，苦志忘形自有魔。"]'),
('yuding-30','途中柳','李中','唐','御定全唐诗','yuding','','[]','翠色晴來近，長亭路去遙。無人折煙縷，落日拂溪橋。',24,'御定全唐詩/json/749.json','["翠色晴來近，長亭路去遙。無人折煙縷，落日拂溪橋。"]'),
('yuding-31','隔牆花','李中','唐','御定全唐诗','yuding','','[]','顏色尤難近，馨香不易通。朱門金鎖隔，空使怨春風。',24,'御定全唐詩/json/749.json','["顏色尤難近，馨香不易通。朱門金鎖隔，空使怨春風。"]'),
('yuding-32','廣陵寒食夜','李中','唐','御定全唐诗','yuding','','[]','廣陵寒食夜，豪貴足佳期。紫陌人歸後，紅樓月上時。',48,'御定全唐詩/json/749.json','["廣陵寒食夜，豪貴足佳期。紫陌人歸後，紅樓月上時。", "綺羅香未歇，絲竹韻猶遲。明日踏青興，輸他輕薄兒。"]'),
('yuding-33','寄廬山莊隱士','李中','唐','御定全唐诗','yuding','','[]','煙蘿擁竹關，物外自求安。逼枕溪聲近，當簷嶽色寒。',48,'御定全唐詩/json/749.json','["煙蘿擁竹關，物外自求安。逼枕溪聲近，當簷嶽色寒。", "藥苗應自采，琴調對誰彈。待了浮名後，依君共掛冠。"]'),
('yuding-34','吉水寄閻侍禦','李中','唐','御定全唐诗','yuding','','[]','何處懷君切，令人欲白頭。偶尋花外寺，獨立水邊樓。',48,'御定全唐詩/json/749.json','["何處懷君切，令人欲白頭。偶尋花外寺，獨立水邊樓。", "不得論休戚，何因校獻酬。吟餘興難盡，風笛起漁舟。"]'),
('yuding-35','送張惟貞少府之江陰','李中','唐','御定全唐诗','yuding','','[]','相送煙汀畔，酒闌登小舟。離京梅雨歇，到邑早蟬秋。',48,'御定全唐詩/json/749.json','["相送煙汀畔，酒闌登小舟。離京梅雨歇，到邑早蟬秋。", "俗必期康濟，詩誰互唱酬。晚涼諸吏散，海月入虛樓。"]'),
('yuding-36','鐘陵禁煙寄從弟','李中','唐','御定全唐诗','yuding','','[]','落絮飛花日又西，踏青無侶草萋萋。',32,'御定全唐詩/json/749.json','["落絮飛花日又西，踏青無侶草萋萋。", "交親書斷竟不到，忍聽黃昏杜宇啼。"]'),
('yuding-37','夜泊江渚','李中','唐','御定全唐诗','yuding','','[]','水鄉明月上晴空，汀島香生杜若風。',32,'御定全唐詩/json/749.json','["水鄉明月上晴空，汀島香生杜若風。", "不是當年獨醒客，且沽村酒待漁翁。"]'),
('yuding-38','吉水縣依韻酬華松秀才見寄','李中','唐','御定全唐诗','yuding','','[]','官況蕭條在水村，吏歸無事好論文。枕欹獨聽殘春雨，',40,'御定全唐詩/json/749.json','["官況蕭條在水村，吏歸無事好論文。枕欹獨聽殘春雨，", "詩情冷淡知音少，獨喜江皋得見君。"]'),
('yuding-39','貽廬山清溪觀王尊師','李中','唐','御定全唐诗','yuding','','[]','霞帔星冠複杖藜，積年修煉住靈溪。松軒睡覺冷雲起，',40,'御定全唐詩/json/749.json','["霞帔星冠複杖藜，積年修煉住靈溪。松軒睡覺冷雲起，", "鼎中龍虎功成後，海上三山去不迷。"]'),
('yuding-40','王昭君','李中','唐','御定全唐诗','yuding','','[]','蛾眉翻自累，萬里陷窮邊。滴淚胡風起，寬心漢月圓。',48,'御定全唐詩/json/749.json','["蛾眉翻自累，萬里陷窮邊。滴淚胡風起，寬心漢月圓。", "飛塵長翳日，白草自連天。誰貢和親策，千秋汙簡編。"]'),
('yuding-41','送姚端先輩歸甯','李中','唐','御定全唐诗','yuding','','[]','知君歸覲省，稱意涉通津。解纜汀洲曉，張帆煙水春。',48,'御定全唐詩/json/749.json','["知君歸覲省，稱意涉通津。解纜汀洲曉，張帆煙水春。", "牽吟芳草遠，貰酒亂花新。拜慶庭闈處，蟾枝香滿身。"]'),
('yuding-42','江村晚秋作','李中','唐','御定全唐诗','yuding','','[]','高秋水村路，隔岸見人家。好是經霜葉，紅於帶露花。',48,'御定全唐詩/json/749.json','["高秋水村路，隔岸見人家。好是經霜葉，紅於帶露花。", "臨罾魚易得，就店酒難賒。吟興胡能盡，風清日又斜。"]'),
('yuding-43','蛩','李中','唐','御定全唐诗','yuding','','[]','月冷莎庭夜已深，百蟲聲外有清音。',32,'御定全唐詩/json/749.json','["月冷莎庭夜已深，百蟲聲外有清音。", "詩情正苦無眠處，愧爾階前相伴吟。"]'),
('yuding-44','感秋書事','李中','唐','御定全唐诗','yuding','','[]','宦途憔悴雪生頭，家計相牽未得休。',32,'御定全唐詩/json/749.json','["宦途憔悴雪生頭，家計相牽未得休。", "紅蓼白蘋消息斷，舊溪煙月負漁舟。"]'),
('yuding-45','訪廬山歸章禪伯','李中','唐','御定全唐诗','yuding','','[]','沉沉石室疏鐘後，寂寂莎池片月明。',32,'御定全唐詩/json/749.json','["沉沉石室疏鐘後，寂寂莎池片月明。", "多少學徒求妙法，要於言下悟無生。"]'),
('yuding-46','廬山棲隱洞譚先生院留題','李中','唐','御定全唐诗','yuding','','[]','壇畔歸雲冷濕襟，拂苔移石坐花陰。',32,'御定全唐詩/json/749.json','["壇畔歸雲冷濕襟，拂苔移石坐花陰。", "偶然醒得莊周夢，始覺玄門興味深。"]'),
('yuding-47','江行值暴風雨','李中','唐','御定全唐诗','yuding','','[]','風狂雨暗舟人懼，自委神明志不邪。',32,'御定全唐詩/json/749.json','["風狂雨暗舟人懼，自委神明志不邪。", "投得葦灣波浪息，岸頭煙火近人家。"]'),
('yuding-48','杪秋夕吟懷寄宋維先輩','李中','唐','御定全唐诗','yuding','','[]','江島窮秋木葉稀，月高何處搗寒衣。',32,'御定全唐詩/json/749.json','["江島窮秋木葉稀，月高何處搗寒衣。", "苦嗟不見登龍客，此夜悠悠一夢飛。"]'),
('yuding-49','七夕','李中','唐','御定全唐诗','yuding','','[]','星河耿耿正新秋，絲竹千家列彩樓。',32,'御定全唐詩/json/749.json','["星河耿耿正新秋，絲竹千家列彩樓。", "可惜穿針方有興，纖纖初月苦難留。"]'),
('yuding-50','吉水作尉時酬閻侍禦見寄','李中','唐','御定全唐诗','yuding','','[]','謬佐驅雞任，常思賦鵩人。未諧林下約，空感病來身。',48,'御定全唐詩/json/749.json','["謬佐驅雞任，常思賦鵩人。未諧林下約，空感病來身。", "鎖徑青苔老，鋪階紅葉新。相思不可見，猶喜得書頻。"]'),
('yuding-51','清溪逢張惟貞秀才','李中','唐','御定全唐诗','yuding','','[]','洞隱紅霞外，房開碧嶂根。昔年同煉句，幾夜共聽猿。',48,'御定全唐詩/json/749.json','["洞隱紅霞外，房開碧嶂根。昔年同煉句，幾夜共聽猿。", "考古書千卷，忘憂酒一樽。如今歸建業，雅道喜重論。"]'),
('yuding-52','送閻侍禦歸闕','李中','唐','御定全唐诗','yuding','','[]','羨君乘紫詔，歸路指通津。鼓棹煙波暖，還京雨露新。',48,'御定全唐詩/json/749.json','["羨君乘紫詔，歸路指通津。鼓棹煙波暖，還京雨露新。", "趨朝丹禁曉，聳轡九衢春。自愧湮沈者，隨軒未有因。"]'),
('yuding-53','甲子歲罷吉水縣過鐘陵時暮春維舟江渚謁柴太尉席上作','李中','唐','御定全唐诗','yuding','','[]','公侯延駐暫踟躕，況值風光三月初。亂落杯盤花片小，',40,'御定全唐詩/json/749.json','["公侯延駐暫踟躕，況值風光三月初。亂落杯盤花片小，", "卻笑田家門下客，當時容易歎車魚。"]'),
('yuding-54','海上春夕旅懷寄左偃','李中','唐','御定全唐诗','yuding','','[]','柳過清明絮亂飛，感時懷舊思淒淒。月生樓閣雲初散，',40,'御定全唐詩/json/749.json','["柳過清明絮亂飛，感時懷舊思淒淒。月生樓閣雲初散，", "北山高臥風騷客，安得同吟複杖藜。"]'),
('yuding-55','江次維舟登古寺','李中','唐','御定全唐诗','yuding','','[]','輟棹因過古梵宮，荒涼門徑鎖苔茸。綠陰滿地前朝樹，',40,'御定全唐詩/json/749.json','["輟棹因過古梵宮，荒涼門徑鎖苔茸。綠陰滿地前朝樹，", "吟餘卻返來時路，回首盤桓尚駐筇。"]'),
('yuding-56','春日招宋維先輩','李中','唐','御定全唐诗','yuding','','[]','甕中竹葉今朝熟，鑒裏桃花昨日開。',32,'御定全唐詩/json/749.json','["甕中竹葉今朝熟，鑒裏桃花昨日開。", "為報廣寒攀桂客，莫辭相訪共銜杯。"]'),
('yuding-57','吹笛兒','李中','唐','御定全唐诗','yuding','','[]','隴頭休聽月明中，妙竹嘉音際會逢。',32,'御定全唐詩/json/749.json','["隴頭休聽月明中，妙竹嘉音際會逢。", "見爾樽前吹一曲，令人重憶許雲封。"]'),
('yuding-58','所思','李中','唐','御定全唐诗','yuding','','[]','解佩當時在洛濱，悠悠疑是夢中身。',32,'御定全唐詩/json/749.json','["解佩當時在洛濱，悠悠疑是夢中身。", "自從物外無消息，花謝鶯啼近十春。"]'),
('yuding-59','吉水縣酬夏侯秀才見寄','李中','唐','御定全唐诗','yuding','','[]','啟鑒悠悠兩鬢蒼，病來心緒易淒涼。',32,'御定全唐詩/json/749.json','["啟鑒悠悠兩鬢蒼，病來心緒易淒涼。", "知音不到吟還懶，鎖印開簾又夕陽。"]'),
('yuding-60','和友人喜雪','李中','唐','御定全唐诗','yuding','','[]','臘雪頻頻降，成堆不可除。伴吟花莫並，銷瘴藥何如。',72,'御定全唐詩/json/749.json','["臘雪頻頻降，成堆不可除。伴吟花莫並，銷瘴藥何如。", "謝女詩成處，袁安睡起初。深迷樵子徑，冷逼旅人居。", "惹砌催樽俎，飄窗入簿書。最宜樓上望，散亂滿空虛。"]'),
('yuding-61','感事呈所知','李中','唐','御定全唐诗','yuding','','[]','競愛松筠翠，皆憐桃李芳。如求濟世廣，桑柘願商量。',24,'御定全唐詩/json/749.json','["競愛松筠翠，皆憐桃李芳。如求濟世廣，桑柘願商量。"]'),
('yuding-62','送汪濤','李中','唐','御定全唐诗','yuding','','[]','知君別家後，不免淚沾襟。芳草千里路，夕陽孤客心。',48,'御定全唐詩/json/749.json','["知君別家後，不免淚沾襟。芳草千里路，夕陽孤客心。", "花飛當野渡，猿叫在煙岑。霄漢知音在，何須恨陸沈。"]'),
('yuding-63','言志寄劉鈞秀才','李中','唐','御定全唐诗','yuding','','[]','童稚親儒墨，時平喜道存。酬身指書劍，賦命委乾坤。',48,'御定全唐詩/json/749.json','["童稚親儒墨，時平喜道存。酬身指書劍，賦命委乾坤。", "秋爽鼓琴興，月清搜句魂。與君同此志，終待至公論。"]'),
('yuding-64','訪澄上人','李中','唐','御定全唐诗','yuding','','[]','尋師來靜境，神骨覺清涼。一餉逢秋雨，相留坐竹堂。',48,'御定全唐詩/json/749.json','["尋師來靜境，神骨覺清涼。一餉逢秋雨，相留坐竹堂。", "石渠堆敗葉，莎砌咽寒螿。話到南能旨，怡然萬慮忘。"]'),
('yuding-65','經古寺','李中','唐','御定全唐诗','yuding','','[]','殿宇半隳摧，門臨野水開。雲凝何代樹，草蔽此時台。',48,'御定全唐詩/json/749.json','["殿宇半隳摧，門臨野水開。雲凝何代樹，草蔽此時台。", "繞塔堆黃葉，沿階積綠苔。踟躕日將暮，棲鳥入巢來。"]'),
('yuding-66','送王道士游東海','李中','唐','御定全唐诗','yuding','','[]','巨浸常牽夢，雲遊豈覺勞。遙空收晚雨，虛閣看秋濤。',48,'御定全唐詩/json/749.json','["巨浸常牽夢，雲遊豈覺勞。遙空收晚雨，虛閣看秋濤。", "必若思三島，應須釣六鼇。如通十洲去，誰信碧天高。"]'),
('yuding-67','貽青陽宰','李中','唐','御定全唐诗','yuding','','[]','征賦常登限，名山管最多。吏閑民訟少，時得訪煙蘿。',24,'御定全唐詩/json/749.json','["征賦常登限，名山管最多。吏閑民訟少，時得訪煙蘿。"]'),
('yuding-68','哭故主人陳太師','李中','唐','御定全唐诗','yuding','','[]','十年孤跡寄侯門，入室升堂忝厚恩。遊遍春郊隨茜旆，',40,'御定全唐詩/json/749.json','["十年孤跡寄侯門，入室升堂忝厚恩。遊遍春郊隨茜旆，", "長慟裴回逝川上，白楊蕭颯又黃昏。"]'),
('yuding-69','秋江夜泊寄劉鈞','李中','唐','御定全唐诗','yuding','','[]','萬里江山斂暮煙，旅情當此獨悠然。沙汀月冷帆初卸，',40,'御定全唐詩/json/749.json','["萬里江山斂暮煙，旅情當此獨悠然。沙汀月冷帆初卸，", "與君共俟酬身了，結侶波中寄釣船。"]'),
('yuding-0','和潯陽宰感舊絕句五首','李中','唐','御定全唐诗','yuding','','[]','追感古今情不已，竹軒閑取史書看。',160,'御定全唐詩/json/750.json','["追感古今情不已，竹軒閑取史書看。", "欲親往哲無因見，空樹臨風襟袖寒。", "潯陽物景真難及，練瀉澄江最好看。", "曾上虛樓吟倚檻，五峰擎雪照人寒。", "園林春媚千花發，爛熳如將畫障看。", "惟愛松筠多冷淡，青青偏稱雪霜寒。", "知君百里鳴琴處，公退千山盡日看。", "政化有同風偃草，更將餘力拯孤寒。", "昔歲尋芳忻得侶，江堤物景盡情看。", "就中吟戀垂楊下，撼起啼鶯晚吹寒。"]'),
('yuding-1','哭柴郎中','李中','唐','御定全唐诗','yuding','','[]','昔歲遭逢在海城，曾容孤跡奉雙旌。酒邊不厭笙歌盛，',40,'御定全唐詩/json/750.json','["昔歲遭逢在海城，曾容孤跡奉雙旌。酒邊不厭笙歌盛，", "音塵自此無因問，淚灑川波夕照明。"]'),
('yuding-2','訪章禪老','李中','唐','御定全唐诗','yuding','','[]','比尋禪客叩禪機，澄卻心如月在池。',32,'御定全唐詩/json/750.json','["比尋禪客叩禪機，澄卻心如月在池。", "松下偶然醒一夢，卻成無語問吾師。"]'),
('yuding-3','泊秋浦','李中','唐','御定全唐诗','yuding','','[]','葦岸風高宿雁驚，維舟特地起鄉情。',32,'御定全唐詩/json/750.json','["葦岸風高宿雁驚，維舟特地起鄉情。", "漁兒隔水吹橫笛，半夜空江月正明。"]'),
('yuding-4','閒居言懷','李中','唐','御定全唐诗','yuding','','[]','未達難隨眾，從他俗所憎。閑聽九秋雨，遠憶四明僧。',48,'御定全唐詩/json/750.json','["未達難隨眾，從他俗所憎。閑聽九秋雨，遠憶四明僧。", "病後倦吟嘯，貧來疏友朋。寂寥元合道，未必是無能。"]'),
('yuding-5','舟次彭澤','李中','唐','御定全唐诗','yuding','','[]','飄泛經彭澤，扁舟思莫窮。無人秋浪晚，一岸蓼花風。',48,'御定全唐詩/json/750.json','["飄泛經彭澤，扁舟思莫窮。無人秋浪晚，一岸蓼花風。", "鄉里夢漸遠，交親書未通。今宵見圓月，難坐冷光中。"]'),
('yuding-6','宿鐘山知覺院','李中','唐','御定全唐诗','yuding','','[]','宿投林下寺，中夜覺神清。磬罷僧初定，山空月又生。',48,'御定全唐詩/json/750.json','["宿投林下寺，中夜覺神清。磬罷僧初定，山空月又生。", "籠燈吐冷豔，岩樹起寒聲。待曉紅塵裏，依前冒遠程。"]'),
('yuding-7','游茅山二首','李中','唐','御定全唐诗','yuding','','[]','綠蘚深迎步，紅霞爛滿衣。洞天應不遠，鸞鶴向人飛。',48,'御定全唐詩/json/750.json','["綠蘚深迎步，紅霞爛滿衣。洞天應不遠，鸞鶴向人飛。", "茅許仙蹤在，煙霞一境清。夷希何許叩，松徑月空明。"]'),
('yuding-8','鶴','李中','唐','御定全唐诗','yuding','','[]','九皋羽翼下晴空，萬里心難駐玉籠。清露滴時翹蘚徑，',40,'御定全唐詩/json/750.json','["九皋羽翼下晴空，萬里心難駐玉籠。清露滴時翹蘚徑，", "好共靈龜作儔侶，十洲三島逐仙翁。"]'),
('yuding-9','暮春吟懷寄姚端先輩','李中','唐','御定全唐诗','yuding','','[]','無奈詩魔旦夕生，更堪芳草滿長汀。故人還爽花前約，',40,'御定全唐詩/json/750.json','["無奈詩魔旦夕生，更堪芳草滿長汀。故人還爽花前約，", "何時得見登龍客，隔卻千山萬仞青。"]'),
('yuding-10','送圓上人歸廬山','李中','唐','御定全唐诗','yuding','','[]','蓮宮舊隱塵埃外，策杖臨風拂袖還。踏雪獨尋青嶂下，',40,'御定全唐詩/json/750.json','["蓮宮舊隱塵埃外，策杖臨風拂袖還。踏雪獨尋青嶂下，", "預想松軒夜禪處，虎溪圓月照空山。"]'),
('yuding-11','送相裏秀才之匡山國子監','李中','唐','御定全唐诗','yuding','','[]','氣秀情閑杳莫群，廬山遊去志求文。已能探虎窮騷雅，',40,'御定全唐詩/json/750.json','["氣秀情閑杳莫群，廬山遊去志求文。已能探虎窮騷雅，", "業成早赴春闈約，要使嘉名海內聞。"]'),
('yuding-12','漁父二首','李中','唐','御定全唐诗','yuding','','[]','偶向蘆花深處行，溪光山色晚來晴。',64,'御定全唐詩/json/750.json','["偶向蘆花深處行，溪光山色晚來晴。", "漁家開戶相迎接，稚子爭窺犬吠聲。", "雪鬢衰髯白布袍，笑攜赬鯉換村醪。", "殷勤留我宿溪上，釣艇歸來明月高。"]'),
('yuding-13','旅次聞砧','李中','唐','御定全唐诗','yuding','','[]','砧杵誰家夜擣衣，金風淅淅露微微。',32,'御定全唐詩/json/750.json','["砧杵誰家夜擣衣，金風淅淅露微微。", "月中獨坐不成寐，舊業經年未得歸。"]'),
('yuding-14','寄楊先生','李中','唐','御定全唐诗','yuding','','[]','仙翁別後無信，應共煙霞卜鄰。莫把壺中秘訣，',35,'御定全唐詩/json/750.json','["仙翁別後無信，應共煙霞卜鄰。莫把壺中秘訣，", "安得一招琴酒，與君共泛天津。"]'),
('yuding-15','對酒招陳昭用','李中','唐','御定全唐诗','yuding','','[]','花開葉落堪悲，似水年光暗移。身世都如夢役，',35,'御定全唐詩/json/750.json','["花開葉落堪悲，似水年光暗移。身世都如夢役，", "幸有一壺清酒，且來閑語希夷。"]'),
('yuding-16','旅夜聞笛','李中','唐','御定全唐诗','yuding','','[]','長笛起誰家，秋涼夜漏賒。一聲來枕上，孤客在天涯。',48,'御定全唐詩/json/750.json','["長笛起誰家，秋涼夜漏賒。一聲來枕上，孤客在天涯。", "木末風微動，窗前月漸斜。暗牽詩思苦，不獨落梅花。"]'),
('yuding-17','送紹明上人之毗陵','李中','唐','御定全唐诗','yuding','','[]','忽起毗陵念，飄然不可留。聽蟬離古寺，攜錫上扁舟。',48,'御定全唐詩/json/750.json','["忽起毗陵念，飄然不可留。聽蟬離古寺，攜錫上扁舟。", "月出沙汀冷，風高葦岸秋。回期端的否，千里路悠悠。"]'),
('yuding-18','再到山陽尋故人不遇二首','李中','唐','御定全唐诗','yuding','','[]','維舟登野岸，因訪故人居。亂後知何處，荊榛匝弊廬。',48,'御定全唐詩/json/750.json','["維舟登野岸，因訪故人居。亂後知何處，荊榛匝弊廬。", "欲問當年事，耕人都不知。空餘堤上柳，依舊自垂絲。"]'),
('yuding-19','寄廬山簡寂觀重道者','李中','唐','御定全唐诗','yuding','','[]','憶昔采芝廬嶽頂，清宮常接絳霄人。玉書閑展石樓曉，',40,'御定全唐詩/json/750.json','["憶昔采芝廬嶽頂，清宮常接絳霄人。玉書閑展石樓曉，", "似醒一夢歸凡世，空向彤霞寄夢頻。"]'),
('yuding-20','思湓渚舊居','李中','唐','御定全唐诗','yuding','','[]','昔歲曾居湓水頭，草堂吟嘯興何幽。迎僧常踏竹間蘚，',40,'御定全唐詩/json/750.json','["昔歲曾居湓水頭，草堂吟嘯興何幽。迎僧常踏竹間蘚，", "從拘宦路無由到，昨夜分明夢去遊。"]'),
('yuding-21','思朐陽春遊感舊寄柴司徒五首','李中','唐','御定全唐诗','yuding','','[]','王孫昔日甚相親，共賞西園正媚春。',160,'御定全唐詩/json/750.json','["王孫昔日甚相親，共賞西園正媚春。", "醉臥如茵芳草上，覺來花月影籠身。", "煙鋪芳草正綿綿，藉草傳杯似列仙。", "暫輟笙歌且聯句，含毫花下破香箋。", "南陌風和舞蝶狂，惜春公子戀斜陽。", "高歌飲罷將回轡，衣上花兼百草香。", "春郊飲散暮煙收，卻引絲簧上翠樓。", "紅袖歌長金斝亂，銀蟾飛出海東頭。", "昔年常接五陵狂，洪飲花間數十場。", "別後或驚如夢覺，音塵難問水茫茫。"]'),
('yuding-22','泉','李中','唐','御定全唐诗','yuding','','[]','潺潺青嶂底，來處一何長。漱石苔痕滑，侵松鶴夢涼。',48,'御定全唐詩/json/750.json','["潺潺青嶂底，來處一何長。漱石苔痕滑，侵松鶴夢涼。", "泛花穿竹塢，瀉月下蓮塘。想得歸何處，天涯助渺茫。"]'),
('yuding-23','題徐五教池亭','李中','唐','御定全唐诗','yuding','','[]','多士池塘好，塵中景恐無。年來養鷗鷺，夢不去江湖。',120,'御定全唐詩/json/750.json','["多士池塘好，塵中景恐無。年來養鷗鷺，夢不去江湖。", "泉脈通深澗，風聲起短蘆。驚魚跳藻荇，戲蝶上菰蒲。", "泛泛容漁艇，閑閑載酒壺。漲痕山雨過，翠積岸苔鋪。", "花影沈波底，煙光入座隅。曉香憐杜若，夜浸愛蟾蜍。", "步逸心難厭，看吟興不辜。憑君命奇筆，為我寫成圖。"]'),
('yuding-24','遙賦義興潛泉','李中','唐','御定全唐诗','yuding','','[]','見說靈泉好，潺湲興莫窮。誰當秋霽後，獨聽月明中。',48,'御定全唐詩/json/750.json','["見說靈泉好，潺湲興莫窮。誰當秋霽後，獨聽月明中。", "濺石苔花潤，隨流木葉紅。何當化霖雨，濟物顯殊功。"]'),
('yuding-25','和毗陵尉曹昭用見寄','李中','唐','御定全唐诗','yuding','','[]','決獄多餘暇，冥搜萬象空。捲簾疏雨後，鎖印夕陽中。',48,'御定全唐詩/json/750.json','["決獄多餘暇，冥搜萬象空。捲簾疏雨後，鎖印夕陽中。", "還往多名士，編題尚古風。宦途知此味，能有幾人同。"]'),
('yuding-26','梅花','李中','唐','御定全唐诗','yuding','','[]','群木方憎雪，開花長在先。流鶯與舞蝶，不見許因緣。',24,'御定全唐詩/json/750.json','["群木方憎雪，開花長在先。流鶯與舞蝶，不見許因緣。"]'),
('yuding-27','舟次吉水逢蔡文慶秀才','李中','唐','御定全唐诗','yuding','','[]','別後音塵斷，相逢又共吟。雪霜今日鬢，煙月舊時心。',48,'御定全唐詩/json/750.json','["別後音塵斷，相逢又共吟。雪霜今日鬢，煙月舊時心。", "艤棹夕陽在，聽鴻秋色深。一尊開口笑，不必話升沈。"]'),
('yuding-28','新喻縣偶寄彭仁正字','李中','唐','御定全唐诗','yuding','','[]','經年離象魏，孤宦在南荒。酒醒公齋冷，雨多歸夢長。',48,'御定全唐詩/json/750.json','["經年離象魏，孤宦在南荒。酒醒公齋冷，雨多歸夢長。", "志難酬國澤，術欠致民康。吾子應相笑，區區道未光。"]'),
('yuding-29','和彭正字喜雪見寄','李中','唐','御定全唐诗','yuding','','[]','千門忻應瑞，偏稱上樓看。密灑虛窗曉，狂飄大野寒。',48,'御定全唐詩/json/750.json','["千門忻應瑞，偏稱上樓看。密灑虛窗曉，狂飄大野寒。", "園深宜竹樹，簾卷洽杯盤。已作豐年兆，黎民意盡安。"]'),
('yuding-30','海上和柴軍使清明書事','李中','唐','御定全唐诗','yuding','','[]','清明時節好煙光，英傑高吟興味長。捧日即應還禁衛，',40,'御定全唐詩/json/750.json','["清明時節好煙光，英傑高吟興味長。捧日即應還禁衛，", "卻是旅人淒屑甚，夜來魂夢到家鄉。"]'),
('yuding-31','壬申歲承命之任淦陽再過廬山國學感舊寄劉鈞明府','李中','唐','御定全唐诗','yuding','','[]','三十年前共苦辛，囊螢曾寄此煙岑。讀書燈暗嫌雲重，',40,'御定全唐詩/json/750.json','["三十年前共苦辛，囊螢曾寄此煙岑。讀書燈暗嫌雲重，", "再來物景還依舊，風冷松高猿狖吟。"]'),
('yuding-32','留題胡參卿秀才幽居','李中','唐','御定全唐诗','yuding','','[]','竹蔭庭除蘚色濃，道心安逸寂寥中。扣門時有棲禪客，',40,'御定全唐詩/json/750.json','["竹蔭庭除蘚色濃，道心安逸寂寥中。扣門時有棲禪客，", "我慚名宦猶拘束，脫屣心情未得同。"]'),
('yuding-33','放鷺鷥','李中','唐','御定全唐诗','yuding','','[]','池塘多謝久淹留，長得霜翎放自由。',32,'御定全唐詩/json/750.json','["池塘多謝久淹留，長得霜翎放自由。", "好去蒹葭深處宿，月明應認舊江秋。"]');
